INSERT INTO `stories` (`id`, `title`, `introduction`, `cover_image_url`, `rating`, `read_count`, `rating_count`, `total_pages`, `is_popular`, `created_at`, `updated_at`) VALUES
(1, 'Little Astronaut Leo', 'Leo was a child who loved watching the sky. To him, every star was a story waiting to be told.', 'https://lingola-stories-kids.b-cdn.net/covers/story_1.png', 4.80, 0, 0, 12, 1, '2026-03-06 12:40:00', '2026-03-06 12:53:38'),
(2, 'The Little Garden on Mars', 'Far away from Earth, there was a red planet called Mars. Ada wondered if life could bloom there.', 'https://lingola-stories-kids.b-cdn.net/covers/story_2.png', 4.70, 0, 0, 11, 0, '2026-03-06 12:40:00', '2026-03-06 12:53:38'),
(3, 'The Lost Stardust', 'The sky was paler than usual. Eren and Mira notice the stars losing their light and act to bring it back.', 'https://lingola-stories-kids.b-cdn.net/covers/story_3.png', 4.90, 0, 0, 15, 1, '2026-03-06 12:40:00', '2026-03-06 12:53:38'),
(4, 'Saturn\'s Lost Ring', 'Deep in space, a small gap appeared in Saturn\'s ring. Deniz dreams of fixing the celestial harmony.', 'https://lingola-stories-kids.b-cdn.net/covers/story_4.png', 4.60, 0, 0, 10, 0, '2026-03-06 12:40:00', '2026-03-06 12:53:38'),
(5, 'My Alien Friend Mimo', 'One summer night, a thin blue light descended into the garden. Arda meets a visitor from another world.', 'https://lingola-stories-kids.b-cdn.net/covers/story_5.png', 4.85, 0, 0, 11, 1, '2026-03-06 12:40:00', '2026-03-06 12:53:38'),
(6, 'The Silent Journey of the Starship', 'Arin wanted to see the planets. He witnesses a rare river of light flowing between the stars.', 'https://lingola-stories-kids.b-cdn.net/covers/story_6.png', 4.75, 0, 0, 10, 0, '2026-03-06 12:40:00', '2026-03-06 12:53:38'),
(7, 'The Silent Asteroid Belt', 'Deep within the Solar System, Kaan navigates through a sea of rocks to find hidden order in chaos.', 'https://lingola-stories-kids.b-cdn.net/covers/story_7.png', 4.65, 0, 0, 9, 0, '2026-03-06 12:40:00', '2026-03-06 12:53:38'),
(8, 'The Clock Tower That Held Time', 'In the middle of a quiet valley, wrapped in soft morning mist, stood an ancient clock tower. It had been there for centuries. Its stones were covered with moss, and its tall windows caught the sunlight at dawn. At the very top rested a great golden clock. This clock did more than show the time. It kept the valley in balance.', 'https://lingola-stories-kids.b-cdn.net/covers/story_8.png', 4.80, 0, 0, 27, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(9, 'The Forest That Forgot Its Colors', 'At the edge of a quiet kingdom stood a forest unlike any other. Its trees shimmered in shades of emerald and gold. The rivers reflected pink sunsets even at noon, and butterflies carried patterns like stained glass. The forest did not simply grow; it glowed.', 'https://lingola-stories-kids.b-cdn.net/covers/story_9.png', 4.70, 0, 0, 11, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(10, 'The Door Behind the Library Shelf', 'In the oldest part of town stood a library filled with towering shelves and dusty books. Most visitors came for stories, but one girl named Mira came for something else. She came for the feeling that something hidden waited between the pages.', 'https://lingola-stories-kids.b-cdn.net/covers/story_10.png', 4.90, 0, 0, 13, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(11, 'The Girl Who Could Hear the Wind', 'In a village surrounded by mountains, the wind never stopped moving. It whispered through rooftops, carried leaves across the ground, and hummed softly at night.', 'https://lingola-stories-kids.b-cdn.net/covers/story_11.png', 4.60, 0, 0, 11, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(12, 'The Crystal in the Snow', 'Far in the north, where winter ruled nearly every season, stood a quiet village wrapped in endless snow. The houses were small and wooden, their rooftops heavy with frost. Smoke curled gently from chimneys, rising into pale skies that seemed almost silver in the cold light.', 'https://lingola-stories-kids.b-cdn.net/covers/story_12.png', 4.80, 0, 0, 29, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(13, 'The Painter of Invisible Wings', 'Along the edge of a restless sea stood a small coastal town painted in shades of white and blue. Fishing boats rocked gently in the harbor, and seagulls filled the sky with wide, graceful circles.', 'https://lingola-stories-kids.b-cdn.net/covers/story_13.png', 4.70, 0, 0, 21, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(14, 'The Garden That Bloomed at Midnight', 'Behind an old stone wall at the edge of town lay a forgotten garden. During the day it looked abandoned. The soil appeared dry, the vines brittle, the paths empty and silent.', 'https://lingola-stories-kids.b-cdn.net/covers/story_14.png', 4.90, 0, 0, 16, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(15, 'The Lion Who Learned to Listen', 'The savanna stretched endlessly under a burning sun. Grass moved like golden waves, and heat shimmered above the earth. In that vast land lived a young lion named Kairo.', 'https://lingola-stories-kids.b-cdn.net/covers/story_15.png', 4.60, 0, 0, 14, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(16, 'The Sparrow Afraid of the Sky', 'High in an old oak tree lived a small sparrow named Luma. From her branch she could see the meadow stretch far into the distance. The sky above seemed endless — too wide, too open.', 'https://lingola-stories-kids.b-cdn.net/covers/story_16.png', 4.50, 0, 0, 12, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(17, 'The Elephant Who Remembered Too Much', 'Anu the elephant carried many memories. She remembered paths through the jungle long after vines had covered them. She remembered dry seasons and heavy rains, hidden streams and safe clearings.', 'https://lingola-stories-kids.b-cdn.net/covers/story_17.png', 4.80, 0, 0, 11, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(18, 'The Turtle Who Carried the Storm', 'Far beneath the surface of a vast blue ocean lived a sea turtle named Neri. Her shell was marked with pale lines like maps of journeys long past. She had swum through warm currents and cold tides, through seasons of calm and seasons of chaos.', 'https://lingola-stories-kids.b-cdn.net/covers/story_18.png', 4.90, 0, 0, 16, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(19, 'The Wolf Who Lost the Moon', 'In a forest where snow blanketed the ground for months at a time lived a gray wolf named Orion. His fur blended with winter shadows, and his eyes reflected the silver glow of the night sky.', 'https://lingola-stories-kids.b-cdn.net/covers/story_19.png', 4.70, 0, 0, 18, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(20, 'The Dolphin Who Swam Alone', 'In bright turquoise waters near a coral reef lived a dolphin named Kael. He was sleek and swift, with a silver line running along his back. While other dolphins traveled in pods, leaping and spinning together, Kael preferred solitude.', 'https://lingola-stories-kids.b-cdn.net/covers/story_20.png', 4.60, 0, 0, 14, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(21, 'The Fox Who Chased the Wind', 'Across rolling hills brushed with tall golden grass lived a fox named Sol. His fur glowed like fire under the sun, and he loved nothing more than to run.', 'https://lingola-stories-kids.b-cdn.net/covers/story_21.png', 4.80, 0, 0, 16, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(22, 'The Case of the Missing Lighthouse Light', 'By the edge of a quiet seaside town stood an old lighthouse that had guided ships safely for generations. Every night, as the sun slipped beneath the ocean, the lighthouse beam swept across the water in steady circles.', 'https://lingola-stories-kids.b-cdn.net/covers/story_22.png', 4.70, 0, 0, 16, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(23, 'The Secret of the Whispering Library', 'In the center of the town stood a library older than any building around it. Its wooden floors creaked softly, and tall shelves reached nearly to the ceiling.', 'https://lingola-stories-kids.b-cdn.net/covers/story_23.png', 4.80, 0, 0, 13, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(24, 'The Midnight Footprints', 'In a quiet neighborhood lined with maple trees, something strange began appearing each morning. Footprints.', 'https://lingola-stories-kids.b-cdn.net/covers/story_24.png', 4.50, 0, 0, 11, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(25, 'The Mystery of the Vanishing Paintings', 'In a small town known for its colorful murals, something strange began to happen. Every morning, one tiny detail from a wall painting disappeared.', 'https://lingola-stories-kids.b-cdn.net/covers/story_25.png', 4.90, 0, 0, 12, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(26, 'The Clock That Skipped Time', 'In the center of Maple Street stood an old clock mounted above a bakery. For years, it had ticked steadily, marking the rhythm of the town.', 'https://lingola-stories-kids.b-cdn.net/covers/story_26.png', 4.60, 0, 0, 12, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(27, 'The Park Bench Code', 'In Willow Park, there was an old wooden bench covered in carved initials and faded marks. One day, children noticed something unusual etched into the wood — a series of tiny symbols that looked almost like a code.', 'https://lingola-stories-kids.b-cdn.net/covers/story_27.png', 4.70, 0, 0, 13, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(28, 'The Case of the Echoing Tunnel', 'At the edge of town ran an old railway tunnel no longer used by trains. Recently, hikers passing through it reported strange echoing sounds — not ordinary echoes, but repeating rhythms that didn’t match their footsteps.', 'https://lingola-stories-kids.b-cdn.net/covers/story_28.png', 4.80, 0, 0, 16, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(29, 'The Valley of the Gentle Giant', 'Long before cities, long before roads, when the earth was warm and wild, there was a vast green valley surrounded by towering cliffs. Ferns stretched taller than trees, and mist floated above winding rivers. In this valley lived a young Brachiosaurus named Aro.', 'https://lingola-stories-kids.b-cdn.net/covers/story_29.png', 4.80, 0, 0, 8, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(30, 'The Raptor Who Couldn’t Hunt', 'In a dense jungle filled with towering cycads and tangled vines lived a young Velociraptor named Kira. She was quick, clever, and observant. Her kind was known for speed and sharp instincts.', 'https://lingola-stories-kids.b-cdn.net/covers/story_30.png', 4.70, 0, 0, 11, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(31, 'The T-Rex Who Feared the Thunder', 'Across an open plain where ancient trees dotted the horizon lived a young Tyrannosaurus named Rexar. His footsteps shook the ground. His teeth were sharp and powerful.', 'https://lingola-stories-kids.b-cdn.net/covers/story_31.png', 4.90, 0, 0, 10, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(32, 'The Triceratops and the Moving Mountain', 'In a wide valley surrounded by jagged cliffs lived a young Triceratops named Tor. His three horns were still growing, but he already carried himself with quiet determination.', 'https://lingola-stories-kids.b-cdn.net/covers/story_32.png', 4.60, 0, 0, 11, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(33, 'The Stegosaurus Who Saw the Future', 'In a lush forest filled with giant cycads and thick tree trunks lived a Stegosaurus named Luma. The plates along her back glowed faintly in the early morning light, shifting color with the warmth of the sun.', 'https://lingola-stories-kids.b-cdn.net/covers/story_33.png', 4.80, 0, 0, 10, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(34, 'The Pterosaur Who Feared the Wind', 'High above the ancient cliffs soared a young Pterosaur named Arin. His wings were long and powerful, built for gliding across enormous distances.', 'https://lingola-stories-kids.b-cdn.net/covers/story_34.png', 4.70, 0, 0, 11, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(35, 'The Ankylosaurus Who Stood Like Stone', 'In a land of wide plains and scattered forests lived a young Ankylosaurus named Brak. His body was covered in thick armor plates, and his heavy tail ended in a powerful club of bone. From the outside, he looked unbreakable.', 'https://lingola-stories-kids.b-cdn.net/covers/story_35.png', 4.90, 0, 0, 11, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(36, 'The Boy Who Could Pause Time', 'In a quiet city filled with tall buildings and crowded streets lived a boy named Elias. To everyone else, he seemed ordinary. He went to school, carried a backpack too heavy for his shoulders, and walked past the same bakery every morning.', 'https://lingola-stories-kids.b-cdn.net/covers/story_36.png', 4.80, 0, 0, 13, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(37, 'The Girl with the Gravity Hands', 'Mira always felt different. When she focused hard enough, objects around her felt lighter. Not floating wildly — just slightly lifted, as if the world had grown less heavy.', 'https://lingola-stories-kids.b-cdn.net/covers/story_37.png', 4.70, 0, 0, 8, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(38, 'The Shadow Runner', 'In a city where lights never fully dimmed, there lived a boy named Theo who could move through shadows.', 'https://lingola-stories-kids.b-cdn.net/covers/story_38.png', 4.90, 0, 0, 10, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(39, 'The Girl Who Could Hear Broken Things', 'In a city filled with noise, traffic, and endless motion lived a quiet girl named Lina. She had an unusual ability — she could hear when things were about to break.', 'https://lingola-stories-kids.b-cdn.net/covers/story_39.png', 4.80, 0, 0, 10, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(40, 'The Invisible Thread', 'Mateo always felt connected to people in a strange way. When someone nearby felt strong emotion — fear, sadness, joy — he sensed a thin, glowing thread linking them.', 'https://lingola-stories-kids.b-cdn.net/covers/story_40.png', 4.90, 0, 0, 8, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(41, 'The Stormlight Runner', 'Ava loved storms. While others hid indoors, she stood at windows watching lightning split the sky. She felt energized when thunder rolled across rooftops.', 'https://lingola-stories-kids.b-cdn.net/covers/story_41.png', 4.70, 0, 0, 8, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(42, 'The Keeper of Small Miracles', 'In a neighborhood filled with tall buildings lived a boy named Omar who had a subtle power — he could improve tiny probabilities.', 'https://lingola-stories-kids.b-cdn.net/covers/story_42.png', 4.60, 0, 0, 9, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(43, 'The City Beneath the Coral Crown', 'Far below the surface of the ocean, where sunlight softened into turquoise beams, there stood a hidden underwater city built among towering coral reefs.', 'https://lingola-stories-kids.b-cdn.net/covers/story_43.png', 4.80, 0, 0, 6, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(44, 'The Whale Who Lost the Song', 'In the deepest parts of the ocean, where darkness hummed like a quiet echo, lived a young humpback whale named Nakoa. Every year, whales crossed vast oceans guided by ancient songs passed from generation to generation.', 'https://lingola-stories-kids.b-cdn.net/covers/story_44.png', 4.90, 0, 0, 6, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(45, 'The Octopus and the Shifting Sand', 'Near a wide stretch of sandy seabed lived an octopus named Arin. Unlike reef creatures surrounded by color and structure, Arin’s world was open and exposed.', 'https://lingola-stories-kids.b-cdn.net/covers/story_45.png', 4.60, 0, 0, 6, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(46, 'The Reef That Went Silent', 'In a warm, shallow sea filled with dancing light lived a coral reef that never slept. Parrotfish scraped gently at coral walls, tiny shrimp snapped in hidden crevices, and bright angelfish darted through tunnels of color.', 'https://lingola-stories-kids.b-cdn.net/covers/story_46.png', 4.80, 0, 0, 8, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(47, 'The Submarine That Found the Deep', 'Far below where sunlight could reach, where the ocean turned dark blue and nearly black, a small exploration submarine named Aurora descended carefully into the abyss.', 'https://lingola-stories-kids.b-cdn.net/covers/story_47.png', 4.70, 0, 0, 7, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(48, 'The Seahorse Who Couldn’t Hold On', 'In a gentle kelp forest near the coast lived a young seahorse named Mira. Seahorses survived by wrapping their tails tightly around swaying plants to anchor themselves against currents.', 'https://lingola-stories-kids.b-cdn.net/covers/story_48.png', 4.60, 0, 0, 6, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(49, 'The Hidden River Beneath the Ice', 'In the coldest part of the ocean, where floating icebergs cast long blue shadows, a young seal named Iko loved exploring beneath the ice sheets.', 'https://lingola-stories-kids.b-cdn.net/covers/story_49.png', 4.80, 0, 0, 10, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(50, 'The Princess Who Refused the Crown', 'In a kingdom surrounded by silver mountains lived a princess named Elowen. The palace she grew up in was carved from pale stone that shimmered in the morning sun. From her balcony, she could see rivers winding like ribbons through the valleys below.', 'https://lingola-stories-kids.b-cdn.net/covers/story_50.png', 4.80, 0, 0, 10, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(51, 'The Prince and the Glass Forest', 'Long ago, in a land where winter lasted half the year, there stood a forest unlike any other. Its trees were made entirely of glass.', 'https://lingola-stories-kids.b-cdn.net/covers/story_51.png', 4.90, 0, 0, 9, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(52, 'The Girl Who Spoke to Dragons', 'In a kingdom where dragons were feared more than storms lived a girl named Mira. For generations, dragons had nested in the mountains beyond the castle walls. Their silhouettes against the sky terrified villagers.', 'https://lingola-stories-kids.b-cdn.net/covers/story_52.png', 4.70, 0, 0, 8, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(53, 'The Queen of the Hidden Garden', 'In a kingdom surrounded by high stone walls lived a young queen named Seraphine. She had inherited the throne unexpectedly after her father’s sudden passing. Though wise beyond her years, she felt unprepared for the quiet loneliness that came with ruling.', 'https://lingola-stories-kids.b-cdn.net/covers/story_53.png', 3.00, 0, 1, 8, 1, '2026-02-26 12:17:30', '2026-03-06 12:26:24'),
(54, 'The Clockmaker’s Daughter', 'In a small town famous for its towering clock tower lived a master clockmaker named Aldric. His workshop was filled with gears, springs, and delicate hands that ticked in perfect rhythm.', 'https://lingola-stories-kids.b-cdn.net/covers/story_54.png', 4.60, 0, 0, 10, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(55, 'The Boy Who Planted Stars', 'In a village surrounded by dark forests lived a boy named Theo who feared the night. The forest seemed endless after sunset, and the sky above felt too vast.', 'https://lingola-stories-kids.b-cdn.net/covers/story_55.png', 4.70, 0, 0, 9, 0, '2026-02-26 12:17:30', '2026-03-06 09:07:15'),
(56, 'The Mirror of True Names', 'In a kingdom of grand halls and golden tapestries stood a mirror unlike any other. It was tall as a door and framed in silver vines. Legend said it revealed a person’s true name — not the name given at birth, but the name that described who they truly were.', 'https://lingola-stories-kids.b-cdn.net/covers/story_56.png', 4.90, 0, 0, 11, 1, '2026-02-26 12:17:30', '2026-03-06 09:07:15');
