INSERT INTO `story_sections` (`id`, `story_id`, `title`, `content`, `page_number`, `elevenlabs_audio_url`, `elevenlabs_voice_id`, `audio_duration`, `word_timestamps`, `created_at`, `updated_at`) VALUES
(1, 15, 'Page 1', 'The savanna stretched endlessly under a burning sun. Grass moved like golden waves, and heat shimmered above the earth. In that vast land lived a young lion named Kairo.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_1.mp3', NULL, NULL, '{\"words\": [\"The\", \"savanna\", \"stretched\", \"endlessly\", \"under\", \"a\", \"burning\", \"sun.\", \"Grass\", \"moved\", \"like\", \"golden\", \"waves,\", \"and\", \"heat\", \"shimmered\", \"above\", \"the\", \"earth.\", \"In\", \"that\", \"vast\", \"land\", \"lived\", \"a\", \"young\", \"lion\", \"named\", \"Kairo.\"], \"start_times\": [0, 0.267, 0.673, 1.103, 1.683, 1.939, 2.009, 2.392, 3.332, 3.808, 4.168, 4.377, 4.772, 5.457, 5.689, 6.014, 6.409, 6.664, 6.792, 8.359, 8.51, 8.684, 9.033, 9.578, 9.822, 9.915, 10.182, 10.553, 10.832], \"end_times\": [0.221, 0.615, 1.033, 1.602, 1.881, 1.962, 2.31, 2.821, 3.738, 4.122, 4.331, 4.702, 5.341, 5.608, 5.933, 6.374, 6.629, 6.734, 7.245, 8.475, 8.626, 8.963, 9.404, 9.799, 9.845, 10.112, 10.495, 10.774, 11.517]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(2, 15, 'Page 2', 'Kairo was proud of his strength. His paws left deep prints in the dust, and his roar could scatter birds from treetops. Every morning he climbed the highest rock near the watering hole and roared across the plains, believing the land belonged to him.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_2.mp3', NULL, NULL, '{\"words\": [\"Kairo\", \"was\", \"proud\", \"of\", \"his\", \"strength.\", \"His\", \"paws\", \"left\", \"deep\", \"prints\", \"in\", \"the\", \"dust,\", \"and\", \"his\", \"roar\", \"could\", \"scatter\", \"birds\", \"from\", \"treetops.\", \"Every\", \"morning\", \"he\", \"climbed\", \"the\", \"highest\", \"rock\", \"near\", \"the\", \"watering\", \"hole\", \"and\", \"roared\", \"across\", \"the\", \"plains,\", \"believing\", \"the\", \"land\", \"belonged\", \"to\", \"him.\"], \"start_times\": [0, 0.569, 0.743, 1.045, 1.149, 1.277, 1.997, 2.229, 2.601, 2.856, 3.088, 3.379, 3.471, 3.576, 4.029, 4.203, 4.365, 4.69, 4.899, 5.341, 5.654, 5.851, 7.129, 7.442, 7.79, 7.906, 8.255, 8.382, 8.766, 9.067, 9.253, 9.358, 9.752, 9.996, 10.159, 10.472, 10.844, 10.96, 11.656, 12.144, 12.272, 12.585, 12.945, 13.05], \"end_times\": [0.511, 0.673, 0.998, 1.091, 1.242, 1.823, 2.159, 2.531, 2.798, 3.03, 3.344, 3.437, 3.541, 4.005, 4.156, 4.296, 4.621, 4.841, 5.271, 5.619, 5.793, 6.618, 7.384, 7.732, 7.848, 8.231, 8.324, 8.696, 8.998, 9.207, 9.323, 9.706, 9.961, 10.089, 10.449, 10.797, 10.913, 11.529, 12.086, 12.214, 12.516, 12.922, 12.992, 13.514]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(3, 15, 'Page 3', 'But Kairo never paid attention to the quieter sounds — the soft shift of wind before a storm, the nervous stomp of zebras, the way the air sometimes grew heavy before change.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_3.mp3', NULL, NULL, '{\"words\": [\"But\", \"Kairo\", \"never\", \"paid\", \"attention\", \"to\", \"the\", \"quieter\", \"sounds\", \"u2014\", \"the\", \"soft\", \"shift\", \"of\", \"wind\", \"before\", \"a\", \"storm,\", \"the\", \"nervous\", \"stomp\", \"of\", \"zebras,\", \"the\", \"way\", \"the\", \"air\", \"sometimes\", \"grew\", \"heavy\", \"before\", \"change.\"], \"start_times\": [0, 0.313, 0.65, 0.894, 1.115, 1.591, 1.718, 1.834, 2.334, 2.972, 3.309, 3.483, 3.855, 4.191, 4.331, 4.656, 5.004, 5.097, 5.933, 6.095, 6.455, 6.885, 7.036, 8.092, 8.243, 8.406, 8.557, 8.8, 9.253, 9.497, 9.81, 10.147], \"end_times\": [0.267, 0.592, 0.836, 1.08, 1.533, 1.66, 1.788, 2.276, 2.763, 3.03, 3.425, 3.796, 4.145, 4.249, 4.586, 4.969, 5.027, 5.724, 6.037, 6.42, 6.815, 6.954, 7.814, 8.197, 8.359, 8.487, 8.742, 9.207, 9.427, 9.741, 10.101, 11.192]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(4, 15, 'Page 4', 'One afternoon, the sky darkened in a strange way. It was not evening. The light simply faded. A hot wind began to sweep across the grasslands. In the distance, a wall of dust rose like a moving mountain.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_4.mp3', NULL, NULL, '{\"words\": [\"One\", \"afternoon,\", \"the\", \"sky\", \"darkened\", \"in\", \"a\", \"strange\", \"way.\", \"It\", \"was\", \"not\", \"evening.\", \"The\", \"light\", \"simply\", \"faded.\", \"A\", \"hot\", \"wind\", \"began\", \"to\", \"sweep\", \"across\", \"the\", \"grasslands.\", \"In\", \"the\", \"distance,\", \"a\", \"wall\", \"of\", \"dust\", \"rose\", \"like\", \"a\", \"moving\", \"mountain.\"], \"start_times\": [0, 0.36, 0.848, 0.952, 1.254, 1.73, 1.846, 1.939, 2.368, 3.216, 3.367, 3.518, 3.727, 4.76, 4.934, 5.19, 5.526, 6.699, 6.861, 7.105, 7.372, 7.651, 7.744, 8.046, 8.406, 8.51, 10.066, 10.217, 10.333, 10.902, 11.041, 11.297, 11.401, 11.796, 12.144, 12.33, 12.411, 12.748], \"end_times\": [0.325, 0.824, 0.917, 1.184, 1.683, 1.8, 1.869, 2.322, 2.833, 3.332, 3.46, 3.669, 4.249, 4.876, 5.132, 5.468, 6.095, 6.78, 7.047, 7.314, 7.605, 7.697, 7.999, 8.371, 8.475, 9.369, 10.182, 10.286, 10.855, 10.971, 11.25, 11.343, 11.703, 12.109, 12.295, 12.353, 12.69, 13.468]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(5, 15, 'Page 5', 'Kairo roared into the wind, trying to show no fear. But the storm did not answer him.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_5.mp3', NULL, NULL, '{\"words\": [\"Kairo\", \"roared\", \"into\", \"the\", \"wind,\", \"trying\", \"to\", \"show\", \"no\", \"fear.\", \"But\", \"the\", \"storm\", \"did\", \"not\", \"answer\", \"him.\"], \"start_times\": [0, 0.511, 0.801, 1.01, 1.115, 1.416, 1.695, 1.776, 1.997, 2.183, 2.775, 2.949, 3.053, 3.344, 3.483, 3.657, 4.017], \"end_times\": [0.441, 0.766, 0.952, 1.08, 1.393, 1.66, 1.741, 1.927, 2.101, 2.566, 2.926, 3.019, 3.297, 3.448, 3.611, 3.959, 4.412]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(6, 15, 'Page 6', 'The air grew thick with sand. Smaller animals began to run. Through the chaos, Kairo noticed the older elephant, Manda, moving steadily toward a rocky ridge. She did not shout. She did not panic. She simply walked with calm purpose, and the herd followed her.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_6.mp3', NULL, NULL, '{\"words\": [\"The\", \"air\", \"grew\", \"thick\", \"with\", \"sand.\", \"Smaller\", \"animals\", \"began\", \"to\", \"run.\", \"Through\", \"the\", \"chaos,\", \"Kairo\", \"noticed\", \"the\", \"older\", \"elephant,\", \"Manda,\", \"moving\", \"steadily\", \"toward\", \"a\", \"rocky\", \"ridge.\", \"She\", \"did\", \"not\", \"shout.\", \"She\", \"did\", \"not\", \"panic.\", \"She\", \"simply\", \"walked\", \"with\", \"calm\", \"purpose,\", \"and\", \"the\", \"herd\", \"followed\", \"her.\"], \"start_times\": [0, 0.313, 0.604, 0.894, 1.196, 1.393, 2.508, 3.019, 3.437, 3.808, 3.971, 5.108, 5.41, 5.515, 6.397, 6.838, 7.221, 7.361, 7.697, 8.464, 9.404, 9.834, 10.426, 10.681, 10.762, 11.146, 12.295, 12.481, 12.643, 12.852, 13.746, 13.92, 14.083, 14.269, 15.244, 15.441, 15.836, 16.242, 16.428, 16.858, 17.868, 18.065, 18.193, 18.564, 18.982], \"end_times\": [0.232, 0.546, 0.813, 1.138, 1.347, 2.067, 2.949, 3.367, 3.75, 3.878, 4.505, 5.387, 5.48, 6.246, 6.769, 7.187, 7.291, 7.628, 8.29, 9.16, 9.741, 10.344, 10.646, 10.704, 11.064, 11.691, 12.423, 12.597, 12.794, 13.421, 13.874, 14.036, 14.211, 14.919, 15.372, 15.766, 16.208, 16.37, 16.776, 17.543, 18.019, 18.135, 18.483, 18.936, 19.412]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(7, 15, 'Page 7', 'For a moment, Kairo stood alone in the swirling dust.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_7.mp3', NULL, NULL, '{\"words\": [\"For\", \"a\", \"moment,\", \"Kairo\", \"stood\", \"alone\", \"in\", \"the\", \"swirling\", \"dust.\"], \"start_times\": [0, 0.302, 0.383, 0.755, 1.161, 1.405, 1.718, 1.811, 1.916, 2.368], \"end_times\": [0.255, 0.337, 0.708, 1.103, 1.37, 1.683, 1.776, 1.881, 2.31, 3.019]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(8, 15, 'Page 8', 'The storm pushed against him harder than any rival ever had. His roar meant nothing against the wind. Finally, he lowered his head and listened.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_8.mp3', NULL, NULL, '{\"words\": [\"The\", \"storm\", \"pushed\", \"against\", \"him\", \"harder\", \"than\", \"any\", \"rival\", \"ever\", \"had.\", \"His\", \"roar\", \"meant\", \"nothing\", \"against\", \"the\", \"wind.\", \"Finally,\", \"he\", \"lowered\", \"his\", \"head\", \"and\", \"listened.\"], \"start_times\": [0, 0.29, 0.592, 0.882, 1.254, 1.474, 1.834, 2.02, 2.252, 2.624, 2.891, 3.68, 3.901, 4.191, 4.435, 4.888, 5.259, 5.375, 6.269, 7.059, 7.221, 7.57, 7.744, 8.104, 8.348], \"end_times\": [0.244, 0.546, 0.848, 1.196, 1.393, 1.788, 1.962, 2.183, 2.554, 2.821, 3.355, 3.831, 4.133, 4.354, 4.807, 5.213, 5.329, 5.828, 6.931, 7.14, 7.523, 7.686, 8.011, 8.278, 9.056]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(9, 15, 'Page 9', 'He felt the vibration of hooves moving toward shelter. He noticed the direction the birds had taken. He sensed the safer ground beneath his paws.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_9.mp3', NULL, NULL, '{\"words\": [\"He\", \"felt\", \"the\", \"vibration\", \"of\", \"hooves\", \"moving\", \"toward\", \"shelter.\", \"He\", \"noticed\", \"the\", \"direction\", \"the\", \"birds\", \"had\", \"taken.\", \"He\", \"sensed\", \"the\", \"safer\", \"ground\", \"beneath\", \"his\", \"paws.\"], \"start_times\": [0, 0.337, 0.604, 0.72, 1.3, 1.44, 1.858, 2.218, 2.519, 3.541, 3.738, 4.11, 4.226, 4.737, 4.853, 5.155, 5.294, 6.432, 6.629, 7.094, 7.245, 7.651, 8.127, 8.464, 8.626], \"end_times\": [0.255, 0.557, 0.673, 1.254, 1.358, 1.788, 2.148, 2.473, 3.1, 3.657, 4.075, 4.18, 4.69, 4.807, 5.108, 5.259, 5.828, 6.56, 7.012, 7.187, 7.581, 8.046, 8.417, 8.568, 9.381]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(10, 15, 'Page 10', 'Quietly, he followed.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_10.mp3', NULL, NULL, '{\"words\": [\"Quietly,\", \"he\", \"followed.\"], \"start_times\": [0, 0.58, 0.72], \"end_times\": [0.557, 0.662, 1.347]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(11, 15, 'Page 11', 'When the storm passed, the savanna looked changed but alive. The herd had survived because they had listened to the land.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_11.mp3', NULL, NULL, '{\"words\": [\"When\", \"the\", \"storm\", \"passed,\", \"the\", \"savanna\", \"looked\", \"changed\", \"but\", \"alive.\", \"The\", \"herd\", \"had\", \"survived\", \"because\", \"they\", \"had\", \"listened\", \"to\", \"the\", \"land.\"], \"start_times\": [0, 0.313, 0.418, 0.743, 1.196, 1.335, 1.8, 2.101, 2.926, 3.146, 4.423, 4.609, 4.876, 5.027, 5.654, 5.956, 6.095, 6.235, 6.641, 6.792, 6.92], \"end_times\": [0.279, 0.383, 0.685, 1.161, 1.289, 1.741, 2.02, 2.647, 3.1, 3.727, 4.54, 4.841, 4.981, 5.584, 5.933, 6.06, 6.177, 6.571, 6.734, 6.861, 7.523]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(12, 15, 'Page 12', 'That evening, Kairo climbed the rock again. But this time, instead of roaring, he sat still. He listened to the wind moving gently through the grass.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_12.mp3', NULL, NULL, '{\"words\": [\"That\", \"evening,\", \"Kairo\", \"climbed\", \"the\", \"rock\", \"again.\", \"But\", \"this\", \"time,\", \"instead\", \"of\", \"roaring,\", \"he\", \"sat\", \"still.\", \"He\", \"listened\", \"to\", \"the\", \"wind\", \"moving\", \"gently\", \"through\", \"the\", \"grass.\"], \"start_times\": [0, 0.372, 0.743, 1.115, 1.405, 1.521, 1.776, 2.334, 2.531, 2.74, 3.1, 3.46, 3.576, 4.191, 4.342, 4.644, 5.84, 6.026, 6.362, 6.478, 6.594, 6.943, 7.256, 7.593, 7.825, 7.918], \"end_times\": [0.313, 0.697, 1.045, 1.382, 1.474, 1.718, 2.159, 2.496, 2.682, 3.077, 3.425, 3.506, 4.11, 4.284, 4.563, 5.143, 5.956, 6.339, 6.42, 6.548, 6.861, 7.198, 7.546, 7.802, 7.895, 8.638]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(13, 15, 'Page 13', 'He realized strength was not only in sound.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_13.mp3', NULL, NULL, '{\"words\": [\"He\", \"realized\", \"strength\", \"was\", \"not\", \"only\", \"in\", \"sound.\"], \"start_times\": [0, 0.29, 0.673, 1.033, 1.196, 1.393, 1.649, 1.788], \"end_times\": [0.232, 0.639, 0.998, 1.138, 1.347, 1.591, 1.718, 2.461]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(14, 15, 'Page 14', 'It was in awareness.', 14, 'https://lingola-stories-kids.b-cdn.net/audio/story_15_page_14.mp3', NULL, NULL, '{\"words\": [\"It\", \"was\", \"in\", \"awareness.\"], \"start_times\": [0, 0.267, 0.406, 0.499], \"end_times\": [0.232, 0.36, 0.464, 1.347]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(15, 16, 'Page 1', 'High in an old oak tree lived a small sparrow named Luma. From her branch she could see the meadow stretch far into the distance. The sky above seemed endless — too wide, too open.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_1.mp3', NULL, NULL, '{\"words\": [\"High\", \"in\", \"an\", \"old\", \"oak\", \"tree\", \"lived\", \"a\", \"small\", \"sparrow\", \"named\", \"Luma.\", \"From\", \"her\", \"branch\", \"she\", \"could\", \"see\", \"the\", \"meadow\", \"stretch\", \"far\", \"into\", \"the\", \"distance.\", \"The\", \"sky\", \"above\", \"seemed\", \"endless\", \"u2014\", \"too\", \"wide,\", \"too\", \"open.\"], \"start_times\": [0, 0.418, 0.522, 0.627, 0.836, 1.068, 1.312, 1.533, 1.602, 1.916, 2.334, 2.624, 3.529, 3.762, 3.878, 4.238, 4.377, 4.551, 4.725, 4.841, 5.155, 5.573, 5.851, 6.06, 6.165, 7.326, 7.488, 7.779, 8.115, 8.452, 9.102, 9.265, 9.52, 10.147, 10.437], \"end_times\": [0.383, 0.476, 0.58, 0.778, 1.01, 1.265, 1.509, 1.556, 1.858, 2.276, 2.554, 3.146, 3.704, 3.831, 4.191, 4.331, 4.516, 4.69, 4.795, 5.074, 5.503, 5.805, 6.002, 6.13, 6.815, 7.442, 7.721, 8.081, 8.382, 8.928, 9.149, 9.462, 9.996, 10.368, 11.099]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(16, 16, 'Page 2', 'Other sparrows darted through the air effortlessly. They skimmed over flowers, soared between clouds, and disappeared into the horizon. Luma watched them, her claws gripping the bark tightly.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_2.mp3', NULL, NULL, '{\"words\": [\"Other\", \"sparrows\", \"darted\", \"through\", \"the\", \"air\", \"effortlessly.\", \"They\", \"skimmed\", \"over\", \"flowers,\", \"soared\", \"between\", \"clouds,\", \"and\", \"disappeared\", \"into\", \"the\", \"horizon.\", \"Luma\", \"watched\", \"them,\", \"her\", \"claws\", \"gripping\", \"the\", \"bark\", \"tightly.\"], \"start_times\": [0, 0.418, 0.882, 1.207, 1.451, 1.591, 1.904, 3.065, 3.286, 3.68, 3.924, 4.737, 5.155, 5.538, 6.281, 6.502, 7.163, 7.396, 7.523, 8.777, 9.172, 9.543, 9.973, 10.147, 10.53, 10.89, 10.995, 11.285], \"end_times\": [0.36, 0.824, 1.173, 1.416, 1.521, 1.823, 2.856, 3.228, 3.634, 3.866, 4.563, 5.097, 5.468, 6.165, 6.444, 7.094, 7.338, 7.465, 8.266, 9.114, 9.509, 9.892, 10.089, 10.472, 10.844, 10.96, 11.227, 11.981]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(17, 16, 'Page 3', 'She did not trust the sky.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_3.mp3', NULL, NULL, '{\"words\": [\"She\", \"did\", \"not\", \"trust\", \"the\", \"sky.\"], \"start_times\": [0, 0.313, 0.476, 0.639, 0.894, 0.998], \"end_times\": [0.255, 0.43, 0.604, 0.859, 0.964, 1.625]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(18, 16, 'Page 4', 'It felt too big.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_4.mp3', NULL, NULL, '{\"words\": [\"It\", \"felt\", \"too\", \"big.\"], \"start_times\": [0, 0.29, 0.511, 0.72], \"end_times\": [0.244, 0.476, 0.65, 1.254]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(19, 16, 'Page 5', 'One morning, a strong wind swept across the meadow. Leaves shook violently. Branches bent. Luma held on as tightly as she could, but a sudden snap beneath her feet sent her into open air.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_5.mp3', NULL, NULL, '{\"words\": [\"One\", \"morning,\", \"a\", \"strong\", \"wind\", \"swept\", \"across\", \"the\", \"meadow.\", \"Leaves\", \"shook\", \"violently.\", \"Branches\", \"bent.\", \"Luma\", \"held\", \"on\", \"as\", \"tightly\", \"as\", \"she\", \"could,\", \"but\", \"a\", \"sudden\", \"snap\", \"beneath\", \"her\", \"feet\", \"sent\", \"her\", \"into\", \"open\", \"air.\"], \"start_times\": [0, 0.441, 0.789, 0.894, 1.312, 1.637, 1.95, 2.299, 2.415, 3.402, 3.82, 4.133, 5.062, 5.631, 6.478, 6.873, 7.163, 7.361, 7.523, 7.988, 8.104, 8.266, 8.916, 9.114, 9.183, 9.532, 9.927, 10.228, 10.368, 10.635, 10.879, 11.006, 11.262, 11.587], \"end_times\": [0.406, 0.766, 0.813, 1.254, 1.567, 1.916, 2.252, 2.368, 2.891, 3.773, 4.075, 4.888, 5.561, 6.095, 6.803, 7.094, 7.303, 7.454, 7.918, 8.057, 8.208, 8.707, 9.079, 9.137, 9.462, 9.868, 10.182, 10.31, 10.577, 10.832, 10.96, 11.169, 11.517, 12.074]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(20, 16, 'Page 6', 'For a heartbeat, she felt only fear.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_6.mp3', NULL, NULL, '{\"words\": [\"For\", \"a\", \"heartbeat,\", \"she\", \"felt\", \"only\", \"fear.\"], \"start_times\": [0, 0.29, 0.36, 0.743, 0.894, 1.138, 1.37], \"end_times\": [0.255, 0.313, 0.72, 0.836, 1.091, 1.312, 1.904]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(21, 16, 'Page 7', 'The ground seemed far away. The sky swallowed her whole. But then something changed. The wind did not push her down. It held her up.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_7.mp3', NULL, NULL, '{\"words\": [\"The\", \"ground\", \"seemed\", \"far\", \"away.\", \"The\", \"sky\", \"swallowed\", \"her\", \"whole.\", \"But\", \"then\", \"something\", \"changed.\", \"The\", \"wind\", \"did\", \"not\", \"push\", \"her\", \"down.\", \"It\", \"held\", \"her\", \"up.\"], \"start_times\": [0, 0.279, 0.615, 0.952, 1.207, 2.101, 2.276, 2.67, 3.111, 3.251, 4.18, 4.354, 4.551, 4.911, 5.968, 6.153, 6.397, 6.548, 6.722, 6.931, 7.059, 7.581, 7.767, 7.988, 8.139], \"end_times\": [0.232, 0.557, 0.894, 1.149, 1.718, 2.229, 2.554, 3.077, 3.204, 3.738, 4.331, 4.481, 4.853, 5.584, 6.107, 6.351, 6.502, 6.676, 6.896, 7.001, 7.5, 7.721, 7.941, 8.069, 8.591]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(22, 16, 'Page 8', 'Her wings spread without thinking. Air flowed beneath her feathers. Instead of falling, she glided.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_8.mp3', NULL, NULL, '{\"words\": [\"Her\", \"wings\", \"spread\", \"without\", \"thinking.\", \"Air\", \"flowed\", \"beneath\", \"her\", \"feathers.\", \"Instead\", \"of\", \"falling,\", \"she\", \"glided.\"], \"start_times\": [0, 0.302, 0.557, 0.848, 1.149, 1.881, 2.194, 2.496, 2.798, 2.949, 3.471, 3.831, 3.924, 4.365, 4.528], \"end_times\": [0.255, 0.522, 0.813, 1.103, 1.707, 2.136, 2.461, 2.752, 2.891, 3.448, 3.796, 3.878, 4.342, 4.47, 5.248]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(23, 16, 'Page 9', 'The meadow below looked peaceful from above. The world was not terrifying. It was beautiful.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_9.mp3', NULL, NULL, '{\"words\": [\"The\", \"meadow\", \"below\", \"looked\", \"peaceful\", \"from\", \"above.\", \"The\", \"world\", \"was\", \"not\", \"terrifying.\", \"It\", \"was\", \"beautiful.\"], \"start_times\": [0, 0.29, 0.569, 0.871, 1.103, 1.544, 1.741, 2.612, 2.798, 3.077, 3.239, 3.425, 4.296, 4.481, 4.656], \"end_times\": [0.232, 0.511, 0.813, 1.068, 1.486, 1.683, 2.287, 2.752, 3.03, 3.181, 3.39, 4.18, 4.435, 4.586, 5.433]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(24, 16, 'Page 10', 'When she landed again, she no longer saw the sky as something to fear.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_10.mp3', NULL, NULL, '{\"words\": [\"When\", \"she\", \"landed\", \"again,\", \"she\", \"no\", \"longer\", \"saw\", \"the\", \"sky\", \"as\", \"something\", \"to\", \"fear.\"], \"start_times\": [0, 0.325, 0.499, 0.813, 1.173, 1.347, 1.498, 1.8, 2.043, 2.148, 2.519, 2.647, 2.995, 3.123], \"end_times\": [0.279, 0.418, 0.778, 1.138, 1.277, 1.44, 1.753, 1.985, 2.113, 2.438, 2.601, 2.949, 3.053, 3.715]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(25, 16, 'Page 11', 'It was something to enter.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_11.mp3', NULL, NULL, '{\"words\": [\"It\", \"was\", \"something\", \"to\", \"enter.\"], \"start_times\": [0, 0.279, 0.418, 0.778, 0.917], \"end_times\": [0.244, 0.383, 0.731, 0.836, 1.486]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(26, 16, 'Page 12', 'And the next time she flew, it was not by accident.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_16_page_12.mp3', NULL, NULL, '{\"words\": [\"And\", \"the\", \"next\", \"time\", \"she\", \"flew,\", \"it\", \"was\", \"not\", \"by\", \"accident.\"], \"start_times\": [0, 0.29, 0.395, 0.639, 0.871, 1.045, 1.382, 1.498, 1.637, 1.823, 1.997], \"end_times\": [0.244, 0.36, 0.604, 0.836, 0.975, 1.347, 1.463, 1.579, 1.788, 1.927, 2.786]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(27, 17, 'Page 1', 'Anu the elephant carried many memories. She remembered paths through the jungle long after vines had covered them. She remembered dry seasons and heavy rains, hidden streams and safe clearings.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_1.mp3', NULL, NULL, '{\"words\": [\"Anu\", \"the\", \"elephant\", \"carried\", \"many\", \"memories.\", \"She\", \"remembered\", \"paths\", \"through\", \"the\", \"jungle\", \"long\", \"after\", \"vines\", \"had\", \"covered\", \"them.\", \"She\", \"remembered\", \"dry\", \"seasons\", \"and\", \"heavy\", \"rains,\", \"hidden\", \"streams\", \"and\", \"safe\", \"clearings.\"], \"start_times\": [0, 0.557, 0.708, 1.161, 1.567, 1.811, 2.902, 3.123, 3.599, 4.017, 4.272, 4.389, 4.772, 5.062, 5.341, 5.759, 5.909, 6.246, 6.966, 7.163, 7.605, 7.953, 8.499, 8.719, 9.067, 9.857, 10.205, 10.739, 10.925, 11.273], \"end_times\": [0.499, 0.639, 1.103, 1.509, 1.753, 2.461, 3.042, 3.553, 3.971, 4.249, 4.342, 4.714, 5.004, 5.271, 5.712, 5.863, 6.211, 6.583, 7.094, 7.57, 7.872, 8.44, 8.638, 8.975, 9.648, 10.136, 10.693, 10.844, 11.227, 12.074]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(28, 17, 'Page 2', 'But she also remembered one mistake.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_2.mp3', NULL, NULL, '{\"words\": [\"But\", \"she\", \"also\", \"remembered\", \"one\", \"mistake.\"], \"start_times\": [0, 0.302, 0.43, 0.685, 1.068, 1.242], \"end_times\": [0.267, 0.383, 0.615, 1.022, 1.207, 1.95]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(29, 17, 'Page 3', 'Years ago, during a drought, she had led her herd toward a river that had already dried up. The herd had found water eventually, but Anu never forgot the exhaustion in their steps.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_3.mp3', NULL, NULL, '{\"words\": [\"Years\", \"ago,\", \"during\", \"a\", \"drought,\", \"she\", \"had\", \"led\", \"her\", \"herd\", \"toward\", \"a\", \"river\", \"that\", \"had\", \"already\", \"dried\", \"up.\", \"The\", \"herd\", \"had\", \"found\", \"water\", \"eventually,\", \"but\", \"Anu\", \"never\", \"forgot\", \"the\", \"exhaustion\", \"in\", \"their\", \"steps.\"], \"start_times\": [0, 0.522, 0.964, 1.277, 1.358, 1.892, 2.067, 2.218, 2.45, 2.635, 2.926, 3.239, 3.332, 3.622, 3.785, 3.924, 4.238, 4.574, 5.213, 5.399, 5.642, 5.793, 6.084, 6.409, 7.314, 7.535, 7.848, 8.115, 8.498, 8.638, 9.242, 9.334, 9.52], \"end_times\": [0.488, 0.906, 1.231, 1.3, 1.834, 2.02, 2.159, 2.392, 2.554, 2.879, 3.193, 3.274, 3.564, 3.75, 3.878, 4.191, 4.516, 4.888, 5.329, 5.596, 5.735, 6.002, 6.339, 7.163, 7.465, 7.79, 8.057, 8.452, 8.568, 9.195, 9.3, 9.474, 10.263]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(30, 17, 'Page 4', 'When another dry season came, the herd turned to her again. The air felt tight and hot. The ground cracked beneath their feet.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_4.mp3', NULL, NULL, '{\"words\": [\"When\", \"another\", \"dry\", \"season\", \"came,\", \"the\", \"herd\", \"turned\", \"to\", \"her\", \"again.\", \"The\", \"air\", \"felt\", \"tight\", \"and\", \"hot.\", \"The\", \"ground\", \"cracked\", \"beneath\", \"their\", \"feet.\"], \"start_times\": [0, 0.313, 0.662, 0.94, 1.3, 1.904, 2.078, 2.322, 2.601, 2.705, 2.844, 3.541, 3.75, 3.971, 4.226, 4.632, 4.818, 5.631, 5.805, 6.165, 6.56, 6.873, 7.07], \"end_times\": [0.267, 0.604, 0.871, 1.242, 1.73, 2.009, 2.287, 2.577, 2.647, 2.786, 3.297, 3.68, 3.913, 4.18, 4.563, 4.737, 5.306, 5.747, 6.084, 6.513, 6.827, 7.024, 7.57]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(31, 17, 'Page 5', 'Anu hesitated.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_5.mp3', NULL, NULL, '{\"words\": [\"Anu\", \"hesitated.\"], \"start_times\": [0, 0.453], \"end_times\": [0.395, 1.254]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(32, 17, 'Page 6', 'She remembered the failure clearly. But she also remembered the signs she had missed — the direction of birds, the smell of damp earth carried faintly on wind.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_6.mp3', NULL, NULL, '{\"words\": [\"She\", \"remembered\", \"the\", \"failure\", \"clearly.\", \"But\", \"she\", \"also\", \"remembered\", \"the\", \"signs\", \"she\", \"had\", \"missed\", \"u2014\", \"the\", \"direction\", \"of\", \"birds,\", \"the\", \"smell\", \"of\", \"damp\", \"earth\", \"carried\", \"faintly\", \"on\", \"wind.\"], \"start_times\": [0, 0.337, 0.72, 0.848, 1.242, 1.962, 2.148, 2.299, 2.601, 2.995, 3.123, 3.553, 3.704, 3.866, 4.319, 4.528, 4.679, 5.132, 5.259, 6.026, 6.2, 6.502, 6.629, 6.931, 7.256, 7.616, 8.011, 8.162], \"end_times\": [0.267, 0.697, 0.789, 1.196, 1.788, 2.113, 2.229, 2.519, 2.961, 3.065, 3.506, 3.646, 3.808, 4.203, 4.377, 4.632, 5.085, 5.19, 5.817, 6.142, 6.455, 6.56, 6.861, 7.187, 7.558, 7.941, 8.104, 9.056]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(33, 17, 'Page 7', 'This time she walked slowly, paying attention. She tested the air, felt the earth, watched the sky.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_7.mp3', NULL, NULL, '{\"words\": [\"This\", \"time\", \"she\", \"walked\", \"slowly,\", \"paying\", \"attention.\", \"She\", \"tested\", \"the\", \"air,\", \"felt\", \"the\", \"earth,\", \"watched\", \"the\", \"sky.\"], \"start_times\": [0, 0.36, 0.592, 0.743, 1.033, 1.474, 1.765, 2.659, 2.856, 3.228, 3.367, 3.727, 4.005, 4.145, 4.609, 4.992, 5.108], \"end_times\": [0.302, 0.557, 0.685, 0.987, 1.451, 1.718, 2.415, 2.786, 3.193, 3.297, 3.68, 3.959, 4.075, 4.528, 4.957, 5.062, 5.759]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(34, 17, 'Page 8', 'She chose a different direction.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_8.mp3', NULL, NULL, '{\"words\": [\"She\", \"chose\", \"a\", \"different\", \"direction.\"], \"start_times\": [0, 0.302, 0.569, 0.639, 0.952], \"end_times\": [0.244, 0.534, 0.592, 0.917, 1.765]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(35, 17, 'Page 9', 'After a long journey, they reached a hidden valley where water shimmered between trees.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_9.mp3', NULL, NULL, '{\"words\": [\"After\", \"a\", \"long\", \"journey,\", \"they\", \"reached\", \"a\", \"hidden\", \"valley\", \"where\", \"water\", \"shimmered\", \"between\", \"trees.\"], \"start_times\": [0, 0.453, 0.534, 0.801, 1.173, 1.347, 1.637, 1.718, 2.02, 2.368, 2.577, 2.961, 3.332, 3.68], \"end_times\": [0.406, 0.476, 0.731, 1.149, 1.289, 1.602, 1.66, 1.962, 2.322, 2.543, 2.891, 3.297, 3.634, 4.365]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(36, 17, 'Page 10', 'As the herd drank deeply, Anu felt her heavy memory shift. It was no longer a burden.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_10.mp3', NULL, NULL, '{\"words\": [\"As\", \"the\", \"herd\", \"drank\", \"deeply,\", \"Anu\", \"felt\", \"her\", \"heavy\", \"memory\", \"shift.\", \"It\", \"was\", \"no\", \"longer\", \"a\", \"burden.\"], \"start_times\": [0, 0.337, 0.453, 0.662, 0.952, 1.614, 1.892, 2.148, 2.299, 2.577, 2.949, 3.727, 3.878, 4.052, 4.226, 4.551, 4.632], \"end_times\": [0.29, 0.406, 0.639, 0.882, 1.44, 1.846, 2.101, 2.241, 2.508, 2.891, 3.448, 3.843, 3.982, 4.156, 4.505, 4.586, 5.248]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(37, 17, 'Page 11', 'It was guidance.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_17_page_11.mp3', NULL, NULL, '{\"words\": [\"It\", \"was\", \"guidance.\"], \"start_times\": [0, 0.302, 0.453], \"end_times\": [0.267, 0.395, 1.3]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(38, 18, 'Page 1', 'Far beneath the surface of a vast blue ocean lived a sea turtle named Neri. Her shell was marked with pale lines like maps of journeys long past. She had swum through warm currents and cold tides, through seasons of calm and seasons of chaos.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_1.mp3', NULL, NULL, '{\"words\": [\"Far\", \"beneath\", \"the\", \"surface\", \"of\", \"a\", \"vast\", \"blue\", \"ocean\", \"lived\", \"a\", \"sea\", \"turtle\", \"named\", \"Neri.\", \"Her\", \"shell\", \"was\", \"marked\", \"with\", \"pale\", \"lines\", \"like\", \"maps\", \"of\", \"journeys\", \"long\", \"past.\", \"She\", \"had\", \"swum\", \"through\", \"warm\", \"currents\", \"and\", \"cold\", \"tides,\", \"through\", \"seasons\", \"of\", \"calm\", \"and\", \"seasons\", \"of\", \"chaos.\"], \"start_times\": [0, 0.441, 0.743, 0.859, 1.254, 1.37, 1.463, 1.823, 2.078, 2.67, 2.937, 3.03, 3.274, 3.68, 4.017, 5.41, 5.619, 5.979, 6.177, 6.467, 6.641, 7.036, 7.523, 7.779, 8.139, 8.266, 8.789, 9.137, 10.333, 10.53, 10.693, 11.029, 11.308, 11.645, 12.109, 12.295, 12.632, 13.491, 13.781, 14.211, 14.35, 14.745, 14.884, 15.267, 15.383], \"end_times\": [0.372, 0.708, 0.813, 1.231, 1.324, 1.405, 1.765, 2.032, 2.496, 2.902, 2.961, 3.228, 3.634, 3.936, 4.598, 5.55, 5.909, 6.095, 6.444, 6.583, 6.978, 7.454, 7.709, 8.092, 8.197, 8.673, 9.056, 9.822, 10.472, 10.646, 10.971, 11.262, 11.575, 12.063, 12.214, 12.585, 13.282, 13.746, 14.164, 14.269, 14.687, 14.826, 15.232, 15.325, 16.208]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(39, 18, 'Page 2', 'Unlike the younger turtles, Neri never hurried. While others darted playfully through coral gardens and chased schools of glittering fish, she preferred the deeper waters where movement was slower and quieter. Down there, the sea spoke in steady rhythms.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_2.mp3', NULL, NULL, '{\"words\": [\"Unlike\", \"the\", \"younger\", \"turtles,\", \"Neri\", \"never\", \"hurried.\", \"While\", \"others\", \"darted\", \"playfully\", \"through\", \"coral\", \"gardens\", \"and\", \"chased\", \"schools\", \"of\", \"glittering\", \"fish,\", \"she\", \"preferred\", \"the\", \"deeper\", \"waters\", \"where\", \"movement\", \"was\", \"slower\", \"and\", \"quieter.\", \"Down\", \"there,\", \"the\", \"sea\", \"spoke\", \"in\", \"steady\", \"rhythms.\"], \"start_times\": [0, 0.511, 0.639, 0.929, 1.498, 1.834, 2.09, 2.914, 3.204, 3.564, 3.936, 4.47, 4.737, 5.12, 5.642, 5.863, 6.316, 6.815, 6.966, 7.5, 8.348, 8.545, 8.986, 9.102, 9.439, 9.88, 10.112, 10.542, 10.728, 11.215, 11.401, 12.701, 12.992, 13.235, 13.375, 13.642, 14.025, 14.187, 14.594], \"end_times\": [0.488, 0.58, 0.871, 1.405, 1.776, 2.043, 2.589, 3.158, 3.495, 3.878, 4.423, 4.679, 5.062, 5.608, 5.793, 6.246, 6.769, 6.873, 7.419, 8.022, 8.487, 8.951, 9.056, 9.381, 9.834, 10.066, 10.495, 10.67, 11.146, 11.331, 12.098, 12.945, 13.212, 13.305, 13.572, 13.978, 14.094, 14.524, 15.325]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(40, 18, 'Page 3', 'One year, something felt different.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_3.mp3', NULL, NULL, '{\"words\": [\"One\", \"year,\", \"something\", \"felt\", \"different.\"], \"start_times\": [0, 0.418, 0.778, 1.149, 1.37], \"end_times\": [0.383, 0.731, 1.091, 1.324, 2.09]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(41, 18, 'Page 4', 'The water did not move the way it usually did. The currents twisted in unusual directions. Tiny fish scattered for no clear reason. Even the coral seemed to hold its breath.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_4.mp3', NULL, NULL, '{\"words\": [\"The\", \"water\", \"did\", \"not\", \"move\", \"the\", \"way\", \"it\", \"usually\", \"did.\", \"The\", \"currents\", \"twisted\", \"in\", \"unusual\", \"directions.\", \"Tiny\", \"fish\", \"scattered\", \"for\", \"no\", \"clear\", \"reason.\", \"Even\", \"the\", \"coral\", \"seemed\", \"to\", \"hold\", \"its\", \"breath.\"], \"start_times\": [0, 0.302, 0.615, 0.778, 0.964, 1.207, 1.324, 1.498, 1.625, 2.02, 2.728, 2.902, 3.32, 3.82, 3.947, 4.47, 5.561, 5.944, 6.2, 6.641, 6.815, 7.012, 7.314, 8.197, 8.475, 8.591, 8.998, 9.242, 9.334, 9.555, 9.718], \"end_times\": [0.255, 0.557, 0.731, 0.906, 1.173, 1.277, 1.451, 1.567, 1.974, 2.403, 2.844, 3.262, 3.762, 3.878, 4.412, 5.283, 5.875, 6.153, 6.594, 6.757, 6.931, 7.245, 7.872, 8.44, 8.545, 8.928, 9.218, 9.288, 9.509, 9.671, 10.542]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(42, 18, 'Page 5', 'Neri felt it before the clouds gathered above.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_5.mp3', NULL, NULL, '{\"words\": [\"Neri\", \"felt\", \"it\", \"before\", \"the\", \"clouds\", \"gathered\", \"above.\"], \"start_times\": [0, 0.476, 0.708, 0.801, 1.068, 1.173, 1.544, 1.916], \"end_times\": [0.418, 0.662, 0.766, 1.033, 1.138, 1.498, 1.881, 2.508]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(43, 18, 'Page 6', 'She sensed the tightening pressure in the water, the subtle vibration traveling through the ocean floor. A storm was coming — a powerful one.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_6.mp3', NULL, NULL, '{\"words\": [\"She\", \"sensed\", \"the\", \"tightening\", \"pressure\", \"in\", \"the\", \"water,\", \"the\", \"subtle\", \"vibration\", \"traveling\", \"through\", \"the\", \"ocean\", \"floor.\", \"A\", \"storm\", \"was\", \"coming\", \"u2014\", \"a\", \"powerful\", \"one.\"], \"start_times\": [0, 0.337, 0.662, 0.766, 1.173, 1.533, 1.625, 1.73, 2.438, 2.601, 2.914, 3.553, 4.052, 4.272, 4.412, 4.76, 5.921, 6.072, 6.42, 6.583, 7.024, 7.535, 7.674, 8.173], \"end_times\": [0.267, 0.639, 0.731, 1.115, 1.498, 1.579, 1.695, 2.229, 2.554, 2.879, 3.495, 4.005, 4.238, 4.342, 4.69, 5.317, 5.991, 6.374, 6.525, 6.873, 7.094, 7.593, 8.104, 8.638]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(44, 18, 'Page 7', 'The younger turtles continued playing near the surface, unaware of what was building in the sky. Neri rose slowly from the depths and began guiding them downward.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_7.mp3', NULL, NULL, '{\"words\": [\"The\", \"younger\", \"turtles\", \"continued\", \"playing\", \"near\", \"the\", \"surface,\", \"unaware\", \"of\", \"what\", \"was\", \"building\", \"in\", \"the\", \"sky.\", \"Neri\", \"rose\", \"slowly\", \"from\", \"the\", \"depths\", \"and\", \"began\", \"guiding\", \"them\", \"downward.\"], \"start_times\": [0, 0.279, 0.592, 0.952, 1.451, 1.8, 1.985, 2.101, 2.868, 3.332, 3.437, 3.587, 3.75, 4.098, 4.18, 4.296, 5.224, 5.584, 5.84, 6.235, 6.42, 6.536, 6.896, 7.036, 7.396, 7.767, 7.964], \"end_times\": [0.221, 0.534, 0.906, 1.416, 1.753, 1.939, 2.055, 2.717, 3.297, 3.39, 3.553, 3.692, 4.063, 4.145, 4.249, 4.841, 5.515, 5.805, 6.188, 6.374, 6.49, 6.85, 6.978, 7.314, 7.721, 7.895, 8.684]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(45, 18, 'Page 8', 'She did not rush. Panic spreads faster than waves. Instead, she moved with calm determination, showing them where the water grew thicker and more stable. She led them toward a deep trench where the force of surface waves could not reach easily.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_8.mp3', NULL, NULL, '{\"words\": [\"She\", \"did\", \"not\", \"rush.\", \"Panic\", \"spreads\", \"faster\", \"than\", \"waves.\", \"Instead,\", \"she\", \"moved\", \"with\", \"calm\", \"determination,\", \"showing\", \"them\", \"where\", \"the\", \"water\", \"grew\", \"thicker\", \"and\", \"more\", \"stable.\", \"She\", \"led\", \"them\", \"toward\", \"a\", \"deep\", \"trench\", \"where\", \"the\", \"force\", \"of\", \"surface\", \"waves\", \"could\", \"not\", \"reach\", \"easily.\"], \"start_times\": [0, 0.313, 0.476, 0.639, 1.358, 1.788, 2.136, 2.566, 2.74, 3.634, 4.075, 4.249, 4.528, 4.69, 5.016, 6.211, 6.571, 6.745, 6.92, 7.036, 7.384, 7.616, 8.022, 8.185, 8.394, 9.578, 9.787, 9.95, 10.124, 10.356, 10.426, 10.681, 11.064, 11.238, 11.378, 11.726, 11.877, 12.283, 12.701, 12.934, 13.177, 13.468], \"end_times\": [0.267, 0.43, 0.592, 1.115, 1.741, 2.078, 2.519, 2.682, 3.355, 4.052, 4.18, 4.493, 4.644, 4.957, 5.886, 6.525, 6.699, 6.896, 6.989, 7.326, 7.546, 7.953, 8.127, 8.348, 8.975, 9.718, 9.927, 10.066, 10.321, 10.379, 10.623, 11.018, 11.204, 11.308, 11.68, 11.796, 12.249, 12.632, 12.875, 13.108, 13.41, 14.118]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(46, 18, 'Page 9', 'When the storm finally struck, the ocean above turned violent. Waves crashed like mountains collapsing. The surface exploded with white foam and roaring wind.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_9.mp3', NULL, NULL, '{\"words\": [\"When\", \"the\", \"storm\", \"finally\", \"struck,\", \"the\", \"ocean\", \"above\", \"turned\", \"violent.\", \"Waves\", \"crashed\", \"like\", \"mountains\", \"collapsing.\", \"The\", \"surface\", \"exploded\", \"with\", \"white\", \"foam\", \"and\", \"roaring\", \"wind.\"], \"start_times\": [0, 0.325, 0.43, 0.789, 1.254, 1.904, 2.101, 2.45, 2.81, 3.111, 4.029, 4.458, 4.865, 5.085, 5.538, 6.548, 6.711, 7.14, 7.744, 7.918, 8.22, 8.591, 8.777, 9.218], \"end_times\": [0.29, 0.395, 0.708, 1.184, 1.753, 2.02, 2.403, 2.763, 3.065, 3.75, 4.4, 4.83, 5.027, 5.48, 6.269, 6.664, 7.105, 7.709, 7.86, 8.162, 8.533, 8.684, 9.149, 9.845]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(47, 18, 'Page 10', 'But below, where Neri had guided them, the water moved differently. It swayed and surged, but it did not break.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_10.mp3', NULL, NULL, '{\"words\": [\"But\", \"below,\", \"where\", \"Neri\", \"had\", \"guided\", \"them,\", \"the\", \"water\", \"moved\", \"differently.\", \"It\", \"swayed\", \"and\", \"surged,\", \"but\", \"it\", \"did\", \"not\", \"break.\"], \"start_times\": [0, 0.325, 0.998, 1.254, 1.533, 1.683, 2.032, 2.461, 2.601, 2.891, 3.111, 3.889, 4.11, 4.551, 4.714, 5.19, 5.352, 5.445, 5.596, 5.747], \"end_times\": [0.29, 0.882, 1.207, 1.486, 1.637, 1.985, 2.334, 2.554, 2.844, 3.088, 3.715, 4.04, 4.505, 4.632, 5.166, 5.317, 5.41, 5.561, 5.712, 6.362]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(48, 18, 'Page 11', 'The younger turtles pressed themselves gently against the ocean floor, remembering how Neri had shown them to let the water pass instead of fighting it.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_11.mp3', NULL, NULL, '{\"words\": [\"The\", \"younger\", \"turtles\", \"pressed\", \"themselves\", \"gently\", \"against\", \"the\", \"ocean\", \"floor,\", \"remembering\", \"how\", \"Neri\", \"had\", \"shown\", \"them\", \"to\", \"let\", \"the\", \"water\", \"pass\", \"instead\", \"of\", \"fighting\", \"it.\"], \"start_times\": [0, 0.29, 0.604, 1.057, 1.382, 1.904, 2.287, 2.612, 2.752, 3.111, 3.82, 4.4, 4.598, 4.934, 5.097, 5.387, 5.584, 5.712, 5.875, 5.991, 6.304, 6.699, 7.047, 7.152, 7.512], \"end_times\": [0.221, 0.557, 0.975, 1.347, 1.834, 2.241, 2.577, 2.682, 3.042, 3.646, 4.342, 4.516, 4.876, 5.05, 5.341, 5.526, 5.654, 5.84, 5.944, 6.246, 6.653, 7.012, 7.094, 7.454, 7.941]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(49, 18, 'Page 12', 'Hours later, the storm drifted away.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_12.mp3', NULL, NULL, '{\"words\": [\"Hours\", \"later,\", \"the\", \"storm\", \"drifted\", \"away.\"], \"start_times\": [0, 0.499, 0.766, 0.882, 1.173, 1.498], \"end_times\": [0.453, 0.743, 0.836, 1.126, 1.463, 2.043]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(50, 18, 'Page 13', 'Sunlight filtered through calmer waters once again. The sea returned to its steady breathing.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_13.mp3', NULL, NULL, '{\"words\": [\"Sunlight\", \"filtered\", \"through\", \"calmer\", \"waters\", \"once\", \"again.\", \"The\", \"sea\", \"returned\", \"to\", \"its\", \"steady\", \"breathing.\"], \"start_times\": [0, 0.615, 0.987, 1.277, 1.637, 1.997, 2.218, 3.158, 3.367, 3.657, 4.075, 4.226, 4.377, 4.714], \"end_times\": [0.569, 0.964, 1.231, 1.579, 1.939, 2.183, 2.647, 3.297, 3.576, 4.04, 4.145, 4.342, 4.656, 5.387]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(51, 18, 'Page 14', 'The younger turtles looked at Neri with new understanding. She had not been the fastest swimmer. She had not been the loudest or boldest.', 14, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_14.mp3', NULL, NULL, '{\"words\": [\"The\", \"younger\", \"turtles\", \"looked\", \"at\", \"Neri\", \"with\", \"new\", \"understanding.\", \"She\", \"had\", \"not\", \"been\", \"the\", \"fastest\", \"swimmer.\", \"She\", \"had\", \"not\", \"been\", \"the\", \"loudest\", \"or\", \"boldest.\"], \"start_times\": [0, 0.29, 0.604, 1.01, 1.277, 1.428, 1.718, 1.927, 2.136, 3.471, 3.622, 3.762, 3.947, 4.122, 4.226, 4.667, 5.387, 5.561, 5.7, 5.875, 6.06, 6.188, 6.583, 6.722], \"end_times\": [0.221, 0.546, 0.952, 1.242, 1.358, 1.672, 1.846, 2.078, 2.961, 3.587, 3.715, 3.901, 4.087, 4.191, 4.632, 5.143, 5.515, 5.654, 5.828, 6.026, 6.13, 6.548, 6.664, 7.57]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(52, 18, 'Page 15', 'But she had listened to the sea.', 15, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_15.mp3', NULL, NULL, '{\"words\": [\"But\", \"she\", \"had\", \"listened\", \"to\", \"the\", \"sea.\"], \"start_times\": [0, 0.29, 0.43, 0.58, 0.929, 1.033, 1.161], \"end_times\": [0.255, 0.395, 0.522, 0.894, 0.975, 1.103, 1.718]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(53, 18, 'Page 16', 'And in doing so, she had carried them safely through the storm.', 16, 'https://lingola-stories-kids.b-cdn.net/audio/story_18_page_16.mp3', NULL, NULL, '{\"words\": [\"And\", \"in\", \"doing\", \"so,\", \"she\", \"had\", \"carried\", \"them\", \"safely\", \"through\", \"the\", \"storm.\"], \"start_times\": [0, 0.325, 0.453, 0.766, 1.115, 1.289, 1.428, 1.753, 1.939, 2.31, 2.531, 2.635], \"end_times\": [0.267, 0.395, 0.697, 1.068, 1.242, 1.382, 1.73, 1.869, 2.276, 2.508, 2.601, 3.251]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(54, 19, 'Page 1', 'In a forest where snow blanketed the ground for months at a time lived a gray wolf named Orion. His fur blended with winter shadows, and his eyes reflected the silver glow of the night sky.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"a\", \"forest\", \"where\", \"snow\", \"blanketed\", \"the\", \"ground\", \"for\", \"months\", \"at\", \"a\", \"time\", \"lived\", \"a\", \"gray\", \"wolf\", \"named\", \"Orion.\", \"His\", \"fur\", \"blended\", \"with\", \"winter\", \"shadows,\", \"and\", \"his\", \"eyes\", \"reflected\", \"the\", \"silver\", \"glow\", \"of\", \"the\", \"night\", \"sky.\"], \"start_times\": [0, 0.29, 0.383, 0.766, 0.975, 1.289, 1.741, 1.846, 2.171, 2.368, 2.67, 2.775, 2.868, 3.262, 3.518, 3.599, 3.889, 4.238, 4.551, 5.7, 5.933, 6.2, 6.571, 6.734, 7.024, 7.628, 7.825, 7.988, 8.243, 8.707, 8.812, 9.149, 9.404, 9.509, 9.625, 9.868], \"end_times\": [0.244, 0.313, 0.731, 0.929, 1.231, 1.718, 1.811, 2.113, 2.287, 2.624, 2.74, 2.81, 3.204, 3.483, 3.541, 3.831, 4.156, 4.481, 5.19, 5.863, 6.13, 6.536, 6.687, 6.978, 7.57, 7.767, 7.918, 8.173, 8.673, 8.777, 9.102, 9.358, 9.462, 9.578, 9.822, 10.495]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(55, 19, 'Page 2', 'Orion loved the moon.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_2.mp3', NULL, NULL, '{\"words\": [\"Orion\", \"loved\", \"the\", \"moon.\"], \"start_times\": [0, 0.639, 0.894, 1.022], \"end_times\": [0.569, 0.859, 0.975, 1.533]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(56, 19, 'Page 3', 'Each evening he waited for it to rise above the tall pines. When its light spilled across the snow, the forest seemed alive with gentle brightness. Under that glow, Orion lifted his head and let his howl stretch across the frozen land.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_3.mp3', NULL, NULL, '{\"words\": [\"Each\", \"evening\", \"he\", \"waited\", \"for\", \"it\", \"to\", \"rise\", \"above\", \"the\", \"tall\", \"pines.\", \"When\", \"its\", \"light\", \"spilled\", \"across\", \"the\", \"snow,\", \"the\", \"forest\", \"seemed\", \"alive\", \"with\", \"gentle\", \"brightness.\", \"Under\", \"that\", \"glow,\", \"Orion\", \"lifted\", \"his\", \"head\", \"and\", \"let\", \"his\", \"howl\", \"stretch\", \"across\", \"the\", \"frozen\", \"land.\"], \"start_times\": [0, 0.418, 0.766, 0.906, 1.242, 1.405, 1.509, 1.649, 1.974, 2.229, 2.334, 2.589, 3.704, 3.913, 4.087, 4.354, 4.69, 5.062, 5.178, 5.84, 6.014, 6.478, 6.838, 7.303, 7.512, 7.906, 9.102, 9.404, 9.59, 10.252, 10.774, 11.169, 11.343, 11.668, 11.854, 12.04, 12.202, 12.678, 13.096, 13.479, 13.595, 14.013], \"end_times\": [0.36, 0.697, 0.836, 1.196, 1.347, 1.474, 1.567, 1.939, 2.194, 2.299, 2.531, 3.262, 3.866, 4.029, 4.307, 4.667, 5.016, 5.132, 5.666, 5.944, 6.397, 6.792, 7.268, 7.43, 7.872, 8.661, 9.358, 9.543, 10.077, 10.704, 11.111, 11.285, 11.598, 11.796, 11.993, 12.144, 12.562, 13.05, 13.433, 13.549, 13.955, 14.629]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(57, 19, 'Page 4', 'The moon was his companion, his guide through darkness.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_4.mp3', NULL, NULL, '{\"words\": [\"The\", \"moon\", \"was\", \"his\", \"companion,\", \"his\", \"guide\", \"through\", \"darkness.\"], \"start_times\": [0, 0.279, 0.522, 0.685, 0.848, 1.486, 1.672, 1.939, 2.171], \"end_times\": [0.221, 0.476, 0.627, 0.789, 1.451, 1.602, 1.916, 2.136, 2.926]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(58, 19, 'Page 5', 'Then one winter night, thick clouds rolled in from the mountains. They swallowed the sky whole. The moon vanished completely.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_5.mp3', NULL, NULL, '{\"words\": [\"Then\", \"one\", \"winter\", \"night,\", \"thick\", \"clouds\", \"rolled\", \"in\", \"from\", \"the\", \"mountains.\", \"They\", \"swallowed\", \"the\", \"sky\", \"whole.\", \"The\", \"moon\", \"vanished\", \"completely.\"], \"start_times\": [0, 0.372, 0.557, 0.882, 1.335, 1.602, 2.009, 2.299, 2.438, 2.624, 2.728, 3.611, 3.831, 4.238, 4.342, 4.667, 5.445, 5.631, 5.909, 6.281], \"end_times\": [0.302, 0.522, 0.824, 1.219, 1.556, 1.95, 2.252, 2.38, 2.577, 2.694, 3.332, 3.785, 4.214, 4.307, 4.609, 5.12, 5.573, 5.84, 6.246, 7.105]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(59, 19, 'Page 6', 'The forest felt heavier than Orion had ever known. Snow absorbed what little light remained. The trees stood like silent giants in endless shadow.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_6.mp3', NULL, NULL, '{\"words\": [\"The\", \"forest\", \"felt\", \"heavier\", \"than\", \"Orion\", \"had\", \"ever\", \"known.\", \"Snow\", \"absorbed\", \"what\", \"little\", \"light\", \"remained.\", \"The\", \"trees\", \"stood\", \"like\", \"silent\", \"giants\", \"in\", \"endless\", \"shadow.\"], \"start_times\": [0, 0.313, 0.697, 0.94, 1.289, 1.463, 1.858, 2.032, 2.276, 3.437, 3.947, 4.598, 4.818, 5.108, 5.375, 6.316, 6.502, 6.838, 7.117, 7.326, 7.779, 8.243, 8.417, 8.835], \"end_times\": [0.255, 0.65, 0.894, 1.242, 1.405, 1.8, 1.962, 2.229, 2.74, 3.855, 4.551, 4.76, 5.062, 5.317, 5.991, 6.444, 6.803, 7.082, 7.268, 7.721, 8.197, 8.324, 8.789, 9.52]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(60, 19, 'Page 7', 'Orion waited.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_7.mp3', NULL, NULL, '{\"words\": [\"Orion\", \"waited.\"], \"start_times\": [0, 0.534], \"end_times\": [0.488, 1.115]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(61, 19, 'Page 8', 'He paced between trees, glancing upward, hoping for a break in the clouds.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_8.mp3', NULL, NULL, '{\"words\": [\"He\", \"paced\", \"between\", \"trees,\", \"glancing\", \"upward,\", \"hoping\", \"for\", \"a\", \"break\", \"in\", \"the\", \"clouds.\"], \"start_times\": [0, 0.325, 0.627, 0.964, 1.393, 1.858, 2.461, 2.821, 2.961, 3.03, 3.309, 3.413, 3.518], \"end_times\": [0.255, 0.592, 0.917, 1.347, 1.8, 2.368, 2.763, 2.926, 2.984, 3.262, 3.367, 3.483, 4.319]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(62, 19, 'Page 9', 'But the sky remained closed.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_9.mp3', NULL, NULL, '{\"words\": [\"But\", \"the\", \"sky\", \"remained\", \"closed.\"], \"start_times\": [0, 0.302, 0.406, 0.743, 1.115], \"end_times\": [0.267, 0.372, 0.662, 1.068, 1.904]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11');
INSERT INTO `story_sections` (`id`, `story_id`, `title`, `content`, `page_number`, `elevenlabs_audio_url`, `elevenlabs_voice_id`, `audio_duration`, `word_timestamps`, `created_at`, `updated_at`) VALUES
(63, 19, 'Page 10', 'After hours of restless wandering, he stopped looking upward and began looking inward. He lowered his nose to the snow and followed the faint scent of pine sap. He listened to the distant crack of ice shifting on a frozen stream. He felt the firmness of the ground beneath his paws.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_10.mp3', NULL, NULL, '{\"words\": [\"After\", \"hours\", \"of\", \"restless\", \"wandering,\", \"he\", \"stopped\", \"looking\", \"upward\", \"and\", \"began\", \"looking\", \"inward.\", \"He\", \"lowered\", \"his\", \"nose\", \"to\", \"the\", \"snow\", \"and\", \"followed\", \"the\", \"faint\", \"scent\", \"of\", \"pine\", \"sap.\", \"He\", \"listened\", \"to\", \"the\", \"distant\", \"crack\", \"of\", \"ice\", \"shifting\", \"on\", \"a\", \"frozen\", \"stream.\", \"He\", \"felt\", \"the\", \"firmness\", \"of\", \"the\", \"ground\", \"beneath\", \"his\", \"paws.\"], \"start_times\": [0, 0.441, 0.801, 0.929, 1.358, 2.183, 2.31, 2.624, 2.949, 3.437, 3.611, 3.982, 4.319, 5.677, 5.851, 6.165, 6.339, 6.664, 6.803, 6.92, 7.419, 7.651, 7.988, 8.104, 8.371, 8.684, 8.812, 9.125, 10.066, 10.24, 10.6, 10.716, 10.82, 11.204, 11.505, 11.645, 12.005, 12.469, 12.574, 12.655, 13.073, 14.222, 14.373, 14.582, 14.71, 15.139, 15.232, 15.337, 15.673, 15.975, 16.138], \"end_times\": [0.383, 0.755, 0.859, 1.312, 2.009, 2.252, 2.589, 2.879, 3.379, 3.553, 3.913, 4.261, 4.865, 5.782, 6.13, 6.269, 6.618, 6.734, 6.873, 7.245, 7.581, 7.964, 8.057, 8.313, 8.638, 8.742, 9.091, 9.555, 10.17, 10.565, 10.646, 10.786, 11.157, 11.447, 11.564, 11.958, 12.411, 12.539, 12.608, 13.015, 13.618, 14.327, 14.547, 14.652, 15.105, 15.197, 15.302, 15.615, 15.94, 16.08, 16.811]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(64, 19, 'Page 11', 'Slowly, the forest became familiar again.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_11.mp3', NULL, NULL, '{\"words\": [\"Slowly,\", \"the\", \"forest\", \"became\", \"familiar\", \"again.\"], \"start_times\": [0, 0.639, 0.766, 1.103, 1.44, 1.881], \"end_times\": [0.615, 0.708, 1.057, 1.393, 1.834, 2.415]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(65, 19, 'Page 12', 'The darkness was not empty. It was simply different.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_12.mp3', NULL, NULL, '{\"words\": [\"The\", \"darkness\", \"was\", \"not\", \"empty.\", \"It\", \"was\", \"simply\", \"different.\"], \"start_times\": [0, 0.279, 0.72, 0.894, 1.103, 1.73, 1.892, 2.009, 2.334], \"end_times\": [0.232, 0.685, 0.824, 1.045, 1.614, 1.858, 1.974, 2.287, 3.019]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(66, 19, 'Page 13', 'When Orion finally lifted his head to howl, it was not because he saw the moon.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_13.mp3', NULL, NULL, '{\"words\": [\"When\", \"Orion\", \"finally\", \"lifted\", \"his\", \"head\", \"to\", \"howl,\", \"it\", \"was\", \"not\", \"because\", \"he\", \"saw\", \"the\", \"moon.\"], \"start_times\": [0, 0.337, 0.766, 1.138, 1.451, 1.591, 1.765, 1.881, 2.426, 2.577, 2.717, 2.891, 3.158, 3.251, 3.46, 3.576], \"end_times\": [0.29, 0.697, 1.091, 1.416, 1.544, 1.73, 1.823, 2.31, 2.543, 2.659, 2.844, 3.135, 3.204, 3.413, 3.529, 4.087]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(67, 19, 'Page 14', 'It was because he felt the forest around him.', 14, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_14.mp3', NULL, NULL, '{\"words\": [\"It\", \"was\", \"because\", \"he\", \"felt\", \"the\", \"forest\", \"around\", \"him.\"], \"start_times\": [0, 0.29, 0.43, 0.743, 0.859, 1.08, 1.207, 1.637, 2.02], \"end_times\": [0.255, 0.372, 0.708, 0.801, 1.045, 1.149, 1.591, 1.95, 2.461]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(68, 19, 'Page 15', 'His voice echoed through the trees, strong and steady.', 15, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_15.mp3', NULL, NULL, '{\"words\": [\"His\", \"voice\", \"echoed\", \"through\", \"the\", \"trees,\", \"strong\", \"and\", \"steady.\"], \"start_times\": [0, 0.348, 0.639, 0.964, 1.184, 1.289, 1.823, 2.276, 2.438], \"end_times\": [0.29, 0.58, 0.94, 1.161, 1.254, 1.73, 2.206, 2.38, 3.111]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(69, 19, 'Page 16', 'When the clouds eventually cleared days later and the moon returned, Orion still howled beneath it.', 16, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_16.mp3', NULL, NULL, '{\"words\": [\"When\", \"the\", \"clouds\", \"eventually\", \"cleared\", \"days\", \"later\", \"and\", \"the\", \"moon\", \"returned,\", \"Orion\", \"still\", \"howled\", \"beneath\", \"it.\"], \"start_times\": [0, 0.302, 0.406, 0.755, 1.265, 1.695, 1.997, 2.31, 2.426, 2.531, 2.786, 3.715, 4.238, 4.551, 5.004, 5.352], \"end_times\": [0.267, 0.372, 0.72, 1.196, 1.637, 1.939, 2.264, 2.392, 2.496, 2.728, 3.39, 4.156, 4.47, 4.946, 5.294, 5.759]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(70, 19, 'Page 17', 'But he no longer needed its light to know his way.', 17, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_17.mp3', NULL, NULL, '{\"words\": [\"But\", \"he\", \"no\", \"longer\", \"needed\", \"its\", \"light\", \"to\", \"know\", \"his\", \"way.\"], \"start_times\": [0, 0.29, 0.418, 0.569, 0.859, 1.149, 1.312, 1.556, 1.683, 1.869, 2.02], \"end_times\": [0.244, 0.337, 0.499, 0.813, 1.103, 1.265, 1.521, 1.625, 1.823, 1.962, 2.554]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(71, 19, 'Page 18', 'He had learned that guidance can come from within, even when the sky is hidden.', 18, 'https://lingola-stories-kids.b-cdn.net/audio/story_19_page_18.mp3', NULL, NULL, '{\"words\": [\"He\", \"had\", \"learned\", \"that\", \"guidance\", \"can\", \"come\", \"from\", \"within,\", \"even\", \"when\", \"the\", \"sky\", \"is\", \"hidden.\"], \"start_times\": [0, 0.267, 0.395, 0.639, 0.801, 1.312, 1.498, 1.683, 1.846, 2.438, 2.74, 2.902, 3.019, 3.39, 3.541], \"end_times\": [0.221, 0.348, 0.615, 0.743, 1.265, 1.428, 1.649, 1.8, 2.31, 2.694, 2.868, 2.972, 3.32, 3.483, 4.087]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(72, 20, 'Page 1', 'In bright turquoise waters near a coral reef lived a dolphin named Kael. He was sleek and swift, with a silver line running along his back. While other dolphins traveled in pods, leaping and spinning together, Kael preferred solitude.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"bright\", \"turquoise\", \"waters\", \"near\", \"a\", \"coral\", \"reef\", \"lived\", \"a\", \"dolphin\", \"named\", \"Kael.\", \"He\", \"was\", \"sleek\", \"and\", \"swift,\", \"with\", \"a\", \"silver\", \"line\", \"running\", \"along\", \"his\", \"back.\", \"While\", \"other\", \"dolphins\", \"traveled\", \"in\", \"pods,\", \"leaping\", \"and\", \"spinning\", \"together,\", \"Kael\", \"preferred\", \"solitude.\"], \"start_times\": [0, 0.29, 0.546, 1.045, 1.463, 1.649, 1.73, 2.101, 2.45, 2.694, 2.763, 3.181, 3.46, 4.807, 4.969, 5.132, 5.515, 5.689, 6.304, 6.513, 6.583, 6.954, 7.268, 7.546, 7.814, 7.976, 9.033, 9.334, 9.578, 10.066, 10.484, 10.623, 11.413, 11.865, 12.016, 12.399, 13.282, 13.688, 14.176], \"end_times\": [0.244, 0.511, 1.01, 1.405, 1.614, 1.672, 2.032, 2.368, 2.659, 2.717, 3.135, 3.402, 3.994, 4.923, 5.085, 5.445, 5.608, 6.235, 6.467, 6.536, 6.885, 7.233, 7.5, 7.767, 7.918, 8.429, 9.288, 9.532, 10.019, 10.449, 10.553, 11.238, 11.807, 11.958, 12.341, 13.038, 13.618, 14.118, 15]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(73, 20, 'Page 2', 'He enjoyed exploring distant reefs no one else visited. He liked swimming through narrow rock arches and diving into deeper waters where sunlight barely reached.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_2.mp3', NULL, NULL, '{\"words\": [\"He\", \"enjoyed\", \"exploring\", \"distant\", \"reefs\", \"no\", \"one\", \"else\", \"visited.\", \"He\", \"liked\", \"swimming\", \"through\", \"narrow\", \"rock\", \"arches\", \"and\", \"diving\", \"into\", \"deeper\", \"waters\", \"where\", \"sunlight\", \"barely\", \"reached.\"], \"start_times\": [0, 0.279, 0.755, 1.277, 1.649, 1.985, 2.136, 2.252, 2.45, 3.448, 3.622, 3.866, 4.214, 4.505, 4.853, 5.108, 5.77, 6.026, 6.397, 6.594, 6.92, 7.396, 7.651, 8.081, 8.429], \"end_times\": [0.221, 0.708, 1.219, 1.602, 1.927, 2.078, 2.229, 2.415, 3.007, 3.553, 3.831, 4.168, 4.447, 4.783, 5.05, 5.561, 5.968, 6.351, 6.536, 6.861, 7.349, 7.605, 8.046, 8.359, 9.056]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(74, 20, 'Page 3', 'He believed independence made him stronger.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_3.mp3', NULL, NULL, '{\"words\": [\"He\", \"believed\", \"independence\", \"made\", \"him\", \"stronger.\"], \"start_times\": [0, 0.29, 0.627, 1.254, 1.428, 1.556], \"end_times\": [0.232, 0.58, 1.219, 1.405, 1.509, 2.229]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(75, 20, 'Page 4', 'One afternoon, the ocean shifted without warning. A powerful current swept through the reef like an invisible river. Kael felt the pull but underestimated its strength.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_4.mp3', NULL, NULL, '{\"words\": [\"One\", \"afternoon,\", \"the\", \"ocean\", \"shifted\", \"without\", \"warning.\", \"A\", \"powerful\", \"current\", \"swept\", \"through\", \"the\", \"reef\", \"like\", \"an\", \"invisible\", \"river.\", \"Kael\", \"felt\", \"the\", \"pull\", \"but\", \"underestimated\", \"its\", \"strength.\"], \"start_times\": [0, 0.372, 0.882, 1.022, 1.335, 1.707, 2.009, 2.821, 2.961, 3.413, 3.762, 4.04, 4.249, 4.365, 4.609, 4.783, 4.888, 5.387, 6.188, 6.548, 6.769, 6.885, 7.175, 7.349, 8.104, 8.255], \"end_times\": [0.337, 0.859, 0.952, 1.277, 1.672, 1.962, 2.496, 2.891, 3.344, 3.704, 4.005, 4.226, 4.319, 4.563, 4.76, 4.841, 5.341, 5.805, 6.478, 6.734, 6.838, 7.117, 7.291, 8.057, 8.22, 8.916]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(76, 20, 'Page 5', 'Within moments, he was carried far from the coral gardens he knew. The water grew colder. The colors faded into darker blues. The sea felt endless and unfamiliar.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_5.mp3', NULL, NULL, '{\"words\": [\"Within\", \"moments,\", \"he\", \"was\", \"carried\", \"far\", \"from\", \"the\", \"coral\", \"gardens\", \"he\", \"knew.\", \"The\", \"water\", \"grew\", \"colder.\", \"The\", \"colors\", \"faded\", \"into\", \"darker\", \"blues.\", \"The\", \"sea\", \"felt\", \"endless\", \"and\", \"unfamiliar.\"], \"start_times\": [0, 0.511, 1.08, 1.219, 1.37, 1.741, 2.043, 2.218, 2.334, 2.659, 3.077, 3.193, 4.4, 4.574, 4.888, 5.108, 5.944, 6.118, 6.525, 6.92, 7.14, 7.477, 8.417, 8.603, 8.847, 9.125, 9.659, 9.892], \"end_times\": [0.43, 1.022, 1.173, 1.312, 1.672, 1.974, 2.183, 2.287, 2.601, 3.019, 3.135, 3.587, 4.528, 4.841, 5.05, 5.7, 6.072, 6.455, 6.873, 7.07, 7.43, 8.034, 8.545, 8.777, 9.056, 9.59, 9.81, 10.82]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(77, 20, 'Page 6', 'Kael swam hard against the current, but the force was stronger than his speed. For the first time, doubt crept into his thoughts.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_6.mp3', NULL, NULL, '{\"words\": [\"Kael\", \"swam\", \"hard\", \"against\", \"the\", \"current,\", \"but\", \"the\", \"force\", \"was\", \"stronger\", \"than\", \"his\", \"speed.\", \"For\", \"the\", \"first\", \"time,\", \"doubt\", \"crept\", \"into\", \"his\", \"thoughts.\"], \"start_times\": [0, 0.522, 0.871, 1.126, 1.428, 1.533, 2.055, 2.229, 2.345, 2.624, 2.763, 3.158, 3.344, 3.483, 4.656, 4.841, 4.969, 5.248, 5.793, 6.107, 6.432, 6.676, 6.827], \"end_times\": [0.441, 0.789, 1.091, 1.393, 1.498, 1.962, 2.206, 2.299, 2.601, 2.717, 3.111, 3.286, 3.448, 3.959, 4.807, 4.911, 5.213, 5.642, 6.049, 6.385, 6.606, 6.78, 7.523]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(78, 20, 'Page 7', 'Then, faintly, he heard it — the sharp clicking sounds of dolphins communicating in the distance.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_7.mp3', NULL, NULL, '{\"words\": [\"Then,\", \"faintly,\", \"he\", \"heard\", \"it\", \"u2014\", \"the\", \"sharp\", \"clicking\", \"sounds\", \"of\", \"dolphins\", \"communicating\", \"in\", \"the\", \"distance.\"], \"start_times\": [0, 0.383, 0.801, 0.929, 1.184, 1.347, 1.683, 1.834, 2.148, 2.519, 2.833, 2.949, 3.39, 4.005, 4.087, 4.191], \"end_times\": [0.337, 0.766, 0.859, 1.138, 1.277, 1.405, 1.788, 2.067, 2.461, 2.798, 2.891, 3.344, 3.971, 4.052, 4.156, 4.969]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(79, 20, 'Page 8', 'A pod approached, moving in perfect coordination. They did not rush him. They circled gently, adjusting their path to create a current of their own. Swimming together, they shifted the water’s movement just enough to guide Kael toward safer, warmer currents.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_8.mp3', NULL, NULL, '{\"words\": [\"A\", \"pod\", \"approached,\", \"moving\", \"in\", \"perfect\", \"coordination.\", \"They\", \"did\", \"not\", \"rush\", \"him.\", \"They\", \"circled\", \"gently,\", \"adjusting\", \"their\", \"path\", \"to\", \"create\", \"a\", \"current\", \"of\", \"their\", \"own.\", \"Swimming\", \"together,\", \"they\", \"shifted\", \"the\", \"wateru2019s\", \"movement\", \"just\", \"enough\", \"to\", \"guide\", \"Kael\", \"toward\", \"safer,\", \"warmer\", \"currents.\"], \"start_times\": [0, 0.279, 0.522, 1.265, 1.579, 1.695, 2.067, 3.077, 3.274, 3.448, 3.646, 3.901, 4.493, 4.714, 5.097, 5.619, 6.142, 6.327, 6.699, 6.85, 7.129, 7.198, 7.57, 7.663, 7.872, 8.684, 9.056, 9.648, 9.857, 10.228, 10.344, 10.739, 11.146, 11.436, 11.703, 11.807, 12.074, 12.434, 12.771, 13.386, 13.804], \"end_times\": [0.197, 0.499, 1.149, 1.533, 1.637, 2.02, 2.868, 3.239, 3.39, 3.587, 3.855, 4.214, 4.656, 5.05, 5.584, 6.107, 6.281, 6.641, 6.78, 7.105, 7.152, 7.523, 7.616, 7.814, 8.243, 9.009, 9.567, 9.799, 10.194, 10.298, 10.67, 11.088, 11.378, 11.668, 11.749, 12.028, 12.365, 12.701, 13.27, 13.746, 14.536]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(80, 20, 'Page 9', 'The journey back felt different from his usual explorations. It was not about speed. It was about rhythm — matching movements, adjusting together.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_9.mp3', NULL, NULL, '{\"words\": [\"The\", \"journey\", \"back\", \"felt\", \"different\", \"from\", \"his\", \"usual\", \"explorations.\", \"It\", \"was\", \"not\", \"about\", \"speed.\", \"It\", \"was\", \"about\", \"rhythm\", \"u2014\", \"matching\", \"movements,\", \"adjusting\", \"together.\"], \"start_times\": [0, 0.313, 0.65, 0.94, 1.196, 1.579, 1.776, 1.962, 2.403, 4.284, 4.447, 4.621, 4.83, 5.132, 6.084, 6.223, 6.351, 6.641, 7.14, 7.396, 7.872, 8.626, 9.207], \"end_times\": [0.244, 0.592, 0.871, 1.138, 1.533, 1.718, 1.892, 2.322, 3.471, 4.412, 4.551, 4.795, 5.05, 5.759, 6.188, 6.316, 6.583, 6.966, 7.221, 7.802, 8.568, 9.149, 10.542]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(81, 20, 'Page 10', 'When they reached familiar waters again, Kael did not immediately swim away.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_10.mp3', NULL, NULL, '{\"words\": [\"When\", \"they\", \"reached\", \"familiar\", \"waters\", \"again,\", \"Kael\", \"did\", \"not\", \"immediately\", \"swim\", \"away.\"], \"start_times\": [0, 0.325, 0.511, 0.789, 1.196, 1.544, 1.985, 2.368, 2.519, 2.682, 3.181, 3.46], \"end_times\": [0.29, 0.441, 0.755, 1.149, 1.498, 1.904, 2.299, 2.485, 2.647, 3.135, 3.402, 4.087]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(82, 20, 'Page 11', 'He stayed.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_11.mp3', NULL, NULL, '{\"words\": [\"He\", \"stayed.\"], \"start_times\": [0, 0.325], \"end_times\": [0.255, 1.022]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(83, 20, 'Page 12', 'He realized solitude had given him courage. But connection gave him strength.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_12.mp3', NULL, NULL, '{\"words\": [\"He\", \"realized\", \"solitude\", \"had\", \"given\", \"him\", \"courage.\", \"But\", \"connection\", \"gave\", \"him\", \"strength.\"], \"start_times\": [0, 0.313, 0.708, 1.3, 1.44, 1.707, 1.858, 2.682, 2.879, 3.344, 3.541, 3.692], \"end_times\": [0.244, 0.673, 1.265, 1.405, 1.66, 1.8, 2.403, 2.844, 3.297, 3.506, 3.634, 4.365]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(84, 20, 'Page 13', 'From then on, he still explored alone sometimes — but he always listened for the sound of the pod.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_13.mp3', NULL, NULL, '{\"words\": [\"From\", \"then\", \"on,\", \"he\", \"still\", \"explored\", \"alone\", \"sometimes\", \"u2014\", \"but\", \"he\", \"always\", \"listened\", \"for\", \"the\", \"sound\", \"of\", \"the\", \"pod.\"], \"start_times\": [0, 0.36, 0.604, 0.917, 1.08, 1.382, 1.916, 2.264, 3.019, 3.39, 3.576, 3.692, 4.017, 4.365, 4.505, 4.621, 4.899, 4.992, 5.097], \"end_times\": [0.313, 0.522, 0.871, 1.01, 1.324, 1.881, 2.229, 2.844, 3.065, 3.541, 3.622, 3.971, 4.331, 4.458, 4.574, 4.853, 4.946, 5.062, 5.666]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(85, 20, 'Page 14', 'Because even the strongest swimmer benefits from shared direction.', 14, 'https://lingola-stories-kids.b-cdn.net/audio/story_20_page_14.mp3', NULL, NULL, '{\"words\": [\"Because\", \"even\", \"the\", \"strongest\", \"swimmer\", \"benefits\", \"from\", \"shared\", \"direction.\"], \"start_times\": [0, 0.383, 0.604, 0.72, 1.173, 1.544, 2.009, 2.206, 2.485], \"end_times\": [0.337, 0.569, 0.673, 1.138, 1.474, 1.974, 2.148, 2.461, 3.297]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(86, 21, 'Page 1', 'Across rolling hills brushed with tall golden grass lived a fox named Sol. His fur glowed like fire under the sun, and he loved nothing more than to run.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_1.mp3', NULL, NULL, '{\"words\": [\"Across\", \"rolling\", \"hills\", \"brushed\", \"with\", \"tall\", \"golden\", \"grass\", \"lived\", \"a\", \"fox\", \"named\", \"Sol.\", \"His\", \"fur\", \"glowed\", \"like\", \"fire\", \"under\", \"the\", \"sun,\", \"and\", \"he\", \"loved\", \"nothing\", \"more\", \"than\", \"to\", \"run.\"], \"start_times\": [0, 0.592, 0.94, 1.231, 1.544, 1.73, 2.043, 2.392, 2.798, 3.03, 3.111, 3.471, 3.738, 4.83, 5.085, 5.375, 5.793, 6.002, 6.351, 6.571, 6.687, 7.233, 7.43, 7.546, 7.825, 8.162, 8.382, 8.545, 8.696], \"end_times\": [0.522, 0.894, 1.173, 1.521, 1.672, 1.974, 2.345, 2.74, 3.007, 3.053, 3.402, 3.68, 4.226, 5.004, 5.294, 5.759, 5.944, 6.316, 6.525, 6.641, 7.059, 7.384, 7.488, 7.755, 8.104, 8.336, 8.499, 8.615, 9.242]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(87, 21, 'Page 2', 'Sol chased the wind as if it were alive. When a gust swept across the field, he sprinted after it, leaping over stones and weaving through grass. The faster he ran, the freer he felt.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_2.mp3', NULL, NULL, '{\"words\": [\"Sol\", \"chased\", \"the\", \"wind\", \"as\", \"if\", \"it\", \"were\", \"alive.\", \"When\", \"a\", \"gust\", \"swept\", \"across\", \"the\", \"field,\", \"he\", \"sprinted\", \"after\", \"it,\", \"leaping\", \"over\", \"stones\", \"and\", \"weaving\", \"through\", \"grass.\", \"The\", \"faster\", \"he\", \"ran,\", \"the\", \"freer\", \"he\", \"felt.\"], \"start_times\": [0, 0.476, 0.813, 0.929, 1.149, 1.265, 1.382, 1.474, 1.649, 2.635, 2.844, 2.926, 3.251, 3.564, 3.878, 3.994, 4.423, 4.574, 5.05, 5.352, 5.596, 5.991, 6.235, 6.676, 6.815, 7.129, 7.349, 8.243, 8.417, 8.835, 8.986, 9.288, 9.404, 9.729, 9.857], \"end_times\": [0.418, 0.778, 0.882, 1.103, 1.219, 1.335, 1.44, 1.614, 2.252, 2.81, 2.868, 3.181, 3.529, 3.843, 3.947, 4.365, 4.505, 5.004, 5.283, 5.503, 5.933, 6.165, 6.629, 6.757, 7.094, 7.314, 7.918, 8.359, 8.777, 8.905, 9.253, 9.358, 9.671, 9.787, 10.403]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(88, 21, 'Page 3', 'He believed freedom meant outrunning everything.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_3.mp3', NULL, NULL, '{\"words\": [\"He\", \"believed\", \"freedom\", \"meant\", \"outrunning\", \"everything.\"], \"start_times\": [0, 0.29, 0.65, 1.01, 1.312, 1.892], \"end_times\": [0.232, 0.604, 0.952, 1.242, 1.823, 2.694]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(89, 21, 'Page 4', 'One autumn afternoon, dark clouds drifted lazily above the hills. A strong wind rushed across the valley, bending grass flat against the earth. Sol took off at full speed, racing the gust toward the highest hill.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_4.mp3', NULL, NULL, '{\"words\": [\"One\", \"autumn\", \"afternoon,\", \"dark\", \"clouds\", \"drifted\", \"lazily\", \"above\", \"the\", \"hills.\", \"A\", \"strong\", \"wind\", \"rushed\", \"across\", \"the\", \"valley,\", \"bending\", \"grass\", \"flat\", \"against\", \"the\", \"earth.\", \"Sol\", \"took\", \"off\", \"at\", \"full\", \"speed,\", \"racing\", \"the\", \"gust\", \"toward\", \"the\", \"highest\", \"hill.\"], \"start_times\": [0, 0.43, 0.72, 1.474, 1.776, 2.194, 2.589, 3.03, 3.274, 3.39, 4.377, 4.54, 4.957, 5.306, 5.608, 5.968, 6.072, 6.571, 6.954, 7.303, 7.686, 8.034, 8.15, 9.021, 9.416, 9.659, 9.857, 9.985, 10.252, 10.96, 11.401, 11.517, 11.923, 12.225, 12.341, 12.725], \"end_times\": [0.383, 0.685, 1.358, 1.718, 2.136, 2.543, 2.984, 3.251, 3.344, 3.936, 4.458, 4.888, 5.224, 5.573, 5.933, 6.037, 6.502, 6.908, 7.245, 7.616, 7.988, 8.104, 8.58, 9.358, 9.601, 9.81, 9.927, 10.194, 10.786, 11.355, 11.471, 11.854, 12.19, 12.295, 12.678, 13.235]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(90, 21, 'Page 5', 'He climbed higher and higher, paws pounding against dry soil.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_5.mp3', NULL, NULL, '{\"words\": [\"He\", \"climbed\", \"higher\", \"and\", \"higher,\", \"paws\", \"pounding\", \"against\", \"dry\", \"soil.\"], \"start_times\": [0, 0.302, 0.72, 1.149, 1.335, 1.916, 2.403, 2.914, 3.239, 3.576], \"end_times\": [0.244, 0.662, 1.068, 1.265, 1.8, 2.322, 2.868, 3.193, 3.495, 4.18]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(91, 21, 'Page 6', 'Then suddenly, at the very top, the wind stopped.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_6.mp3', NULL, NULL, '{\"words\": [\"Then\", \"suddenly,\", \"at\", \"the\", \"very\", \"top,\", \"the\", \"wind\", \"stopped.\"], \"start_times\": [0, 0.348, 0.813, 0.929, 1.045, 1.289, 1.602, 1.73, 1.962], \"end_times\": [0.29, 0.789, 0.894, 0.998, 1.231, 1.567, 1.683, 1.904, 2.601]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(92, 21, 'Page 7', 'The world fell silent.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_7.mp3', NULL, NULL, '{\"words\": [\"The\", \"world\", \"fell\", \"silent.\"], \"start_times\": [0, 0.279, 0.534, 0.731], \"end_times\": [0.232, 0.488, 0.685, 1.393]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(93, 21, 'Page 8', 'The tall grass stood still. Leaves rested motionless on branches. Even the air felt paused.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_8.mp3', NULL, NULL, '{\"words\": [\"The\", \"tall\", \"grass\", \"stood\", \"still.\", \"Leaves\", \"rested\", \"motionless\", \"on\", \"branches.\", \"Even\", \"the\", \"air\", \"felt\", \"paused.\"], \"start_times\": [0, 0.267, 0.522, 0.859, 1.138, 1.939, 2.264, 2.612, 3.123, 3.251, 4.156, 4.435, 4.574, 4.795, 5.039], \"end_times\": [0.221, 0.476, 0.824, 1.091, 1.66, 2.206, 2.554, 3.077, 3.204, 3.947, 4.4, 4.505, 4.737, 4.981, 5.759]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(94, 21, 'Page 9', 'Sol stood there, confused. Without the wind to chase, he did not know what to do. For the first time, he realized he had never run without following something else.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_9.mp3', NULL, NULL, '{\"words\": [\"Sol\", \"stood\", \"there,\", \"confused.\", \"Without\", \"the\", \"wind\", \"to\", \"chase,\", \"he\", \"did\", \"not\", \"know\", \"what\", \"to\", \"do.\", \"For\", \"the\", \"first\", \"time,\", \"he\", \"realized\", \"he\", \"had\", \"never\", \"run\", \"without\", \"following\", \"something\", \"else.\"], \"start_times\": [0, 0.546, 0.813, 1.033, 2.055, 2.392, 2.508, 2.74, 2.856, 3.239, 3.355, 3.518, 3.669, 3.855, 4.029, 4.156, 4.853, 5.016, 5.12, 5.364, 5.666, 5.793, 6.258, 6.351, 6.478, 6.734, 7.001, 7.314, 7.721, 8.069], \"end_times\": [0.464, 0.778, 0.998, 1.811, 2.357, 2.461, 2.694, 2.798, 3.216, 3.297, 3.471, 3.622, 3.808, 3.994, 4.087, 4.528, 4.981, 5.085, 5.329, 5.631, 5.724, 6.223, 6.304, 6.432, 6.664, 6.943, 7.268, 7.663, 7.999, 8.731]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(95, 21, 'Page 10', 'He sat down and watched.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_10.mp3', NULL, NULL, '{\"words\": [\"He\", \"sat\", \"down\", \"and\", \"watched.\"], \"start_times\": [0, 0.29, 0.557, 0.778, 0.906], \"end_times\": [0.232, 0.499, 0.731, 0.859, 1.533]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(96, 21, 'Page 11', 'Minutes passed.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_11.mp3', NULL, NULL, '{\"words\": [\"Minutes\", \"passed.\"], \"start_times\": [0, 0.546], \"end_times\": [0.499, 1.254]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(97, 21, 'Page 12', 'Slowly, he noticed subtle movements — a faint ripple in distant grass, a soft swirl of air brushing his whiskers. The world had its own rhythm, even without dramatic gusts.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_12.mp3', NULL, NULL, '{\"words\": [\"Slowly,\", \"he\", \"noticed\", \"subtle\", \"movements\", \"u2014\", \"a\", \"faint\", \"ripple\", \"in\", \"distant\", \"grass,\", \"a\", \"soft\", \"swirl\", \"of\", \"air\", \"brushing\", \"his\", \"whiskers.\", \"The\", \"world\", \"had\", \"its\", \"own\", \"rhythm,\", \"even\", \"without\", \"dramatic\", \"gusts.\"], \"start_times\": [0, 0.824, 1.01, 1.463, 1.858, 2.566, 2.937, 3.111, 3.506, 3.901, 4.04, 4.435, 5.155, 5.317, 5.712, 6.13, 6.269, 6.583, 6.978, 7.129, 8.429, 8.615, 8.986, 9.149, 9.3, 9.52, 10.147, 10.449, 10.82, 11.308], \"end_times\": [0.778, 0.929, 1.37, 1.811, 2.392, 2.612, 2.995, 3.39, 3.855, 3.971, 4.389, 5.039, 5.224, 5.642, 6.084, 6.188, 6.502, 6.92, 7.082, 7.825, 8.557, 8.94, 9.102, 9.253, 9.474, 10.019, 10.403, 10.774, 11.25, 12.121]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(98, 21, 'Page 13', 'Sol stood again, but this time he did not sprint blindly. He began to move with the breeze when it returned, adjusting his pace instead of fighting it.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_13.mp3', NULL, NULL, '{\"words\": [\"Sol\", \"stood\", \"again,\", \"but\", \"this\", \"time\", \"he\", \"did\", \"not\", \"sprint\", \"blindly.\", \"He\", \"began\", \"to\", \"move\", \"with\", \"the\", \"breeze\", \"when\", \"it\", \"returned,\", \"adjusting\", \"his\", \"pace\", \"instead\", \"of\", \"fighting\", \"it.\"], \"start_times\": [0, 0.441, 0.685, 0.998, 1.149, 1.37, 1.649, 1.765, 1.916, 2.113, 2.461, 3.518, 3.68, 3.982, 4.098, 4.307, 4.458, 4.563, 4.911, 5.074, 5.178, 5.759, 6.293, 6.444, 6.757, 7.082, 7.187, 7.558], \"end_times\": [0.383, 0.65, 0.964, 1.115, 1.312, 1.602, 1.707, 1.869, 2.055, 2.415, 3.077, 3.622, 3.924, 4.029, 4.284, 4.423, 4.528, 4.888, 5.027, 5.132, 5.724, 6.235, 6.385, 6.722, 7.047, 7.129, 7.5, 7.941]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(99, 21, 'Page 14', 'Running no longer felt like a chase.', 14, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_14.mp3', NULL, NULL, '{\"words\": [\"Running\", \"no\", \"longer\", \"felt\", \"like\", \"a\", \"chase.\"], \"start_times\": [0, 0.522, 0.697, 1.033, 1.231, 1.405, 1.474], \"end_times\": [0.453, 0.615, 0.975, 1.196, 1.37, 1.428, 2.136]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(100, 21, 'Page 15', 'It felt like harmony.', 15, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_15.mp3', NULL, NULL, '{\"words\": [\"It\", \"felt\", \"like\", \"harmony.\"], \"start_times\": [0, 0.29, 0.476, 0.662], \"end_times\": [0.244, 0.441, 0.615, 1.3]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(101, 21, 'Page 16', 'And in learning to move with the world rather than against it, Sol discovered a deeper kind of freedom — one that did not depend on speed at all.', 16, 'https://lingola-stories-kids.b-cdn.net/audio/story_21_page_16.mp3', NULL, NULL, '{\"words\": [\"And\", \"in\", \"learning\", \"to\", \"move\", \"with\", \"the\", \"world\", \"rather\", \"than\", \"against\", \"it,\", \"Sol\", \"discovered\", \"a\", \"deeper\", \"kind\", \"of\", \"freedom\", \"u2014\", \"one\", \"that\", \"did\", \"not\", \"depend\", \"on\", \"speed\", \"at\", \"all.\"], \"start_times\": [0, 0.337, 0.464, 0.824, 0.987, 1.289, 1.463, 1.579, 1.927, 2.229, 2.403, 2.844, 3.402, 3.773, 4.342, 4.47, 4.876, 5.166, 5.283, 5.828, 6.385, 6.618, 6.78, 6.954, 7.14, 7.5, 7.663, 7.988, 8.104], \"end_times\": [0.267, 0.406, 0.766, 0.894, 1.254, 1.428, 1.533, 1.858, 2.183, 2.357, 2.775, 3.123, 3.704, 4.284, 4.389, 4.807, 5.108, 5.224, 5.654, 5.875, 6.583, 6.745, 6.908, 7.094, 7.43, 7.593, 7.953, 8.057, 9.334]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(102, 22, 'Page 1', 'By the edge of a quiet seaside town stood an old lighthouse that had guided ships safely for generations. Every night, as the sun slipped beneath the ocean, the lighthouse beam swept across the water in steady circles.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_1.mp3', NULL, NULL, '{\"words\": [\"By\", \"the\", \"edge\", \"of\", \"a\", \"quiet\", \"seaside\", \"town\", \"stood\", \"an\", \"old\", \"lighthouse\", \"that\", \"had\", \"guided\", \"ships\", \"safely\", \"for\", \"generations.\", \"Every\", \"night,\", \"as\", \"the\", \"sun\", \"slipped\", \"beneath\", \"the\", \"ocean,\", \"the\", \"lighthouse\", \"beam\", \"swept\", \"across\", \"the\", \"water\", \"in\", \"steady\", \"circles.\"], \"start_times\": [0, 0.313, 0.453, 0.65, 0.743, 0.824, 1.254, 1.753, 2.148, 2.415, 2.566, 2.914, 3.483, 3.657, 3.808, 4.18, 4.528, 5.016, 5.178, 6.931, 7.245, 7.535, 7.709, 7.825, 8.104, 8.475, 8.777, 8.928, 9.601, 9.764, 10.24, 10.565, 10.937, 11.297, 11.413, 11.784, 11.935, 12.283], \"end_times\": [0.255, 0.383, 0.627, 0.697, 0.766, 1.196, 1.718, 2.078, 2.38, 2.485, 2.833, 3.448, 3.611, 3.75, 4.133, 4.47, 4.957, 5.12, 6.118, 7.187, 7.512, 7.651, 7.779, 8.034, 8.417, 8.731, 8.858, 9.485, 9.706, 10.194, 10.472, 10.89, 11.25, 11.366, 11.714, 11.865, 12.225, 13.05]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(103, 22, 'Page 2', 'But one chilly autumn evening, the light did not turn on.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_2.mp3', NULL, NULL, '{\"words\": [\"But\", \"one\", \"chilly\", \"autumn\", \"evening,\", \"the\", \"light\", \"did\", \"not\", \"turn\", \"on.\"], \"start_times\": [0, 0.302, 0.476, 0.801, 1.091, 1.533, 1.672, 1.881, 2.043, 2.218, 2.461], \"end_times\": [0.244, 0.441, 0.743, 1.045, 1.486, 1.625, 1.846, 1.997, 2.183, 2.403, 2.926]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(104, 22, 'Page 3', 'For the first time in memory, the tower stood dark against the night sky. The townspeople felt uneasy. Without the light, ships could not find the harbor safely.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_3.mp3', NULL, NULL, '{\"words\": [\"For\", \"the\", \"first\", \"time\", \"in\", \"memory,\", \"the\", \"tower\", \"stood\", \"dark\", \"against\", \"the\", \"night\", \"sky.\", \"The\", \"townspeople\", \"felt\", \"uneasy.\", \"Without\", \"the\", \"light,\", \"ships\", \"could\", \"not\", \"find\", \"the\", \"harbor\", \"safely.\"], \"start_times\": [0, 0.29, 0.406, 0.662, 0.882, 0.998, 1.358, 1.486, 1.846, 2.125, 2.403, 2.728, 2.844, 3.077, 4.133, 4.319, 4.923, 5.201, 6.165, 6.525, 6.653, 7.175, 7.488, 7.674, 7.848, 8.081, 8.197, 8.522], \"end_times\": [0.255, 0.36, 0.627, 0.848, 0.94, 1.335, 1.428, 1.788, 2.078, 2.345, 2.694, 2.798, 3.03, 3.622, 4.261, 4.888, 5.143, 5.84, 6.49, 6.594, 7.059, 7.442, 7.639, 7.802, 8.046, 8.15, 8.464, 9.242]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(105, 22, 'Page 4', 'Ten-year-old Leo, who lived in the cottage nearest to the lighthouse, knew something was wrong. His grandfather had been the lighthouse keeper, and Leo knew every corner of the stone tower. He grabbed his flashlight and walked up the rocky path.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_4.mp3', NULL, NULL, '{\"words\": [\"Ten-year-old\", \"Leo,\", \"who\", \"lived\", \"in\", \"the\", \"cottage\", \"nearest\", \"to\", \"the\", \"lighthouse,\", \"knew\", \"something\", \"was\", \"wrong.\", \"His\", \"grandfather\", \"had\", \"been\", \"the\", \"lighthouse\", \"keeper,\", \"and\", \"Leo\", \"knew\", \"every\", \"corner\", \"of\", \"the\", \"stone\", \"tower.\", \"He\", \"grabbed\", \"his\", \"flashlight\", \"and\", \"walked\", \"up\", \"the\", \"rocky\", \"path.\"], \"start_times\": [0, 0.801, 1.312, 1.544, 1.765, 1.858, 1.962, 2.357, 2.659, 2.763, 2.868, 3.646, 3.924, 4.296, 4.458, 5.399, 5.619, 6.269, 6.409, 6.594, 6.699, 7.129, 7.744, 7.976, 8.301, 8.545, 8.928, 9.323, 9.427, 9.543, 9.892, 10.844, 11.018, 11.366, 11.505, 12.098, 12.26, 12.562, 12.701, 12.817, 13.142], \"end_times\": [0.743, 1.289, 1.474, 1.741, 1.823, 1.927, 2.31, 2.624, 2.705, 2.833, 3.471, 3.855, 4.249, 4.412, 4.888, 5.561, 6.211, 6.374, 6.56, 6.664, 7.094, 7.593, 7.906, 8.243, 8.464, 8.858, 9.265, 9.381, 9.497, 9.845, 10.403, 10.96, 11.331, 11.459, 12.051, 12.19, 12.527, 12.655, 12.771, 13.084, 14.303]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(106, 22, 'Page 5', 'Inside, the air smelled of salt and old oil. Leo climbed the spiral stairs, his flashlight beam bouncing off the curved walls. When he reached the lantern room at the top, the massive glass lens sat perfectly intact, but the powerful lamp inside was cold.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_5.mp3', NULL, NULL, '{\"words\": [\"Inside,\", \"the\", \"air\", \"smelled\", \"of\", \"salt\", \"and\", \"old\", \"oil.\", \"Leo\", \"climbed\", \"the\", \"spiral\", \"stairs,\", \"his\", \"flashlight\", \"beam\", \"bouncing\", \"off\", \"the\", \"curved\", \"walls.\", \"When\", \"he\", \"reached\", \"the\", \"lantern\", \"room\", \"at\", \"the\", \"top,\", \"the\", \"massive\", \"glass\", \"lens\", \"sat\", \"perfectly\", \"intact,\", \"but\", \"the\", \"powerful\", \"lamp\", \"inside\", \"was\", \"cold.\"], \"start_times\": [0, 0.743, 0.894, 1.126, 1.451, 1.567, 2.02, 2.241, 2.519, 3.518, 3.831, 4.156, 4.261, 4.667, 5.503, 5.677, 6.223, 6.49, 6.896, 7.059, 7.163, 7.5, 8.498, 8.707, 8.847, 9.125, 9.253, 9.648, 9.845, 9.95, 10.054, 10.704, 10.867, 11.262, 11.656, 12.028, 12.318, 12.852, 13.735, 13.909, 14.025, 14.501, 14.779, 15.244, 15.43], \"end_times\": [0.72, 0.824, 1.057, 1.416, 1.498, 1.962, 2.159, 2.45, 3.077, 3.773, 4.133, 4.226, 4.609, 5.294, 5.631, 6.188, 6.432, 6.838, 7.012, 7.129, 7.454, 8.057, 8.661, 8.766, 9.102, 9.195, 9.601, 9.799, 9.915, 10.019, 10.53, 10.809, 11.227, 11.575, 11.981, 12.249, 12.783, 13.526, 13.886, 13.978, 14.431, 14.721, 15.209, 15.36, 16.022]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(107, 22, 'Page 6', 'He inspected the control panel. The switch was perfectly fine.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_6.mp3', NULL, NULL, '{\"words\": [\"He\", \"inspected\", \"the\", \"control\", \"panel.\", \"The\", \"switch\", \"was\", \"perfectly\", \"fine.\"], \"start_times\": [0, 0.302, 0.789, 0.894, 1.254, 1.753, 1.916, 2.206, 2.38, 2.844], \"end_times\": [0.255, 0.755, 0.859, 1.196, 1.625, 1.869, 2.171, 2.31, 2.786, 3.437]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(108, 22, 'Page 7', 'He looked closer at the base of the lamp. Something was missing — a small, brass connecting gear that kept the mechanism connected to the power source.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_7.mp3', NULL, NULL, '{\"words\": [\"He\", \"looked\", \"closer\", \"at\", \"the\", \"base\", \"of\", \"the\", \"lamp.\", \"Something\", \"was\", \"missing\", \"u2014\", \"a\", \"small,\", \"brass\", \"connecting\", \"gear\", \"that\", \"kept\", \"the\", \"mechanism\", \"connected\", \"to\", \"the\", \"power\", \"source.\"], \"start_times\": [0, 0.279, 0.522, 0.906, 0.998, 1.103, 1.347, 1.451, 1.579, 2.438, 2.81, 2.972, 3.483, 3.715, 3.831, 4.191, 4.574, 5.05, 5.271, 5.445, 5.666, 5.782, 6.351, 6.792, 6.908, 7.024, 7.384], \"end_times\": [0.232, 0.476, 0.859, 0.964, 1.068, 1.324, 1.405, 1.521, 1.997, 2.763, 2.914, 3.309, 3.541, 3.762, 4.168, 4.516, 5.004, 5.224, 5.399, 5.631, 5.735, 6.281, 6.745, 6.85, 6.978, 7.314, 7.988]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(109, 22, 'Page 8', 'Leo knelt down, searching the floor. There, tucked under a small metal grate, he found it. It hadn\'t fallen on its own; someone or something had moved it. Beside the gear was a strange, tiny footprint. It wasn\'t human. It looked like a small paw with long, delicate claws.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_8.mp3', NULL, NULL, '{\"words\": [\"Leo\", \"knelt\", \"down,\", \"searching\", \"the\", \"floor.\", \"There,\", \"tucked\", \"under\", \"a\", \"small\", \"metal\", \"grate,\", \"he\", \"found\", \"it.\", \"It\", \"hadn\'t\", \"fallen\", \"on\", \"its\", \"own;\", \"someone\", \"or\", \"something\", \"had\", \"moved\", \"it.\", \"Beside\", \"the\", \"gear\", \"was\", \"a\", \"strange,\", \"tiny\", \"footprint.\", \"It\", \"wasn\'t\", \"human.\", \"It\", \"looked\", \"like\", \"a\", \"small\", \"paw\", \"with\", \"long,\", \"delicate\", \"claws.\"], \"start_times\": [0, 0.453, 0.697, 1.126, 1.509, 1.625, 2.775, 3.32, 3.692, 3.936, 4.017, 4.365, 4.656, 5.062, 5.224, 5.538, 6.536, 6.734, 7.059, 7.442, 7.57, 7.755, 8.394, 8.928, 9.114, 9.799, 10.008, 10.333, 11.807, 12.249, 12.365, 12.655, 12.829, 12.91, 13.41, 13.793, 15.116, 15.29, 15.592, 16.684, 16.846, 17.09, 17.264, 17.357, 17.728, 18.088, 18.309, 18.68, 19.145], \"end_times\": [0.406, 0.65, 1.057, 1.463, 1.579, 2.171, 3.239, 3.634, 3.878, 3.959, 4.307, 4.598, 5.004, 5.155, 5.48, 5.84, 6.676, 7.001, 7.396, 7.523, 7.697, 8.115, 8.882, 9.044, 9.683, 9.95, 10.275, 10.693, 12.225, 12.318, 12.585, 12.783, 12.852, 13.386, 13.735, 14.512, 15.244, 15.557, 16.173, 16.811, 17.055, 17.229, 17.287, 17.659, 18.019, 18.228, 18.634, 19.11, 19.876]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(110, 22, 'Page 9', 'He remembered the family of raccoons that lived near the cliffs. They loved shiny objects.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_9.mp3', NULL, NULL, '{\"words\": [\"He\", \"remembered\", \"the\", \"family\", \"of\", \"raccoons\", \"that\", \"lived\", \"near\", \"the\", \"cliffs.\", \"They\", \"loved\", \"shiny\", \"objects.\"], \"start_times\": [0, 0.302, 0.743, 0.871, 1.3, 1.451, 2.055, 2.229, 2.473, 2.647, 2.763, 3.471, 3.727, 4.04, 4.458], \"end_times\": [0.232, 0.708, 0.813, 1.231, 1.37, 2.009, 2.183, 2.438, 2.601, 2.717, 3.297, 3.657, 3.982, 4.377, 5.294]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(111, 22, 'Page 10', 'Following a trail of subtle scratches on the floor, Leo made his way back down to the ground. Outside, he traced the tiny footprints in the damp soil. They led directly to an old hollow log near the cliff edge.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_10.mp3', NULL, NULL, '{\"words\": [\"Following\", \"a\", \"trail\", \"of\", \"subtle\", \"scratches\", \"on\", \"the\", \"floor,\", \"Leo\", \"made\", \"his\", \"way\", \"back\", \"down\", \"to\", \"the\", \"ground.\", \"Outside,\", \"he\", \"traced\", \"the\", \"tiny\", \"footprints\", \"in\", \"the\", \"damp\", \"soil.\", \"They\", \"led\", \"directly\", \"to\", \"an\", \"old\", \"hollow\", \"log\", \"near\", \"the\", \"cliff\", \"edge.\"], \"start_times\": [0, 0.58, 0.65, 0.975, 1.091, 1.416, 1.927, 2.043, 2.148, 2.879, 3.204, 3.413, 3.576, 3.762, 3.994, 4.214, 4.342, 4.447, 5.666, 6.606, 6.745, 7.047, 7.152, 7.465, 7.976, 8.081, 8.185, 8.475, 9.323, 9.52, 9.718, 10.205, 10.368, 10.495, 10.762, 11.111, 11.447, 11.645, 11.749, 12.04], \"end_times\": [0.534, 0.604, 0.917, 1.033, 1.382, 1.881, 2.009, 2.113, 2.67, 3.146, 3.379, 3.518, 3.704, 3.936, 4.168, 4.272, 4.412, 4.969, 6.397, 6.687, 7.024, 7.117, 7.419, 7.93, 8.034, 8.15, 8.406, 8.998, 9.474, 9.671, 10.147, 10.286, 10.426, 10.704, 11.041, 11.378, 11.598, 11.714, 11.97, 12.585]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(112, 22, 'Page 11', 'He crouched and peered inside. In the reflection of his flashlight, a pair of bright eyes blinked back. The raccoon had built a small nest, and right in the center sat the shiny brass gear.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_11.mp3', NULL, NULL, '{\"words\": [\"He\", \"crouched\", \"and\", \"peered\", \"inside.\", \"In\", \"the\", \"reflection\", \"of\", \"his\", \"flashlight,\", \"a\", \"pair\", \"of\", \"bright\", \"eyes\", \"blinked\", \"back.\", \"The\", \"raccoon\", \"had\", \"built\", \"a\", \"small\", \"nest,\", \"and\", \"right\", \"in\", \"the\", \"center\", \"sat\", \"the\", \"shiny\", \"brass\", \"gear.\"], \"start_times\": [0, 0.325, 0.778, 0.906, 1.231, 2.159, 2.31, 2.426, 2.914, 3.007, 3.135, 3.808, 3.947, 4.261, 4.389, 4.725, 5.039, 5.352, 6.525, 6.711, 7.221, 7.372, 7.639, 7.709, 8.034, 8.905, 9.102, 9.323, 9.416, 9.532, 9.973, 10.205, 10.321, 10.704, 11.041], \"end_times\": [0.267, 0.743, 0.848, 1.196, 1.881, 2.276, 2.38, 2.879, 2.961, 3.088, 3.773, 3.866, 4.191, 4.319, 4.656, 4.992, 5.306, 5.828, 6.641, 7.163, 7.326, 7.593, 7.663, 7.964, 8.58, 9.044, 9.288, 9.381, 9.485, 9.892, 10.17, 10.275, 10.658, 10.971, 11.61]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(113, 22, 'Page 12', 'Leo knew he shouldn\'t startle the animal. He reached into his pocket and pulled out a small piece of apple he’d saved from dinner. He placed it near the opening and waited. The raccoon crept forward, grabbed the apple, and scampered away.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_12.mp3', NULL, NULL, '{\"words\": [\"Leo\", \"knew\", \"he\", \"shouldn\'t\", \"startle\", \"the\", \"animal.\", \"He\", \"reached\", \"into\", \"his\", \"pocket\", \"and\", \"pulled\", \"out\", \"a\", \"small\", \"piece\", \"of\", \"apple\", \"heu2019d\", \"saved\", \"from\", \"dinner.\", \"He\", \"placed\", \"it\", \"near\", \"the\", \"opening\", \"and\", \"waited.\", \"The\", \"raccoon\", \"crept\", \"forward,\", \"grabbed\", \"the\", \"apple,\", \"and\", \"scampered\", \"away.\"], \"start_times\": [0, 0.499, 0.743, 0.848, 1.173, 1.521, 1.66, 2.902, 3.088, 3.413, 3.657, 3.808, 4.226, 4.377, 4.621, 4.76, 4.841, 5.143, 5.41, 5.526, 5.828, 6.037, 6.339, 6.536, 7.523, 7.697, 8.022, 8.115, 8.29, 8.429, 8.835, 8.975, 10.286, 10.472, 10.913, 11.227, 12.074, 12.481, 12.62, 12.968, 13.142, 13.607], \"end_times\": [0.441, 0.673, 0.801, 1.138, 1.498, 1.602, 2.206, 3.007, 3.367, 3.587, 3.75, 4.168, 4.319, 4.586, 4.725, 4.783, 5.097, 5.375, 5.468, 5.793, 6.002, 6.304, 6.478, 7.012, 7.639, 7.988, 8.081, 8.243, 8.359, 8.777, 8.916, 9.474, 10.403, 10.844, 11.169, 11.865, 12.434, 12.55, 12.945, 13.084, 13.572, 14.211]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(114, 22, 'Page 13', 'Leo carefully reached in and retrieved the gear.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_13.mp3', NULL, NULL, '{\"words\": [\"Leo\", \"carefully\", \"reached\", \"in\", \"and\", \"retrieved\", \"the\", \"gear.\"], \"start_times\": [0, 0.453, 0.882, 1.196, 1.335, 1.474, 1.869, 1.974], \"end_times\": [0.395, 0.824, 1.138, 1.277, 1.416, 1.846, 1.939, 2.461]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(115, 22, 'Page 14', 'He ran back up the tower, slotted the gear into place, and flipped the switch. A brilliant beam of light shot out across the dark ocean.', 14, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_14.mp3', NULL, NULL, '{\"words\": [\"He\", \"ran\", \"back\", \"up\", \"the\", \"tower,\", \"slotted\", \"the\", \"gear\", \"into\", \"place,\", \"and\", \"flipped\", \"the\", \"switch.\", \"A\", \"brilliant\", \"beam\", \"of\", \"light\", \"shot\", \"out\", \"across\", \"the\", \"dark\", \"ocean.\"], \"start_times\": [0, 0.325, 0.592, 0.848, 0.998, 1.115, 1.776, 2.218, 2.322, 2.531, 2.728, 3.053, 3.204, 3.564, 3.68, 4.783, 4.946, 5.422, 5.689, 5.84, 6.165, 6.49, 6.629, 6.978, 7.082, 7.372], \"end_times\": [0.244, 0.522, 0.789, 0.94, 1.068, 1.602, 2.194, 2.287, 2.485, 2.67, 3.03, 3.146, 3.506, 3.634, 4.18, 4.865, 5.364, 5.631, 5.747, 6.095, 6.444, 6.594, 6.931, 7.047, 7.303, 7.988]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(116, 22, 'Page 15', 'The town let out a collective breath.', 15, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_15.mp3', NULL, NULL, '{\"words\": [\"The\", \"town\", \"let\", \"out\", \"a\", \"collective\", \"breath.\"], \"start_times\": [0, 0.279, 0.546, 0.708, 0.848, 0.929, 1.393], \"end_times\": [0.232, 0.499, 0.673, 0.813, 0.882, 1.37, 2.043]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(117, 22, 'Page 16', 'The mystery wasn\'t a crime; it was just a curious neighbor.', 16, 'https://lingola-stories-kids.b-cdn.net/audio/story_22_page_16.mp3', NULL, NULL, '{\"words\": [\"The\", \"mystery\", \"wasn\'t\", \"a\", \"crime;\", \"it\", \"was\", \"just\", \"a\", \"curious\", \"neighbor.\"], \"start_times\": [0, 0.302, 0.662, 0.917, 0.998, 1.358, 1.451, 1.579, 1.776, 1.858, 2.334], \"end_times\": [0.244, 0.615, 0.894, 0.94, 1.335, 1.416, 1.533, 1.741, 1.8, 2.287, 2.972]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(118, 23, 'Page 1', 'In the center of the town stood a library older than any building around it. Its wooden floors creaked softly, and tall shelves reached nearly to the ceiling.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"the\", \"center\", \"of\", \"the\", \"town\", \"stood\", \"a\", \"library\", \"older\", \"than\", \"any\", \"building\", \"around\", \"it.\", \"Its\", \"wooden\", \"floors\", \"creaked\", \"softly,\", \"and\", \"tall\", \"shelves\", \"reached\", \"nearly\", \"to\", \"the\", \"ceiling.\"], \"start_times\": [0, 0.279, 0.406, 0.731, 0.824, 0.94, 1.3, 1.544, 1.625, 2.218, 2.519, 2.717, 2.961, 3.309, 3.646, 4.261, 4.481, 4.807, 5.224, 5.584, 6.444, 6.653, 6.931, 7.372, 7.732, 8.092, 8.22, 8.324], \"end_times\": [0.244, 0.348, 0.685, 0.789, 0.894, 1.242, 1.509, 1.567, 2.148, 2.473, 2.647, 2.902, 3.262, 3.587, 3.878, 4.435, 4.748, 5.155, 5.538, 6.2, 6.594, 6.861, 7.303, 7.651, 8.046, 8.162, 8.29, 8.963]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(119, 23, 'Page 2', 'People went there for peace and quiet. But recently, visitors had begun hearing whispers — soft, echoing sounds that seemed to come from the walls whenever the room was empty.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_2.mp3', NULL, NULL, '{\"words\": [\"People\", \"went\", \"there\", \"for\", \"peace\", \"and\", \"quiet.\", \"But\", \"recently,\", \"visitors\", \"had\", \"begun\", \"hearing\", \"whispers\", \"u2014\", \"soft,\", \"echoing\", \"sounds\", \"that\", \"seemed\", \"to\", \"come\", \"from\", \"the\", \"walls\", \"whenever\", \"the\", \"room\", \"was\", \"empty.\"], \"start_times\": [0, 0.476, 0.662, 0.848, 0.998, 1.265, 1.393, 2.612, 2.821, 3.309, 3.738, 3.889, 4.238, 4.574, 5.224, 5.55, 6.153, 6.664, 7.129, 7.303, 7.558, 7.663, 7.872, 8.046, 8.162, 8.533, 8.87, 8.986, 9.23, 9.404], \"end_times\": [0.441, 0.627, 0.813, 0.94, 1.231, 1.335, 2.009, 2.775, 3.274, 3.704, 3.843, 4.156, 4.516, 5.108, 5.271, 6.072, 6.571, 7.082, 7.256, 7.535, 7.605, 7.837, 7.999, 8.115, 8.499, 8.824, 8.94, 9.183, 9.346, 10.728]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(120, 23, 'Page 3', 'Some said the library was haunted by old authors. Others stopped visiting altogether.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_3.mp3', NULL, NULL, '{\"words\": [\"Some\", \"said\", \"the\", \"library\", \"was\", \"haunted\", \"by\", \"old\", \"authors.\", \"Others\", \"stopped\", \"visiting\", \"altogether.\"], \"start_times\": [0, 0.406, 0.604, 0.72, 1.091, 1.254, 1.637, 1.811, 2.032, 2.844, 3.193, 3.529, 3.901], \"end_times\": [0.372, 0.569, 0.673, 1.057, 1.184, 1.591, 1.741, 1.974, 2.635, 3.158, 3.483, 3.855, 4.737]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(121, 23, 'Page 4', 'Twelve-year-old Maya loved mysteries. She spent her afternoons reading detective novels and taking notes in a small green notebook. The whispering library was exactly her kind of case.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_4.mp3', NULL, NULL, '{\"words\": [\"Twelve-year-old\", \"Maya\", \"loved\", \"mysteries.\", \"She\", \"spent\", \"her\", \"afternoons\", \"reading\", \"detective\", \"novels\", \"and\", \"taking\", \"notes\", \"in\", \"a\", \"small\", \"green\", \"notebook.\", \"The\", \"whispering\", \"library\", \"was\", \"exactly\", \"her\", \"kind\", \"of\", \"case.\"], \"start_times\": [0, 0.778, 1.207, 1.509, 2.543, 2.728, 2.995, 3.135, 3.692, 3.959, 4.435, 4.783, 4.911, 5.283, 5.55, 5.654, 5.735, 6.072, 6.362, 7.396, 7.558, 8.057, 8.626, 8.8, 9.346, 9.532, 9.799, 9.915], \"end_times\": [0.708, 1.138, 1.44, 2.299, 2.67, 2.961, 3.077, 3.646, 3.913, 4.4, 4.748, 4.865, 5.213, 5.515, 5.608, 5.677, 6.014, 6.304, 6.954, 7.512, 7.988, 8.568, 8.742, 9.276, 9.462, 9.752, 9.857, 10.588]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11');
INSERT INTO `story_sections` (`id`, `story_id`, `title`, `content`, `page_number`, `elevenlabs_audio_url`, `elevenlabs_voice_id`, `audio_duration`, `word_timestamps`, `created_at`, `updated_at`) VALUES
(122, 23, 'Page 5', 'She stayed late one evening, hiding behind a massive oak desk. When the librarian went to the back room, the main hall grew silent.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_5.mp3', NULL, NULL, '{\"words\": [\"She\", \"stayed\", \"late\", \"one\", \"evening,\", \"hiding\", \"behind\", \"a\", \"massive\", \"oak\", \"desk.\", \"When\", \"the\", \"librarian\", \"went\", \"to\", \"the\", \"back\", \"room,\", \"the\", \"main\", \"hall\", \"grew\", \"silent.\"], \"start_times\": [0, 0.325, 0.662, 0.906, 1.08, 1.765, 2.136, 2.45, 2.543, 2.961, 3.216, 4.458, 4.667, 4.783, 5.364, 5.55, 5.642, 5.759, 6.049, 6.444, 6.606, 6.85, 7.082, 7.314], \"end_times\": [0.267, 0.604, 0.859, 1.045, 1.614, 2.078, 2.403, 2.485, 2.914, 3.135, 3.762, 4.632, 4.737, 5.317, 5.515, 5.596, 5.712, 5.968, 6.374, 6.548, 6.78, 7.036, 7.256, 8.081]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(123, 23, 'Page 6', 'Then, it began.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_6.mp3', NULL, NULL, '{\"words\": [\"Then,\", \"it\", \"began.\"], \"start_times\": [0, 0.406, 0.522], \"end_times\": [0.383, 0.476, 1.207]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(124, 23, 'Page 7', 'A soft, whistling whisper drifted through the aisles. It didn\'t sound like voices. It sounded like sighs.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_7.mp3', NULL, NULL, '{\"words\": [\"A\", \"soft,\", \"whistling\", \"whisper\", \"drifted\", \"through\", \"the\", \"aisles.\", \"It\", \"didn\'t\", \"sound\", \"like\", \"voices.\", \"It\", \"sounded\", \"like\", \"sighs.\"], \"start_times\": [0, 0.29, 0.813, 1.335, 1.73, 2.113, 2.334, 2.461, 3.309, 3.46, 3.715, 3.994, 4.18, 5.016, 5.201, 5.573, 5.782], \"end_times\": [0.197, 0.766, 1.289, 1.672, 2.078, 2.31, 2.403, 3.03, 3.425, 3.669, 3.936, 4.133, 4.807, 5.143, 5.526, 5.735, 6.548]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(125, 23, 'Page 8', 'Maya crept quietly down the central aisle. She stopped and listened. The sound was strongest near the older history section. She closely examined the massive wooden shelves. Nothing appeared out of the ordinary. She checked behind the books, looking for a hidden speaker or perhaps a draft of wind.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_8.mp3', NULL, NULL, '{\"words\": [\"Maya\", \"crept\", \"quietly\", \"down\", \"the\", \"central\", \"aisle.\", \"She\", \"stopped\", \"and\", \"listened.\", \"The\", \"sound\", \"was\", \"strongest\", \"near\", \"the\", \"older\", \"history\", \"section.\", \"She\", \"closely\", \"examined\", \"the\", \"massive\", \"wooden\", \"shelves.\", \"Nothing\", \"appeared\", \"out\", \"of\", \"the\", \"ordinary.\", \"She\", \"checked\", \"behind\", \"the\", \"books,\", \"looking\", \"for\", \"a\", \"hidden\", \"speaker\", \"or\", \"perhaps\", \"a\", \"draft\", \"of\", \"wind.\"], \"start_times\": [0, 0.569, 0.906, 1.428, 1.637, 1.753, 2.148, 3.17, 3.379, 3.82, 3.947, 5.016, 5.213, 5.584, 5.747, 6.385, 6.618, 6.757, 7.07, 7.465, 8.696, 8.882, 9.346, 9.845, 9.973, 10.356, 10.67, 11.564, 11.935, 12.33, 12.457, 12.562, 12.69, 14.002, 14.199, 14.489, 14.791, 14.896, 15.348, 15.685, 15.848, 15.929, 16.242, 16.742, 16.939, 17.31, 17.38, 17.717, 17.833], \"end_times\": [0.499, 0.848, 1.37, 1.602, 1.707, 2.078, 2.659, 3.309, 3.785, 3.889, 4.505, 5.143, 5.526, 5.689, 6.293, 6.571, 6.687, 7.012, 7.407, 8.092, 8.824, 9.288, 9.81, 9.915, 10.333, 10.612, 11.285, 11.889, 12.307, 12.434, 12.516, 12.632, 13.398, 14.129, 14.443, 14.745, 14.861, 15.29, 15.627, 15.79, 15.871, 16.173, 16.649, 16.869, 17.276, 17.334, 17.67, 17.763, 18.39]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(126, 23, 'Page 9', 'As she traced her hand along the back panel of a shelf, she felt a slight breeze. She pushed a heavy encyclopedia aside and saw a small gap where the wood had warped.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_9.mp3', NULL, NULL, '{\"words\": [\"As\", \"she\", \"traced\", \"her\", \"hand\", \"along\", \"the\", \"back\", \"panel\", \"of\", \"a\", \"shelf,\", \"she\", \"felt\", \"a\", \"slight\", \"breeze.\", \"She\", \"pushed\", \"a\", \"heavy\", \"encyclopedia\", \"aside\", \"and\", \"saw\", \"a\", \"small\", \"gap\", \"where\", \"the\", \"wood\", \"had\", \"warped.\"], \"start_times\": [0, 0.279, 0.406, 0.708, 0.824, 1.057, 1.289, 1.393, 1.637, 1.962, 2.055, 2.125, 2.659, 2.844, 3.077, 3.158, 3.483, 4.505, 4.69, 4.981, 5.062, 5.294, 6.049, 6.478, 6.594, 6.792, 6.861, 7.21, 7.512, 7.686, 7.79, 7.988, 8.115], \"end_times\": [0.244, 0.36, 0.673, 0.778, 0.998, 1.254, 1.358, 1.567, 1.916, 2.009, 2.078, 2.543, 2.786, 3.042, 3.1, 3.437, 3.994, 4.632, 4.946, 5.004, 5.248, 6.002, 6.444, 6.548, 6.745, 6.815, 7.14, 7.454, 7.651, 7.755, 7.953, 8.069, 8.684]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(127, 23, 'Page 10', 'Beyond the gap was the library\'s old ventilation shaft, built into the wall.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_10.mp3', NULL, NULL, '{\"words\": [\"Beyond\", \"the\", \"gap\", \"was\", \"the\", \"library\'s\", \"old\", \"ventilation\", \"shaft,\", \"built\", \"into\", \"the\", \"wall.\"], \"start_times\": [0, 0.43, 0.546, 0.824, 0.987, 1.103, 1.579, 1.811, 2.473, 2.914, 3.204, 3.437, 3.553], \"end_times\": [0.383, 0.499, 0.778, 0.929, 1.057, 1.521, 1.753, 2.415, 2.879, 3.158, 3.367, 3.506, 4.133]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(128, 23, 'Page 11', 'Maya climbed onto a small stool and peered closer. Trapped inside the narrow shaft, just out of reach, was a small, frightened gray pigeon. Every time it fluttered its wings or shifted, the sound echoed through the metal pipe, turning into a strange, ghostly whisper.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_11.mp3', NULL, NULL, '{\"words\": [\"Maya\", \"climbed\", \"onto\", \"a\", \"small\", \"stool\", \"and\", \"peered\", \"closer.\", \"Trapped\", \"inside\", \"the\", \"narrow\", \"shaft,\", \"just\", \"out\", \"of\", \"reach,\", \"was\", \"a\", \"small,\", \"frightened\", \"gray\", \"pigeon.\", \"Every\", \"time\", \"it\", \"fluttered\", \"its\", \"wings\", \"or\", \"shifted,\", \"the\", \"sound\", \"echoed\", \"through\", \"the\", \"metal\", \"pipe,\", \"turning\", \"into\", \"a\", \"strange,\", \"ghostly\", \"whisper.\"], \"start_times\": [0, 0.488, 0.836, 1.045, 1.126, 1.451, 1.823, 1.95, 2.241, 3.309, 3.692, 4.04, 4.156, 4.458, 4.981, 5.259, 5.422, 5.55, 6.142, 6.339, 6.432, 6.838, 7.338, 7.616, 8.649, 8.928, 9.16, 9.265, 9.636, 9.81, 10.17, 10.31, 11.204, 11.366, 11.714, 12.098, 12.341, 12.446, 12.713, 13.351, 13.723, 13.955, 14.036, 14.71, 15.209], \"end_times\": [0.43, 0.801, 0.987, 1.08, 1.393, 1.765, 1.892, 2.194, 2.868, 3.657, 4.005, 4.11, 4.4, 4.923, 5.213, 5.375, 5.48, 6.026, 6.293, 6.362, 6.803, 7.268, 7.546, 8.139, 8.882, 9.125, 9.218, 9.601, 9.764, 10.124, 10.252, 10.96, 11.308, 11.633, 12.063, 12.318, 12.411, 12.666, 13.177, 13.677, 13.874, 13.978, 14.617, 15.151, 15.836]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(129, 23, 'Page 12', 'Maya ran to get the librarian. Together, they carefully opened the grate lower down the wall and guided the pigeon to safety.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_12.mp3', NULL, NULL, '{\"words\": [\"Maya\", \"ran\", \"to\", \"get\", \"the\", \"librarian.\", \"Together,\", \"they\", \"carefully\", \"opened\", \"the\", \"grate\", \"lower\", \"down\", \"the\", \"wall\", \"and\", \"guided\", \"the\", \"pigeon\", \"to\", \"safety.\"], \"start_times\": [0, 0.499, 0.72, 0.813, 0.952, 1.068, 2.067, 2.74, 2.937, 3.425, 3.785, 3.901, 4.226, 4.516, 4.702, 4.818, 5.166, 5.329, 5.677, 5.782, 6.153, 6.293], \"end_times\": [0.441, 0.673, 0.766, 0.917, 1.022, 1.823, 2.659, 2.891, 3.355, 3.727, 3.855, 4.18, 4.458, 4.667, 4.772, 5.085, 5.271, 5.642, 5.747, 6.095, 6.223, 7.012]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(130, 23, 'Page 13', 'The library returned to its peaceful silence. The ghosts were gone, replaced by logic and a small green notebook.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_23_page_13.mp3', NULL, NULL, '{\"words\": [\"The\", \"library\", \"returned\", \"to\", \"its\", \"peaceful\", \"silence.\", \"The\", \"ghosts\", \"were\", \"gone,\", \"replaced\", \"by\", \"logic\", \"and\", \"a\", \"small\", \"green\", \"notebook.\"], \"start_times\": [0, 0.302, 0.801, 1.196, 1.324, 1.486, 1.892, 2.961, 3.123, 3.402, 3.564, 4.203, 4.598, 4.772, 5.213, 5.352, 5.422, 5.7, 5.956], \"end_times\": [0.232, 0.731, 1.173, 1.254, 1.428, 1.834, 2.519, 3.077, 3.367, 3.529, 4.029, 4.563, 4.69, 5.155, 5.306, 5.375, 5.654, 5.909, 6.641]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(131, 24, 'Page 1', 'In a quiet neighborhood lined with maple trees, something strange began appearing each morning. Footprints.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"a\", \"quiet\", \"neighborhood\", \"lined\", \"with\", \"maple\", \"trees,\", \"something\", \"strange\", \"began\", \"appearing\", \"each\", \"morning.\", \"Footprints.\"], \"start_times\": [0, 0.279, 0.36, 0.685, 1.161, 1.405, 1.556, 1.834, 2.543, 2.937, 3.379, 3.68, 4.11, 4.319, 5.224], \"end_times\": [0.244, 0.302, 0.65, 1.103, 1.382, 1.509, 1.811, 2.299, 2.868, 3.332, 3.634, 4.063, 4.261, 4.783, 6.316]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(132, 24, 'Page 2', 'They started at the edge of Mr. Henderson’s perfect lawn and tracked muddy paths directly to his front door, only to disappear completely on the small porch. They weren\'t muddy boots giving away a clumsy thief; they were small, perfectly round dots. Like someone walking on stilts.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_2.mp3', NULL, NULL, '{\"words\": [\"They\", \"started\", \"at\", \"the\", \"edge\", \"of\", \"Mr.\", \"Hendersonu2019s\", \"perfect\", \"lawn\", \"and\", \"tracked\", \"muddy\", \"paths\", \"directly\", \"to\", \"his\", \"front\", \"door,\", \"only\", \"to\", \"disappear\", \"completely\", \"on\", \"the\", \"small\", \"porch.\", \"They\", \"weren\'t\", \"muddy\", \"boots\", \"giving\", \"away\", \"a\", \"clumsy\", \"thief;\", \"they\", \"were\", \"small,\", \"perfectly\", \"round\", \"dots.\", \"Like\", \"someone\", \"walking\", \"on\", \"stilts.\"], \"start_times\": [0, 0.325, 0.731, 0.836, 0.987, 1.254, 1.37, 1.695, 2.264, 2.728, 3.216, 3.448, 3.843, 4.133, 4.621, 5.108, 5.248, 5.399, 5.654, 6.362, 6.664, 6.792, 7.314, 7.895, 8.011, 8.115, 8.429, 9.671, 9.868, 10.136, 10.426, 10.762, 11.041, 11.285, 11.378, 11.865, 12.701, 12.875, 13.05, 13.7, 14.28, 14.64, 15.639, 15.882, 16.266, 16.637, 16.811], \"end_times\": [0.279, 0.685, 0.801, 0.906, 1.219, 1.312, 1.672, 2.206, 2.659, 3.1, 3.39, 3.773, 4.075, 4.54, 5.062, 5.178, 5.341, 5.619, 6.153, 6.606, 6.722, 7.245, 7.837, 7.964, 8.081, 8.359, 9.067, 9.834, 10.089, 10.368, 10.704, 11.006, 11.238, 11.32, 11.784, 12.376, 12.841, 13.003, 13.584, 14.211, 14.571, 15.256, 15.848, 16.231, 16.579, 16.73, 18.112]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(133, 24, 'Page 3', 'Mr. Henderson was frustrated. \"Someone is playing a prank,\" he declared.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_3.mp3', NULL, NULL, '{\"words\": [\"Mr.\", \"Henderson\", \"was\", \"frustrated.\", \"\"Someone\", \"is\", \"playing\", \"a\", \"prank,\"\", \"he\", \"declared.\"], \"start_times\": [0, 0.476, 0.894, 1.045, 1.985, 2.531, 2.647, 2.949, 3.007, 3.541, 3.669], \"end_times\": [0.453, 0.848, 0.987, 1.776, 2.496, 2.601, 2.902, 2.972, 3.448, 3.611, 4.365]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(134, 24, 'Page 4', 'Seven-year-old Sam, who watched the neighborhood carefully from his bedroom window, decided to investigate. He set his alarm for midnight, determined to catch the culprit.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_4.mp3', NULL, NULL, '{\"words\": [\"Seven-year-old\", \"Sam,\", \"who\", \"watched\", \"the\", \"neighborhood\", \"carefully\", \"from\", \"his\", \"bedroom\", \"window,\", \"decided\", \"to\", \"investigate.\", \"He\", \"set\", \"his\", \"alarm\", \"for\", \"midnight,\", \"determined\", \"to\", \"catch\", \"the\", \"culprit.\"], \"start_times\": [0, 0.778, 1.184, 1.382, 1.683, 1.788, 2.206, 2.659, 2.821, 2.937, 3.251, 3.889, 4.354, 4.493, 5.991, 6.165, 6.362, 6.49, 6.78, 6.954, 7.686, 8.185, 8.278, 8.557, 8.673], \"end_times\": [0.72, 1.161, 1.324, 1.649, 1.753, 2.159, 2.612, 2.786, 2.891, 3.216, 3.738, 4.319, 4.412, 5.294, 6.107, 6.327, 6.444, 6.722, 6.885, 7.477, 8.162, 8.231, 8.51, 8.626, 9.381]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(135, 24, 'Page 5', 'When the clock struck twelve, Sam peered into the darkness. The streetlamps cast long shadows, but nothing moved. He waited. A light rain began to fall.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_5.mp3', NULL, NULL, '{\"words\": [\"When\", \"the\", \"clock\", \"struck\", \"twelve,\", \"Sam\", \"peered\", \"into\", \"the\", \"darkness.\", \"The\", \"streetlamps\", \"cast\", \"long\", \"shadows,\", \"but\", \"nothing\", \"moved.\", \"He\", \"waited.\", \"A\", \"light\", \"rain\", \"began\", \"to\", \"fall.\"], \"start_times\": [0, 0.29, 0.395, 0.72, 1.01, 1.707, 2.09, 2.368, 2.554, 2.659, 3.913, 4.087, 4.714, 5.12, 5.457, 6.304, 6.513, 6.861, 7.732, 7.93, 8.719, 8.882, 9.137, 9.381, 9.694, 9.822], \"end_times\": [0.255, 0.36, 0.662, 0.952, 1.591, 2.02, 2.334, 2.496, 2.624, 3.402, 4.029, 4.667, 5.039, 5.387, 6.188, 6.467, 6.792, 7.349, 7.86, 8.475, 8.8, 9.079, 9.323, 9.636, 9.741, 10.403]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(136, 24, 'Page 6', 'Suddenly, a small figure scurried across the street.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_6.mp3', NULL, NULL, '{\"words\": [\"Suddenly,\", \"a\", \"small\", \"figure\", \"scurried\", \"across\", \"the\", \"street.\"], \"start_times\": [0, 0.58, 0.662, 0.987, 1.347, 1.718, 2.067, 2.171], \"end_times\": [0.557, 0.604, 0.917, 1.3, 1.695, 2.032, 2.136, 2.786]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(137, 24, 'Page 7', 'Sam pressed his nose against the glass. It wasn\'t a person on stilts. It wasn\'t a prankster.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_7.mp3', NULL, NULL, '{\"words\": [\"Sam\", \"pressed\", \"his\", \"nose\", \"against\", \"the\", \"glass.\", \"It\", \"wasn\'t\", \"a\", \"person\", \"on\", \"stilts.\", \"It\", \"wasn\'t\", \"a\", \"prankster.\"], \"start_times\": [0, 0.395, 0.697, 0.848, 1.057, 1.358, 1.463, 2.218, 2.38, 2.682, 2.752, 3.077, 3.228, 3.669, 3.808, 4.098, 4.18], \"end_times\": [0.337, 0.662, 0.789, 1.033, 1.312, 1.428, 2.043, 2.345, 2.647, 2.705, 3.03, 3.158, 3.646, 3.762, 4.052, 4.122, 5.016]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(138, 24, 'Page 8', 'It was a small stray cat.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_8.mp3', NULL, NULL, '{\"words\": [\"It\", \"was\", \"a\", \"small\", \"stray\", \"cat.\"], \"start_times\": [0, 0.267, 0.418, 0.499, 0.848, 1.149], \"end_times\": [0.232, 0.372, 0.453, 0.778, 1.091, 1.718]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(139, 24, 'Page 9', 'But why the round dots?', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_9.mp3', NULL, NULL, '{\"words\": [\"But\", \"why\", \"the\", \"round\", \"dots?\"], \"start_times\": [0, 0.302, 0.522, 0.639, 0.894], \"end_times\": [0.267, 0.464, 0.592, 0.848, 1.533]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(140, 24, 'Page 10', 'The next morning, Sam went outside and traced the path. He noticed an old, overturned bucket near the curb, covered in wet, sticky mud. The cat must have stepped onto the rim of the bucket, getting thick circles of mud on its paws before walking across the lawn.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_10.mp3', NULL, NULL, '{\"words\": [\"The\", \"next\", \"morning,\", \"Sam\", \"went\", \"outside\", \"and\", \"traced\", \"the\", \"path.\", \"He\", \"noticed\", \"an\", \"old,\", \"overturned\", \"bucket\", \"near\", \"the\", \"curb,\", \"covered\", \"in\", \"wet,\", \"sticky\", \"mud.\", \"The\", \"cat\", \"must\", \"have\", \"stepped\", \"onto\", \"the\", \"rim\", \"of\", \"the\", \"bucket,\", \"getting\", \"thick\", \"circles\", \"of\", \"mud\", \"on\", \"its\", \"paws\", \"before\", \"walking\", \"across\", \"the\", \"lawn.\"], \"start_times\": [0, 0.302, 0.592, 1.115, 1.416, 1.591, 2.032, 2.136, 2.45, 2.554, 3.437, 3.622, 3.982, 4.122, 4.481, 5.108, 5.457, 5.631, 5.747, 6.467, 6.838, 6.966, 7.291, 7.697, 8.812, 8.986, 9.3, 9.509, 9.648, 9.985, 10.205, 10.333, 10.542, 10.67, 10.786, 11.378, 11.703, 11.993, 12.446, 12.585, 12.864, 12.992, 13.166, 13.56, 13.886, 14.245, 14.629, 14.745], \"end_times\": [0.255, 0.522, 1.045, 1.37, 1.556, 1.997, 2.101, 2.415, 2.519, 3.053, 3.541, 3.947, 4.052, 4.435, 5.05, 5.41, 5.596, 5.7, 6.258, 6.803, 6.896, 7.233, 7.628, 8.115, 8.928, 9.242, 9.474, 9.613, 9.938, 10.147, 10.275, 10.495, 10.612, 10.739, 11.262, 11.645, 11.912, 12.388, 12.504, 12.806, 12.945, 13.108, 13.491, 13.839, 14.199, 14.582, 14.698, 15.697]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(141, 24, 'Page 11', 'The mystery of the midnight stilts was solved. It was just a clever cat trying to keep its paws dry.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_24_page_11.mp3', NULL, NULL, '{\"words\": [\"The\", \"mystery\", \"of\", \"the\", \"midnight\", \"stilts\", \"was\", \"solved.\", \"It\", \"was\", \"just\", \"a\", \"clever\", \"cat\", \"trying\", \"to\", \"keep\", \"its\", \"paws\", \"dry.\"], \"start_times\": [0, 0.255, 0.592, 0.685, 0.789, 1.184, 1.544, 1.707, 2.473, 2.612, 2.74, 2.949, 3.019, 3.355, 3.669, 3.936, 4.017, 4.226, 4.389, 4.76], \"end_times\": [0.209, 0.557, 0.65, 0.755, 1.126, 1.509, 1.649, 2.264, 2.577, 2.694, 2.914, 2.972, 3.286, 3.622, 3.901, 3.982, 4.18, 4.331, 4.702, 5.341]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(142, 25, 'Page 1', 'In a small town known for its colorful murals, something strange began to happen. Every morning, one tiny detail from a wall painting disappeared.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"a\", \"small\", \"town\", \"known\", \"for\", \"its\", \"colorful\", \"murals,\", \"something\", \"strange\", \"began\", \"to\", \"happen.\", \"Every\", \"morning,\", \"one\", \"tiny\", \"detail\", \"from\", \"a\", \"wall\", \"painting\", \"disappeared.\"], \"start_times\": [0, 0.279, 0.348, 0.65, 0.964, 1.207, 1.358, 1.533, 2.067, 2.902, 3.355, 3.785, 4.075, 4.18, 5.283, 5.561, 6.142, 6.409, 6.757, 7.187, 7.372, 7.454, 7.709, 8.104], \"end_times\": [0.244, 0.302, 0.604, 0.917, 1.161, 1.312, 1.474, 2.009, 2.659, 3.274, 3.75, 4.04, 4.122, 4.679, 5.503, 6.026, 6.374, 6.699, 7.129, 7.326, 7.396, 7.651, 8.046, 8.916]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(143, 25, 'Page 2', 'First, a painted bird was missing from the bakery wall. Then, a bright red apple vanished from the mural on the grocery store. The paint simply flaked away overnight, leaving empty gray patches.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_2.mp3', NULL, NULL, '{\"words\": [\"First,\", \"a\", \"painted\", \"bird\", \"was\", \"missing\", \"from\", \"the\", \"bakery\", \"wall.\", \"Then,\", \"a\", \"bright\", \"red\", \"apple\", \"vanished\", \"from\", \"the\", \"mural\", \"on\", \"the\", \"grocery\", \"store.\", \"The\", \"paint\", \"simply\", \"flaked\", \"away\", \"overnight,\", \"leaving\", \"empty\", \"gray\", \"patches.\"], \"start_times\": [0, 0.65, 0.789, 1.149, 1.405, 1.579, 1.916, 2.09, 2.194, 2.612, 3.669, 4.133, 4.284, 4.598, 4.818, 5.213, 5.7, 5.875, 5.991, 6.385, 6.502, 6.606, 7.012, 7.79, 7.953, 8.243, 8.591, 8.928, 9.207, 10.101, 10.472, 10.774, 11.018], \"end_times\": [0.592, 0.72, 1.103, 1.358, 1.521, 1.858, 2.043, 2.159, 2.554, 3.065, 4.087, 4.203, 4.54, 4.76, 5.166, 5.654, 5.84, 5.944, 6.316, 6.467, 6.571, 6.954, 7.465, 7.906, 8.185, 8.533, 8.905, 9.137, 9.892, 10.403, 10.716, 10.96, 11.842]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(144, 25, 'Page 3', 'The townspeople were confused. Was someone ruining their art?', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_3.mp3', NULL, NULL, '{\"words\": [\"The\", \"townspeople\", \"were\", \"confused.\", \"Was\", \"someone\", \"ruining\", \"their\", \"art?\"], \"start_times\": [0, 0.29, 0.801, 0.964, 1.707, 1.904, 2.218, 2.566, 2.775], \"end_times\": [0.232, 0.778, 0.929, 1.556, 1.858, 2.183, 2.531, 2.717, 3.344]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(145, 25, 'Page 4', 'Eleven-year-old Elara, an aspiring artist herself, decided to find out. She knew spray paint didn’t just vanish without a trace. Someone—or something—was removing it.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_4.mp3', NULL, NULL, '{\"words\": [\"Eleven-year-old\", \"Elara,\", \"an\", \"aspiring\", \"artist\", \"herself,\", \"decided\", \"to\", \"find\", \"out.\", \"She\", \"knew\", \"spray\", \"paint\", \"didnu2019t\", \"just\", \"vanish\", \"without\", \"a\", \"trace.\", \"Someoneu2014or\", \"somethingu2014was\", \"removing\", \"it.\"], \"start_times\": [0, 0.906, 1.544, 1.707, 2.276, 2.624, 3.483, 3.924, 4.04, 4.331, 5.492, 5.689, 5.898, 6.211, 6.478, 6.734, 6.943, 7.279, 7.546, 7.616, 8.8, 9.741, 10.565, 11.006], \"end_times\": [0.848, 1.474, 1.66, 2.218, 2.577, 3.274, 3.889, 3.982, 4.261, 4.679, 5.631, 5.84, 6.153, 6.432, 6.699, 6.896, 7.245, 7.512, 7.57, 8.197, 9.671, 10.484, 10.948, 11.424]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(146, 25, 'Page 5', 'She chose the largest mural on the community center wall to keep watch over. She hid behind a nearby bush right before sunset, holding a camera.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_5.mp3', NULL, NULL, '{\"words\": [\"She\", \"chose\", \"the\", \"largest\", \"mural\", \"on\", \"the\", \"community\", \"center\", \"wall\", \"to\", \"keep\", \"watch\", \"over.\", \"She\", \"hid\", \"behind\", \"a\", \"nearby\", \"bush\", \"right\", \"before\", \"sunset,\", \"holding\", \"a\", \"camera.\"], \"start_times\": [0, 0.36, 0.685, 0.813, 1.254, 1.591, 1.695, 1.8, 2.31, 2.67, 2.937, 3.042, 3.297, 3.576, 4.586, 4.807, 5.062, 5.399, 5.48, 5.898, 6.269, 6.49, 6.827, 7.57, 7.918, 7.988], \"end_times\": [0.29, 0.65, 0.755, 1.196, 1.533, 1.66, 1.765, 2.252, 2.601, 2.879, 2.984, 3.228, 3.529, 3.982, 4.725, 5.004, 5.341, 5.422, 5.817, 6.2, 6.455, 6.769, 7.477, 7.872, 7.941, 8.638]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(147, 25, 'Page 6', 'As the evening cooled, the streetlights flickered on. The square was empty.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_6.mp3', NULL, NULL, '{\"words\": [\"As\", \"the\", \"evening\", \"cooled,\", \"the\", \"streetlights\", \"flickered\", \"on.\", \"The\", \"square\", \"was\", \"empty.\"], \"start_times\": [0, 0.337, 0.488, 0.824, 1.474, 1.625, 2.125, 2.508, 3.17, 3.332, 3.669, 3.831], \"end_times\": [0.29, 0.406, 0.766, 1.324, 1.579, 2.09, 2.45, 2.844, 3.286, 3.634, 3.773, 4.458]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(148, 25, 'Page 7', 'Then, a shadow moved near the wall.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_7.mp3', NULL, NULL, '{\"words\": [\"Then,\", \"a\", \"shadow\", \"moved\", \"near\", \"the\", \"wall.\"], \"start_times\": [0, 0.348, 0.453, 0.871, 1.138, 1.324, 1.44], \"end_times\": [0.325, 0.383, 0.789, 1.103, 1.277, 1.393, 1.997]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(149, 25, 'Page 8', 'Elara held her breath and raised her camera.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_8.mp3', NULL, NULL, '{\"words\": [\"Elara\", \"held\", \"her\", \"breath\", \"and\", \"raised\", \"her\", \"camera.\"], \"start_times\": [0, 0.569, 0.801, 0.917, 1.196, 1.324, 1.602, 1.707], \"end_times\": [0.511, 0.743, 0.871, 1.149, 1.265, 1.567, 1.672, 2.368]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(150, 25, 'Page 9', 'It wasn’t a person with paint thinner. It was a flock of small, shiny beetles.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_9.mp3', NULL, NULL, '{\"words\": [\"It\", \"wasnu2019t\", \"a\", \"person\", \"with\", \"paint\", \"thinner.\", \"It\", \"was\", \"a\", \"flock\", \"of\", \"small,\", \"shiny\", \"beetles.\"], \"start_times\": [0, 0.29, 0.569, 0.639, 0.929, 1.091, 1.347, 1.904, 2.043, 2.171, 2.229, 2.508, 2.635, 3.007, 3.379], \"end_times\": [0.255, 0.546, 0.592, 0.894, 1.045, 1.312, 1.73, 2.009, 2.125, 2.194, 2.461, 2.566, 2.984, 3.32, 4.087]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(151, 25, 'Page 10', 'She snapped a picture with a flash. The startled insects scattered, flying off into the night.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_10.mp3', NULL, NULL, '{\"words\": [\"She\", \"snapped\", \"a\", \"picture\", \"with\", \"a\", \"flash.\", \"The\", \"startled\", \"insects\", \"scattered,\", \"flying\", \"off\", \"into\", \"the\", \"night.\"], \"start_times\": [0, 0.337, 0.697, 0.766, 1.057, 1.207, 1.265, 2.125, 2.299, 2.728, 3.158, 3.808, 4.249, 4.435, 4.644, 4.76], \"end_times\": [0.267, 0.673, 0.72, 1.033, 1.173, 1.231, 1.8, 2.241, 2.67, 3.1, 3.692, 4.191, 4.389, 4.574, 4.714, 5.294]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(152, 25, 'Page 11', 'The next day, Elara showed the photo to the town\'s science teacher. It turned out the new eco-friendly paint used for the details contained a natural sugar base that attracted a specific type of local beetle. They weren\'t vandals; they were just hungry.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_11.mp3', NULL, NULL, '{\"words\": [\"The\", \"next\", \"day,\", \"Elara\", \"showed\", \"the\", \"photo\", \"to\", \"the\", \"town\'s\", \"science\", \"teacher.\", \"It\", \"turned\", \"out\", \"the\", \"new\", \"eco-friendly\", \"paint\", \"used\", \"for\", \"the\", \"details\", \"contained\", \"a\", \"natural\", \"sugar\", \"base\", \"that\", \"attracted\", \"a\", \"specific\", \"type\", \"of\", \"local\", \"beetle.\", \"They\", \"weren\'t\", \"vandals;\", \"they\", \"were\", \"just\", \"hungry.\"], \"start_times\": [0, 0.279, 0.557, 0.94, 1.393, 1.625, 1.73, 2.055, 2.171, 2.276, 2.577, 3.007, 4.029, 4.203, 4.516, 4.702, 4.853, 5.166, 5.875, 6.455, 6.78, 6.92, 7.036, 7.57, 8.022, 8.139, 8.661, 8.951, 9.578, 9.787, 10.228, 10.31, 10.867, 11.122, 11.262, 11.564, 12.608, 12.806, 13.061, 13.793, 13.967, 14.106, 14.327], \"end_times\": [0.232, 0.499, 0.894, 1.335, 1.602, 1.695, 1.997, 2.113, 2.241, 2.554, 2.972, 3.518, 4.168, 4.481, 4.656, 4.783, 5.05, 5.805, 6.281, 6.734, 6.885, 6.989, 7.512, 7.976, 8.057, 8.591, 8.893, 9.404, 9.752, 10.194, 10.252, 10.809, 11.088, 11.18, 11.517, 12.005, 12.771, 13.015, 13.677, 13.932, 14.071, 14.269, 15.047]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(153, 25, 'Page 12', 'The town switched to a different paint, and the murals remained whole once more. Another case closed by careful observation.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_25_page_12.mp3', NULL, NULL, '{\"words\": [\"The\", \"town\", \"switched\", \"to\", \"a\", \"different\", \"paint,\", \"and\", \"the\", \"murals\", \"remained\", \"whole\", \"once\", \"more.\", \"Another\", \"case\", \"closed\", \"by\", \"careful\", \"observation.\"], \"start_times\": [0, 0.267, 0.522, 0.859, 0.998, 1.068, 1.405, 1.904, 2.09, 2.194, 2.635, 3.007, 3.309, 3.599, 4.528, 4.911, 5.19, 5.608, 5.759, 6.153], \"end_times\": [0.221, 0.476, 0.824, 0.929, 1.022, 1.37, 1.846, 2.043, 2.159, 2.566, 2.972, 3.262, 3.553, 4.017, 4.865, 5.155, 5.573, 5.7, 6.084, 7.105]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(154, 26, 'Page 1', 'In the center of Maple Street stood an old clock mounted above a bakery. For years, it had ticked steadily, marking the rhythm of the town.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"the\", \"center\", \"of\", \"Maple\", \"Street\", \"stood\", \"an\", \"old\", \"clock\", \"mounted\", \"above\", \"a\", \"bakery.\", \"For\", \"years,\", \"it\", \"had\", \"ticked\", \"steadily,\", \"marking\", \"the\", \"rhythm\", \"of\", \"the\", \"town.\"], \"start_times\": [0, 0.302, 0.43, 0.766, 0.871, 1.184, 1.533, 1.788, 1.916, 2.206, 2.624, 2.995, 3.251, 3.332, 4.783, 4.992, 5.782, 5.933, 6.072, 6.409, 7.256, 7.651, 7.767, 8.104, 8.22, 8.336], \"end_times\": [0.255, 0.372, 0.708, 0.813, 1.149, 1.474, 1.753, 1.846, 2.125, 2.543, 2.961, 3.228, 3.286, 3.971, 4.934, 5.608, 5.898, 6.037, 6.339, 7.082, 7.605, 7.721, 8.046, 8.162, 8.29, 8.963]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(155, 26, 'Page 2', 'But lately, it had developed a strange habit. Every Tuesday afternoon, specifically around 3:00 PM, it would skip ahead exactly ten minutes.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_2.mp3', NULL, NULL, '{\"words\": [\"But\", \"lately,\", \"it\", \"had\", \"developed\", \"a\", \"strange\", \"habit.\", \"Every\", \"Tuesday\", \"afternoon,\", \"specifically\", \"around\", \"3:00\", \"PM,\", \"it\", \"would\", \"skip\", \"ahead\", \"exactly\", \"ten\", \"minutes.\"], \"start_times\": [0, 0.348, 0.813, 0.964, 1.115, 1.544, 1.614, 2.032, 3.019, 3.309, 3.657, 4.203, 4.83, 5.132, 5.642, 6.432, 6.583, 6.757, 7.036, 7.314, 7.872, 8.069], \"end_times\": [0.29, 0.778, 0.929, 1.068, 1.509, 1.567, 1.985, 2.508, 3.274, 3.622, 4.168, 4.783, 5.05, 5.526, 6.153, 6.548, 6.734, 6.978, 7.256, 7.814, 8.022, 8.684]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(156, 26, 'Page 3', 'The baker, Mrs. Gable, was annoyed. Her bread timing was constantly thrown off. “The clock is broken,” she complained.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_3.mp3', NULL, NULL, '{\"words\": [\"The\", \"baker,\", \"Mrs.\", \"Gable,\", \"was\", \"annoyed.\", \"Her\", \"bread\", \"timing\", \"was\", \"constantly\", \"thrown\", \"off.\", \"u201cThe\", \"clock\", \"is\", \"broken,u201d\", \"she\", \"complained.\"], \"start_times\": [0, 0.267, 0.766, 1.115, 1.498, 1.66, 2.45, 2.647, 2.914, 3.309, 3.495, 4.133, 4.447, 5.155, 5.422, 5.689, 5.805, 6.362, 6.548], \"end_times\": [0.221, 0.708, 1.08, 1.474, 1.614, 2.206, 2.589, 2.868, 3.262, 3.402, 4.087, 4.389, 4.83, 5.387, 5.631, 5.759, 6.304, 6.49, 7.245]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(157, 26, 'Page 4', 'But a clock ignoring only ten minutes, once a week, sounded too specific to be a mechanical failure. Ten-year-old Toby thought it sounded like a puzzle.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_4.mp3', NULL, NULL, '{\"words\": [\"But\", \"a\", \"clock\", \"ignoring\", \"only\", \"ten\", \"minutes,\", \"once\", \"a\", \"week,\", \"sounded\", \"too\", \"specific\", \"to\", \"be\", \"a\", \"mechanical\", \"failure.\", \"Ten-year-old\", \"Toby\", \"thought\", \"it\", \"sounded\", \"like\", \"a\", \"puzzle.\"], \"start_times\": [0, 0.29, 0.372, 0.72, 1.219, 1.521, 1.776, 2.508, 2.821, 2.902, 3.251, 3.634, 3.82, 4.4, 4.528, 4.656, 4.725, 5.271, 6.548, 7.245, 7.651, 7.883, 7.988, 8.313, 8.487, 8.557], \"end_times\": [0.267, 0.313, 0.65, 1.149, 1.463, 1.718, 2.299, 2.786, 2.844, 3.204, 3.587, 3.773, 4.342, 4.47, 4.609, 4.679, 5.201, 5.851, 7.198, 7.593, 7.86, 7.941, 8.278, 8.452, 8.51, 9.149]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(158, 26, 'Page 5', 'He arrived at the bakery on a Tuesday at 2:50 PM, notebook in hand. He sat on a bench opposite the clock and watched.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_5.mp3', NULL, NULL, '{\"words\": [\"He\", \"arrived\", \"at\", \"the\", \"bakery\", \"on\", \"a\", \"Tuesday\", \"at\", \"2:50\", \"PM,\", \"notebook\", \"in\", \"hand.\", \"He\", \"sat\", \"on\", \"a\", \"bench\", \"opposite\", \"the\", \"clock\", \"and\", \"watched.\"], \"start_times\": [0, 0.279, 0.604, 0.697, 0.813, 1.231, 1.347, 1.428, 1.892, 1.997, 2.508, 2.926, 3.309, 3.437, 4.4, 4.574, 4.83, 4.946, 5.027, 5.306, 5.724, 5.828, 6.142, 6.281], \"end_times\": [0.232, 0.58, 0.662, 0.766, 1.184, 1.3, 1.382, 1.858, 1.95, 2.426, 2.879, 3.262, 3.367, 3.889, 4.516, 4.783, 4.899, 4.969, 5.248, 5.7, 5.793, 6.084, 6.223, 6.966]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(159, 26, 'Page 6', 'At 2:55 PM, the delivery truck from the flour mill arrived, parking right beneath the clock. It was heavy, and the ground vibrated slightly as it idled.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_6.mp3', NULL, NULL, '{\"words\": [\"At\", \"2:55\", \"PM,\", \"the\", \"delivery\", \"truck\", \"from\", \"the\", \"flour\", \"mill\", \"arrived,\", \"parking\", \"right\", \"beneath\", \"the\", \"clock.\", \"It\", \"was\", \"heavy,\", \"and\", \"the\", \"ground\", \"vibrated\", \"slightly\", \"as\", \"it\", \"idled.\"], \"start_times\": [0, 0.325, 1.091, 1.672, 1.823, 2.252, 2.519, 2.67, 2.775, 3.146, 3.344, 4.017, 4.435, 4.702, 4.992, 5.097, 5.875, 6.037, 6.223, 6.699, 6.896, 7.012, 7.384, 7.93, 8.371, 8.545, 8.661], \"end_times\": [0.279, 1.033, 1.556, 1.776, 2.194, 2.473, 2.635, 2.74, 3.088, 3.297, 3.901, 4.354, 4.644, 4.957, 5.062, 5.55, 6.002, 6.142, 6.664, 6.85, 6.966, 7.326, 7.883, 8.301, 8.487, 8.615, 9.334]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(160, 26, 'Page 7', 'At 3:00 PM, a loud whistle blew from the nearby train station.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_7.mp3', NULL, NULL, '{\"words\": [\"At\", \"3:00\", \"PM,\", \"a\", \"loud\", \"whistle\", \"blew\", \"from\", \"the\", \"nearby\", \"train\", \"station.\"], \"start_times\": [0, 0.29, 0.778, 1.149, 1.242, 1.509, 1.892, 2.148, 2.334, 2.45, 2.821, 3.1], \"end_times\": [0.232, 0.697, 1.126, 1.184, 1.463, 1.858, 2.101, 2.287, 2.403, 2.752, 3.042, 3.762]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(161, 26, 'Page 8', 'But neither of these things touched the clock.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_8.mp3', NULL, NULL, '{\"words\": [\"But\", \"neither\", \"of\", \"these\", \"things\", \"touched\", \"the\", \"clock.\"], \"start_times\": [0, 0.313, 0.65, 0.755, 0.975, 1.3, 1.649, 1.765], \"end_times\": [0.255, 0.604, 0.708, 0.929, 1.242, 1.602, 1.718, 2.415]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(162, 26, 'Page 9', 'Then, Toby noticed the delivery driver. The man reached into the back of the truck and pulled out a large, powerful industrial magnet used to sort metal bags. As he carried it past the wall where the clock was mounted, the magnetic field passed right through the bricks.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_9.mp3', NULL, NULL, '{\"words\": [\"Then,\", \"Toby\", \"noticed\", \"the\", \"delivery\", \"driver.\", \"The\", \"man\", \"reached\", \"into\", \"the\", \"back\", \"of\", \"the\", \"truck\", \"and\", \"pulled\", \"out\", \"a\", \"large,\", \"powerful\", \"industrial\", \"magnet\", \"used\", \"to\", \"sort\", \"metal\", \"bags.\", \"As\", \"he\", \"carried\", \"it\", \"past\", \"the\", \"wall\", \"where\", \"the\", \"clock\", \"was\", \"mounted,\", \"the\", \"magnetic\", \"field\", \"passed\", \"right\", \"through\", \"the\", \"bricks.\"], \"start_times\": [0, 0.453, 0.778, 1.126, 1.254, 1.66, 2.914, 3.088, 3.344, 3.646, 3.82, 3.924, 4.145, 4.238, 4.342, 4.667, 4.865, 5.143, 5.317, 5.445, 5.944, 6.606, 7.245, 7.848, 8.139, 8.266, 8.533, 8.8, 10.066, 10.286, 10.403, 10.762, 10.855, 11.169, 11.285, 11.552, 11.714, 11.819, 12.098, 12.26, 13.073, 13.235, 13.677, 14.025, 14.443, 14.698, 14.93, 15.035], \"end_times\": [0.418, 0.708, 1.091, 1.196, 1.614, 2.218, 3.042, 3.274, 3.611, 3.773, 3.889, 4.098, 4.191, 4.307, 4.598, 4.807, 5.108, 5.259, 5.364, 5.898, 6.525, 7.175, 7.721, 8.104, 8.197, 8.487, 8.742, 9.462, 10.228, 10.344, 10.728, 10.82, 11.122, 11.238, 11.505, 11.691, 11.784, 12.04, 12.202, 12.829, 13.177, 13.618, 13.944, 14.362, 14.663, 14.907, 15, 15.743]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(163, 26, 'Page 10', 'The strong magnetic pull caught the metal hands of the old clock, dragging the minute hand forward slightly before the driver walked into the store.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_10.mp3', NULL, NULL, '{\"words\": [\"The\", \"strong\", \"magnetic\", \"pull\", \"caught\", \"the\", \"metal\", \"hands\", \"of\", \"the\", \"old\", \"clock,\", \"dragging\", \"the\", \"minute\", \"hand\", \"forward\", \"slightly\", \"before\", \"the\", \"driver\", \"walked\", \"into\", \"the\", \"store.\"], \"start_times\": [0, 0.313, 0.708, 1.161, 1.544, 1.811, 1.927, 2.206, 2.473, 2.577, 2.705, 2.914, 3.599, 4.029, 4.145, 4.493, 4.737, 5.143, 5.561, 5.851, 5.968, 6.351, 6.664, 6.873, 6.989], \"end_times\": [0.244, 0.639, 1.103, 1.451, 1.776, 1.881, 2.148, 2.438, 2.531, 2.647, 2.856, 3.39, 3.982, 4.098, 4.458, 4.667, 5.097, 5.503, 5.817, 5.921, 6.293, 6.629, 6.815, 6.943, 7.616]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(164, 26, 'Page 11', 'A ten-minute jump. Exactly at 3:00 PM. Every Tuesday.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_11.mp3', NULL, NULL, '{\"words\": [\"A\", \"ten-minute\", \"jump.\", \"Exactly\", \"at\", \"3:00\", \"PM.\", \"Every\", \"Tuesday.\"], \"start_times\": [0, 0.267, 0.731, 1.033, 1.533, 1.66, 2.032, 2.403, 2.752], \"end_times\": [0.186, 0.697, 0.987, 1.486, 1.602, 1.974, 2.345, 2.705, 3.483]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(165, 26, 'Page 12', 'Toby smiled, wrote down the solution, and explained it to Mrs. Gable. A simple shift in the delivery parking spot fixed the time permanently.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_26_page_12.mp3', NULL, NULL, '{\"words\": [\"Toby\", \"smiled,\", \"wrote\", \"down\", \"the\", \"solution,\", \"and\", \"explained\", \"it\", \"to\", \"Mrs.\", \"Gable.\", \"A\", \"simple\", \"shift\", \"in\", \"the\", \"delivery\", \"parking\", \"spot\", \"fixed\", \"the\", \"time\", \"permanently.\"], \"start_times\": [0, 0.441, 1.045, 1.3, 1.474, 1.579, 2.206, 2.426, 2.844, 2.937, 3.03, 3.297, 4.098, 4.238, 4.528, 4.818, 4.923, 5.039, 5.457, 5.84, 6.223, 6.502, 6.618, 6.861], \"end_times\": [0.383, 0.952, 1.265, 1.44, 1.544, 2.148, 2.368, 2.821, 2.902, 2.984, 3.274, 3.773, 4.168, 4.493, 4.772, 4.876, 4.992, 5.399, 5.782, 6.142, 6.478, 6.571, 6.827, 7.663]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(166, 27, 'Page 1', 'In Willow Park, there was an old wooden bench covered in carved initials and faded marks. One day, children noticed something unusual etched into the wood — a series of tiny symbols that looked almost like a code: a star, a circle, two lines, and a triangle.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"Willow\", \"Park,\", \"there\", \"was\", \"an\", \"old\", \"wooden\", \"bench\", \"covered\", \"in\", \"carved\", \"initials\", \"and\", \"faded\", \"marks.\", \"One\", \"day,\", \"children\", \"noticed\", \"something\", \"unusual\", \"etched\", \"into\", \"the\", \"wood\", \"u2014\", \"a\", \"series\", \"of\", \"tiny\", \"symbols\", \"that\", \"looked\", \"almost\", \"like\", \"a\", \"code:\", \"a\", \"star,\", \"a\", \"circle,\", \"two\", \"lines,\", \"and\", \"a\", \"triangle.\"], \"start_times\": [0, 0.302, 0.627, 1.254, 1.44, 1.567, 1.695, 1.997, 2.334, 2.821, 3.251, 3.402, 3.808, 4.365, 4.598, 4.946, 6.513, 6.745, 7.14, 7.605, 7.999, 8.394, 9.102, 9.439, 9.683, 9.787, 10.217, 10.507, 10.646, 11.041, 11.157, 11.54, 12.051, 12.225, 12.469, 12.817, 13.003, 13.096, 13.735, 13.886, 14.652, 14.814, 15.464, 15.766, 16.451, 16.649, 16.718], \"end_times\": [0.244, 0.557, 1.103, 1.416, 1.533, 1.637, 1.927, 2.276, 2.67, 3.216, 3.32, 3.762, 4.319, 4.516, 4.888, 5.561, 6.711, 7.082, 7.546, 7.941, 8.336, 8.986, 9.392, 9.613, 9.752, 10.043, 10.263, 10.565, 10.995, 11.099, 11.471, 11.993, 12.19, 12.423, 12.771, 12.968, 13.026, 13.584, 13.804, 14.501, 14.721, 15.372, 15.685, 16.405, 16.591, 16.672, 17.554]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(167, 27, 'Page 2', 'Rumors spread quickly. Was it a treasure map? A message from spies?', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_2.mp3', NULL, NULL, '{\"words\": [\"Rumors\", \"spread\", \"quickly.\", \"Was\", \"it\", \"a\", \"treasure\", \"map?\", \"A\", \"message\", \"from\", \"spies?\"], \"start_times\": [0, 0.522, 0.824, 1.556, 1.788, 1.892, 1.962, 2.276, 2.995, 3.135, 3.46, 3.646], \"end_times\": [0.499, 0.766, 1.312, 1.741, 1.858, 1.927, 2.241, 2.612, 3.065, 3.437, 3.587, 4.412]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(168, 27, 'Page 3', 'Twins Lily and Max loved puzzles. They sat on the bench, studying the marks carefully. They traced them onto a piece of paper.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_3.mp3', NULL, NULL, '{\"words\": [\"Twins\", \"Lily\", \"and\", \"Max\", \"loved\", \"puzzles.\", \"They\", \"sat\", \"on\", \"the\", \"bench,\", \"studying\", \"the\", \"marks\", \"carefully.\", \"They\", \"traced\", \"them\", \"onto\", \"a\", \"piece\", \"of\", \"paper.\"], \"start_times\": [0, 1.73, 2.032, 2.148, 2.543, 2.868, 3.75, 3.947, 4.156, 4.249, 4.365, 4.69, 5.12, 5.236, 5.55, 6.432, 6.641, 6.931, 7.105, 7.338, 7.407, 7.628, 7.732], \"end_times\": [0.615, 1.985, 2.101, 2.426, 2.81, 3.576, 3.913, 4.11, 4.214, 4.319, 4.667, 5.074, 5.19, 5.492, 6.223, 6.594, 6.908, 7.047, 7.279, 7.372, 7.605, 7.686, 8.406]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(169, 27, 'Page 4', '\"It doesn\'t look like letters or numbers,\" Max said.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_4.mp3', NULL, NULL, '{\"words\": [\"\"It\", \"doesn\'t\", \"look\", \"like\", \"letters\", \"or\", \"numbers,\"\", \"Max\", \"said.\"], \"start_times\": [0, 0.279, 0.534, 0.72, 0.894, 1.184, 1.312, 1.881, 2.183], \"end_times\": [0.244, 0.511, 0.673, 0.848, 1.149, 1.254, 1.823, 2.148, 2.833]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(170, 27, 'Page 5', 'Lily looked around the park. \"Maybe it relates to what we can see from here.\"', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_5.mp3', NULL, NULL, '{\"words\": [\"Lily\", \"looked\", \"around\", \"the\", \"park.\", \"\"Maybe\", \"it\", \"relates\", \"to\", \"what\", \"we\", \"can\", \"see\", \"from\", \"here.\"\"], \"start_times\": [0, 0.453, 0.697, 0.94, 1.045, 1.73, 2.125, 2.229, 2.566, 2.659, 2.798, 2.914, 3.077, 3.274, 3.471], \"end_times\": [0.406, 0.662, 0.906, 1.01, 1.486, 2.09, 2.183, 2.531, 2.612, 2.775, 2.868, 3.03, 3.239, 3.413, 3.947]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(171, 27, 'Page 6', 'She stood by the bench and looked straight ahead. The star symbol. She looked up at the sky. A star? No, the large metal star sculpture in the center of the fountain.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_6.mp3', NULL, NULL, '{\"words\": [\"She\", \"stood\", \"by\", \"the\", \"bench\", \"and\", \"looked\", \"straight\", \"ahead.\", \"The\", \"star\", \"symbol.\", \"She\", \"looked\", \"up\", \"at\", \"the\", \"sky.\", \"A\", \"star?\", \"No,\", \"the\", \"large\", \"metal\", \"star\", \"sculpture\", \"in\", \"the\", \"center\", \"of\", \"the\", \"fountain.\"], \"start_times\": [0, 0.313, 0.58, 0.731, 0.848, 1.196, 1.358, 1.637, 1.939, 2.705, 2.902, 3.228, 4.249, 4.458, 4.679, 4.783, 4.876, 4.981, 5.619, 5.782, 6.734, 7.349, 7.535, 7.918, 8.185, 8.464, 8.94, 9.056, 9.172, 9.451, 9.532, 9.659], \"end_times\": [0.255, 0.546, 0.673, 0.801, 1.138, 1.312, 1.591, 1.904, 2.38, 2.833, 3.158, 3.738, 4.389, 4.656, 4.748, 4.841, 4.946, 5.468, 5.7, 6.293, 7.175, 7.465, 7.86, 8.139, 8.406, 8.893, 9.009, 9.125, 9.404, 9.497, 9.601, 10.356]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(172, 27, 'Page 7', 'She then looked at the circle. Beyond the fountain was the round clock tower of the town hall.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_7.mp3', NULL, NULL, '{\"words\": [\"She\", \"then\", \"looked\", \"at\", \"the\", \"circle.\", \"Beyond\", \"the\", \"fountain\", \"was\", \"the\", \"round\", \"clock\", \"tower\", \"of\", \"the\", \"town\", \"hall.\"], \"start_times\": [0, 0.313, 0.511, 0.731, 0.824, 0.952, 1.869, 2.252, 2.368, 2.775, 2.961, 3.088, 3.413, 3.75, 4.098, 4.214, 4.331, 4.632], \"end_times\": [0.244, 0.453, 0.708, 0.789, 0.894, 1.486, 2.206, 2.322, 2.717, 2.902, 3.03, 3.344, 3.692, 4.029, 4.168, 4.284, 4.574, 5.155]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(173, 27, 'Page 8', 'Two lines. The parallel tracks of the old tram line visible just past the clock tower.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_8.mp3', NULL, NULL, '{\"words\": [\"Two\", \"lines.\", \"The\", \"parallel\", \"tracks\", \"of\", \"the\", \"old\", \"tram\", \"line\", \"visible\", \"just\", \"past\", \"the\", \"clock\", \"tower.\"], \"start_times\": [0, 0.337, 1.045, 1.196, 1.614, 1.974, 2.078, 2.206, 2.426, 2.763, 3.042, 3.46, 3.738, 4.052, 4.156, 4.447], \"end_times\": [0.267, 0.871, 1.149, 1.556, 1.939, 2.032, 2.148, 2.38, 2.694, 2.995, 3.402, 3.68, 4.005, 4.122, 4.389, 5.016]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(174, 27, 'Page 9', 'And the triangle. The pointed roof of the library in the distance.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_9.mp3', NULL, NULL, '{\"words\": [\"And\", \"the\", \"triangle.\", \"The\", \"pointed\", \"roof\", \"of\", \"the\", \"library\", \"in\", \"the\", \"distance.\"], \"start_times\": [0, 0.302, 0.406, 1.161, 1.324, 1.683, 1.939, 2.043, 2.171, 2.624, 2.717, 2.821], \"end_times\": [0.255, 0.372, 1.01, 1.277, 1.625, 1.881, 1.997, 2.113, 2.589, 2.682, 2.786, 3.576]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(175, 27, 'Page 10', 'The symbols weren\'t a code. They were a map of sightlines.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_10.mp3', NULL, NULL, '{\"words\": [\"The\", \"symbols\", \"weren\'t\", \"a\", \"code.\", \"They\", \"were\", \"a\", \"map\", \"of\", \"sightlines.\"], \"start_times\": [0, 0.267, 0.627, 0.871, 0.94, 1.509, 1.695, 1.858, 1.927, 2.183, 2.299], \"end_times\": [0.221, 0.58, 0.836, 0.894, 1.358, 1.66, 1.823, 1.881, 2.125, 2.229, 3.158]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(176, 27, 'Page 11', 'The twins walked the exact path indicated by the symbols: past the fountain, toward the clock tower, along the tracks, straight to the library.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_11.mp3', NULL, NULL, '{\"words\": [\"The\", \"twins\", \"walked\", \"the\", \"exact\", \"path\", \"indicated\", \"by\", \"the\", \"symbols:\", \"past\", \"the\", \"fountain,\", \"toward\", \"the\", \"clock\", \"tower,\", \"along\", \"the\", \"tracks,\", \"straight\", \"to\", \"the\", \"library.\"], \"start_times\": [0, 0.279, 0.615, 0.882, 1.01, 1.428, 1.753, 2.241, 2.38, 2.496, 3.564, 3.843, 3.959, 4.702, 4.992, 5.085, 5.364, 5.886, 6.235, 6.351, 6.989, 7.291, 7.384, 7.488], \"end_times\": [0.232, 0.557, 0.859, 0.952, 1.358, 1.695, 2.206, 2.334, 2.45, 3.123, 3.808, 3.913, 4.493, 4.957, 5.062, 5.306, 5.793, 6.188, 6.304, 6.873, 7.268, 7.338, 7.454, 8.266]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(177, 27, 'Page 12', 'At the base of the library steps, half-buried in the dirt, they found a small metal box. Inside was a collection of vintage glass marbles and a note that read: \"To whoever follows the view, enjoy.\"', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_12.mp3', NULL, NULL, '{\"words\": [\"At\", \"the\", \"base\", \"of\", \"the\", \"library\", \"steps,\", \"half-buried\", \"in\", \"the\", \"dirt,\", \"they\", \"found\", \"a\", \"small\", \"metal\", \"box.\", \"Inside\", \"was\", \"a\", \"collection\", \"of\", \"vintage\", \"glass\", \"marbles\", \"and\", \"a\", \"note\", \"that\", \"read:\", \"\"To\", \"whoever\", \"follows\", \"the\", \"view,\", \"enjoy.\"\"], \"start_times\": [0, 0.279, 0.395, 0.685, 0.766, 0.882, 1.37, 2.043, 2.659, 2.763, 2.868, 3.425, 3.622, 3.831, 3.901, 4.214, 4.47, 5.631, 6.211, 6.362, 6.432, 6.873, 6.978, 7.349, 7.686, 8.29, 8.522, 8.626, 8.858, 9.056, 9.671, 9.973, 10.414, 10.82, 10.937, 11.297], \"end_times\": [0.244, 0.348, 0.65, 0.731, 0.836, 1.312, 1.927, 2.624, 2.717, 2.833, 3.309, 3.576, 3.796, 3.855, 4.156, 4.423, 5.027, 6.177, 6.327, 6.397, 6.838, 6.92, 7.314, 7.628, 8.115, 8.464, 8.545, 8.824, 8.986, 9.462, 9.915, 10.333, 10.774, 10.89, 11.238, 12.307]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(178, 27, 'Page 13', 'It wasn\'t espionage; it was a game left behind years ago. And the twins had won.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_27_page_13.mp3', NULL, NULL, '{\"words\": [\"It\", \"wasn\'t\", \"espionage;\", \"it\", \"was\", \"a\", \"game\", \"left\", \"behind\", \"years\", \"ago.\", \"And\", \"the\", \"twins\", \"had\", \"won.\"], \"start_times\": [0, 0.29, 0.569, 1.405, 1.533, 1.66, 1.73, 1.974, 2.206, 2.566, 2.821, 3.193, 3.367, 3.471, 3.762, 3.901], \"end_times\": [0.244, 0.534, 1.231, 1.509, 1.625, 1.683, 1.939, 2.148, 2.519, 2.786, 3.135, 3.32, 3.437, 3.727, 3.855, 4.412]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11');
INSERT INTO `story_sections` (`id`, `story_id`, `title`, `content`, `page_number`, `elevenlabs_audio_url`, `elevenlabs_voice_id`, `audio_duration`, `word_timestamps`, `created_at`, `updated_at`) VALUES
(179, 28, 'Page 1', 'At the edge of town ran an old railway tunnel no longer used by trains. Recently, hikers passing through it reported strange echoing sounds — not ordinary echoes, but repeating rhythms that didn’t match their footsteps.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_1.mp3', NULL, NULL, '{\"words\": [\"At\", \"the\", \"edge\", \"of\", \"town\", \"ran\", \"an\", \"old\", \"railway\", \"tunnel\", \"no\", \"longer\", \"used\", \"by\", \"trains.\", \"Recently,\", \"hikers\", \"passing\", \"through\", \"it\", \"reported\", \"strange\", \"echoing\", \"sounds\", \"u2014\", \"not\", \"ordinary\", \"echoes,\", \"but\", \"repeating\", \"rhythms\", \"that\", \"didnu2019t\", \"match\", \"their\", \"footsteps.\"], \"start_times\": [0, 0.279, 0.406, 0.569, 0.673, 1.022, 1.242, 1.37, 1.625, 2.02, 2.368, 2.519, 2.844, 3.111, 3.274, 4.807, 5.352, 5.793, 6.165, 6.444, 6.571, 7.001, 7.512, 7.953, 8.522, 9.009, 9.242, 9.694, 10.461, 10.658, 11.099, 11.505, 11.656, 11.912, 12.19, 12.365], \"end_times\": [0.244, 0.348, 0.546, 0.615, 0.94, 1.196, 1.3, 1.544, 1.974, 2.31, 2.45, 2.775, 3.077, 3.216, 3.855, 5.317, 5.735, 6.118, 6.409, 6.513, 6.943, 7.454, 7.872, 8.371, 8.568, 9.183, 9.636, 10.286, 10.612, 11.041, 11.459, 11.622, 11.877, 12.144, 12.33, 13.235]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(180, 28, 'Page 2', 'Some said the tunnel was haunted by the ghost of an old train conductor.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_2.mp3', NULL, NULL, '{\"words\": [\"Some\", \"said\", \"the\", \"tunnel\", \"was\", \"haunted\", \"by\", \"the\", \"ghost\", \"of\", \"an\", \"old\", \"train\", \"conductor.\"], \"start_times\": [0, 0.441, 0.673, 0.778, 1.08, 1.242, 1.649, 1.8, 1.916, 2.229, 2.322, 2.438, 2.659, 3.019], \"end_times\": [0.406, 0.639, 0.743, 1.033, 1.173, 1.602, 1.741, 1.869, 2.183, 2.287, 2.38, 2.612, 2.949, 3.808]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(181, 28, 'Page 3', 'Ten-year-old Aris didn\'t believe in ghosts. He believed in acoustics. Equipped with a flashlight and a heavy pair of boots, he walked toward the stone archway.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_3.mp3', NULL, NULL, '{\"words\": [\"Ten-year-old\", \"Aris\", \"didn\'t\", \"believe\", \"in\", \"ghosts.\", \"He\", \"believed\", \"in\", \"acoustics.\", \"Equipped\", \"with\", \"a\", \"flashlight\", \"and\", \"a\", \"heavy\", \"pair\", \"of\", \"boots,\", \"he\", \"walked\", \"toward\", \"the\", \"stone\", \"archway.\"], \"start_times\": [0, 0.708, 1.091, 1.347, 1.672, 1.8, 2.798, 2.972, 3.297, 3.39, 4.737, 5.132, 5.259, 5.329, 5.944, 6.084, 6.165, 6.42, 6.629, 6.745, 7.407, 7.57, 7.872, 8.139, 8.255, 8.626], \"end_times\": [0.639, 1.033, 1.312, 1.637, 1.741, 2.473, 2.914, 3.262, 3.355, 4.226, 5.108, 5.236, 5.283, 5.898, 6.037, 6.107, 6.362, 6.583, 6.687, 7.198, 7.5, 7.848, 8.104, 8.208, 8.58, 9.427]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(182, 28, 'Page 4', 'The tunnel was damp and cold. He stomped his boot.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_4.mp3', NULL, NULL, '{\"words\": [\"The\", \"tunnel\", \"was\", \"damp\", \"and\", \"cold.\", \"He\", \"stomped\", \"his\", \"boot.\"], \"start_times\": [0, 0.279, 0.58, 0.755, 1.068, 1.219, 1.765, 1.939, 2.299, 2.438], \"end_times\": [0.232, 0.546, 0.685, 1.022, 1.149, 1.683, 1.881, 2.276, 2.38, 2.972]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(183, 28, 'Page 5', 'Thud... thud... thud...', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_5.mp3', NULL, NULL, '{\"words\": [\"Thud...\", \"thud...\", \"thud...\"], \"start_times\": [0, 0.569, 1.033], \"end_times\": [0.499, 0.987, 1.579]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(184, 28, 'Page 6', 'The echo was normal.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_6.mp3', NULL, NULL, '{\"words\": [\"The\", \"echo\", \"was\", \"normal.\"], \"start_times\": [0, 0.302, 0.546, 0.708], \"end_times\": [0.244, 0.499, 0.65, 1.3]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(185, 28, 'Page 7', 'He walked further, nearing the center where the darkness was thickest. Suddenly, the strange rhythm started.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_7.mp3', NULL, NULL, '{\"words\": [\"He\", \"walked\", \"further,\", \"nearing\", \"the\", \"center\", \"where\", \"the\", \"darkness\", \"was\", \"thickest.\", \"Suddenly,\", \"the\", \"strange\", \"rhythm\", \"started.\"], \"start_times\": [0, 0.302, 0.58, 1.277, 1.591, 1.707, 2.055, 2.218, 2.322, 2.786, 2.949, 4.029, 4.632, 4.795, 5.224, 5.573], \"end_times\": [0.244, 0.534, 1.126, 1.544, 1.66, 2.009, 2.183, 2.287, 2.74, 2.891, 3.587, 4.586, 4.737, 5.178, 5.492, 6.223]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(186, 28, 'Page 8', 'Clack, clack-clack, clack.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_8.mp3', NULL, NULL, '{\"words\": [\"Clack,\", \"clack-clack,\", \"clack.\"], \"start_times\": [0, 0.476, 1.033], \"end_times\": [0.453, 1.01, 1.579]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(187, 28, 'Page 9', 'He stopped. The sound continued for a few seconds, then faded. It wasn\'t his echo. It was independent.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_9.mp3', NULL, NULL, '{\"words\": [\"He\", \"stopped.\", \"The\", \"sound\", \"continued\", \"for\", \"a\", \"few\", \"seconds,\", \"then\", \"faded.\", \"It\", \"wasn\'t\", \"his\", \"echo.\", \"It\", \"was\", \"independent.\"], \"start_times\": [0, 0.29, 0.871, 1.068, 1.393, 1.881, 2.02, 2.09, 2.276, 3.088, 3.32, 4.005, 4.168, 4.458, 4.632, 5.224, 5.399, 5.55], \"end_times\": [0.232, 0.743, 1.01, 1.324, 1.846, 1.974, 2.043, 2.229, 2.879, 3.251, 3.796, 4.122, 4.412, 4.563, 5.074, 5.352, 5.492, 6.409]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(188, 28, 'Page 10', 'He shined his flashlight along the curved stone ceiling. Water dripped slowly from the damp bricks.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_10.mp3', NULL, NULL, '{\"words\": [\"He\", \"shined\", \"his\", \"flashlight\", \"along\", \"the\", \"curved\", \"stone\", \"ceiling.\", \"Water\", \"dripped\", \"slowly\", \"from\", \"the\", \"damp\", \"bricks.\"], \"start_times\": [0, 0.302, 0.627, 0.766, 1.37, 1.649, 1.765, 2.194, 2.601, 3.738, 4.133, 4.447, 4.876, 5.05, 5.155, 5.457], \"end_times\": [0.255, 0.592, 0.72, 1.324, 1.602, 1.718, 2.136, 2.554, 3.228, 4.075, 4.4, 4.818, 5.016, 5.12, 5.375, 6.177]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(189, 28, 'Page 11', 'He listened closer. The sound wasn\'t coming from the air; it was traveling through the ground. He knelt and pressed his ear to the cold stone floor, near the old, rusted metal tracks that had never been fully removed.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_11.mp3', NULL, NULL, '{\"words\": [\"He\", \"listened\", \"closer.\", \"The\", \"sound\", \"wasn\'t\", \"coming\", \"from\", \"the\", \"air;\", \"it\", \"was\", \"traveling\", \"through\", \"the\", \"ground.\", \"He\", \"knelt\", \"and\", \"pressed\", \"his\", \"ear\", \"to\", \"the\", \"cold\", \"stone\", \"floor,\", \"near\", \"the\", \"old,\", \"rusted\", \"metal\", \"tracks\", \"that\", \"had\", \"never\", \"been\", \"fully\", \"removed.\"], \"start_times\": [0, 0.302, 0.685, 1.649, 1.846, 2.206, 2.45, 2.705, 2.868, 3.007, 3.715, 3.866, 4.04, 4.574, 4.783, 4.876, 6.037, 6.211, 6.536, 6.676, 6.989, 7.163, 7.384, 7.5, 7.616, 7.93, 8.278, 8.975, 9.195, 9.346, 9.706, 10.228, 10.542, 10.983, 11.134, 11.285, 11.552, 11.761, 12.086], \"end_times\": [0.232, 0.615, 1.324, 1.776, 2.148, 2.415, 2.67, 2.833, 2.937, 3.437, 3.831, 3.971, 4.528, 4.76, 4.853, 5.526, 6.153, 6.478, 6.618, 6.954, 7.094, 7.326, 7.442, 7.57, 7.872, 8.231, 8.8, 9.149, 9.276, 9.636, 10.147, 10.495, 10.937, 11.099, 11.227, 11.494, 11.703, 12.016, 13.235]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(190, 28, 'Page 12', 'The rhythm was clear now.', 12, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_12.mp3', NULL, NULL, '{\"words\": [\"The\", \"rhythm\", \"was\", \"clear\", \"now.\"], \"start_times\": [0, 0.279, 0.546, 0.708, 1.01], \"end_times\": [0.232, 0.511, 0.65, 0.952, 1.486]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(191, 28, 'Page 13', 'Clack, clack-clack.', 13, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_13.mp3', NULL, NULL, '{\"words\": [\"Clack,\", \"clack-clack.\"], \"start_times\": [0, 0.464], \"end_times\": [0.441, 1.347]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(192, 28, 'Page 14', 'He knew what lay beyond the hill the tunnel ran under. The town’s new construction site.', 14, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_14.mp3', NULL, NULL, '{\"words\": [\"He\", \"knew\", \"what\", \"lay\", \"beyond\", \"the\", \"hill\", \"the\", \"tunnel\", \"ran\", \"under.\", \"The\", \"townu2019s\", \"new\", \"construction\", \"site.\"], \"start_times\": [0, 0.279, 0.453, 0.615, 0.824, 1.138, 1.254, 1.556, 1.672, 2.009, 2.241, 3.111, 3.274, 3.599, 3.75, 4.331], \"end_times\": [0.232, 0.418, 0.569, 0.766, 1.091, 1.207, 1.486, 1.637, 1.95, 2.183, 2.67, 3.228, 3.553, 3.704, 4.272, 4.83]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(193, 28, 'Page 15', 'The sound wasn\'t a ghost. It was the vibration of heavy machinery digging into the rock miles away, traveling perfectly along the continuous line of the forgotten steel tracks into the echoing chamber of the tunnel.', 15, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_15.mp3', NULL, NULL, '{\"words\": [\"The\", \"sound\", \"wasn\'t\", \"a\", \"ghost.\", \"It\", \"was\", \"the\", \"vibration\", \"of\", \"heavy\", \"machinery\", \"digging\", \"into\", \"the\", \"rock\", \"miles\", \"away,\", \"traveling\", \"perfectly\", \"along\", \"the\", \"continuous\", \"line\", \"of\", \"the\", \"forgotten\", \"steel\", \"tracks\", \"into\", \"the\", \"echoing\", \"chamber\", \"of\", \"the\", \"tunnel.\"], \"start_times\": [0, 0.279, 0.557, 0.859, 0.929, 1.66, 1.823, 1.974, 2.09, 2.682, 2.821, 3.123, 3.762, 4.145, 4.377, 4.505, 4.888, 5.341, 6.246, 6.827, 7.5, 7.837, 7.953, 8.649, 9.009, 9.137, 9.276, 9.868, 10.263, 10.82, 11.111, 11.262, 11.691, 12.121, 12.26, 12.376], \"end_times\": [0.232, 0.499, 0.824, 0.894, 1.486, 1.788, 1.927, 2.043, 2.635, 2.74, 3.053, 3.669, 4.087, 4.307, 4.447, 4.772, 5.283, 5.863, 6.745, 7.43, 7.79, 7.906, 8.591, 8.975, 9.079, 9.207, 9.787, 10.194, 10.739, 11.041, 11.18, 11.633, 12.063, 12.19, 12.33, 12.957]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(194, 28, 'Page 16', 'Mystery solved. Sound travels faster through solid metal than empty air.', 16, 'https://lingola-stories-kids.b-cdn.net/audio/story_28_page_16.mp3', NULL, NULL, '{\"words\": [\"Mystery\", \"solved.\", \"Sound\", \"travels\", \"faster\", \"through\", \"solid\", \"metal\", \"than\", \"empty\", \"air.\"], \"start_times\": [0, 0.65, 1.289, 1.591, 1.939, 2.357, 2.601, 2.949, 3.216, 3.379, 3.715], \"end_times\": [0.58, 1.173, 1.556, 1.892, 2.31, 2.566, 2.902, 3.17, 3.332, 3.646, 4.226]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(195, 29, 'Page 1', 'Long before cities, long before roads, when the earth was warm and wild, there was a vast green valley surrounded by towering cliffs. Ferns stretched taller than trees, and mist floated above winding rivers. In this valley lived a young Brachiosaurus named Aro.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_29_page_1.mp3', NULL, NULL, '{\"words\": [\"Long\", \"before\", \"cities,\", \"long\", \"before\", \"roads,\", \"when\", \"the\", \"earth\", \"was\", \"warm\", \"and\", \"wild,\", \"there\", \"was\", \"a\", \"vast\", \"green\", \"valley\", \"surrounded\", \"by\", \"towering\", \"cliffs.\", \"Ferns\", \"stretched\", \"taller\", \"than\", \"trees,\", \"and\", \"mist\", \"floated\", \"above\", \"winding\", \"rivers.\", \"In\", \"this\", \"valley\", \"lived\", \"a\", \"young\", \"Brachiosaurus\", \"named\", \"Aro.\"], \"start_times\": [0, 0.534, 0.906, 1.672, 2.02, 2.38, 3.181, 3.39, 3.518, 3.785, 3.982, 4.423, 4.598, 5.387, 5.573, 5.712, 5.805, 6.316, 6.687, 7.094, 7.593, 7.779, 8.313, 9.555, 10.043, 10.507, 10.902, 11.076, 11.865, 12.109, 12.55, 12.957, 13.247, 13.653, 14.919, 15.128, 15.372, 16.091, 16.451, 16.579, 16.869, 17.74, 18.03], \"end_times\": [0.464, 0.848, 1.521, 1.95, 2.322, 2.937, 3.355, 3.46, 3.727, 3.901, 4.354, 4.516, 5.143, 5.55, 5.666, 5.735, 6.223, 6.618, 7.024, 7.546, 7.697, 8.255, 8.858, 9.996, 10.437, 10.855, 11.018, 11.656, 12.04, 12.434, 12.922, 13.212, 13.595, 14.222, 15.07, 15.302, 15.766, 16.393, 16.486, 16.811, 17.659, 17.961, 18.622]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(196, 29, 'Page 2', 'Aro was the tallest dinosaur in his herd. Even as a youngster, his long neck allowed him to reach leaves that no other dinosaur could touch. He loved standing among the highest branches, feeling the cool breeze and watching the world from above.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_29_page_2.mp3', NULL, NULL, '{\"words\": [\"Aro\", \"was\", \"the\", \"tallest\", \"dinosaur\", \"in\", \"his\", \"herd.\", \"Even\", \"as\", \"a\", \"youngster,\", \"his\", \"long\", \"neck\", \"allowed\", \"him\", \"to\", \"reach\", \"leaves\", \"that\", \"no\", \"other\", \"dinosaur\", \"could\", \"touch.\", \"He\", \"loved\", \"standing\", \"among\", \"the\", \"highest\", \"branches,\", \"feeling\", \"the\", \"cool\", \"breeze\", \"and\", \"watching\", \"the\", \"world\", \"from\", \"above.\"], \"start_times\": [0, 0.604, 0.813, 0.929, 1.358, 1.881, 1.997, 2.171, 3.297, 3.599, 3.727, 3.831, 4.54, 4.748, 5.062, 5.283, 5.584, 5.735, 5.863, 6.177, 6.56, 6.745, 6.92, 7.14, 7.628, 7.814, 8.893, 9.091, 9.404, 9.834, 10.066, 10.182, 10.542, 11.366, 11.761, 11.877, 12.167, 12.562, 12.713, 13.084, 13.189, 13.468, 13.665], \"end_times\": [0.511, 0.755, 0.882, 1.3, 1.811, 1.939, 2.113, 2.601, 3.553, 3.68, 3.762, 4.423, 4.679, 4.992, 5.236, 5.55, 5.689, 5.793, 6.084, 6.513, 6.699, 6.85, 7.094, 7.57, 7.779, 8.29, 9.009, 9.334, 9.787, 10.031, 10.136, 10.484, 11.238, 11.714, 11.831, 12.109, 12.516, 12.655, 13.038, 13.154, 13.421, 13.607, 14.257]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(197, 29, 'Page 3', 'But his height also made him stand out. Smaller dinosaurs found him intimidating. When he walked, his heavy footsteps made the ground shake, and smaller creatures would scatter into the bushes. Aro never meant to scare anyone. He had a gentle heart, but his size made him seem like a moving mountain.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_29_page_3.mp3', NULL, NULL, '{\"words\": [\"But\", \"his\", \"height\", \"also\", \"made\", \"him\", \"stand\", \"out.\", \"Smaller\", \"dinosaurs\", \"found\", \"him\", \"intimidating.\", \"When\", \"he\", \"walked,\", \"his\", \"heavy\", \"footsteps\", \"made\", \"the\", \"ground\", \"shake,\", \"and\", \"smaller\", \"creatures\", \"would\", \"scatter\", \"into\", \"the\", \"bushes.\", \"Aro\", \"never\", \"meant\", \"to\", \"scare\", \"anyone.\", \"He\", \"had\", \"a\", \"gentle\", \"heart,\", \"but\", \"his\", \"size\", \"made\", \"him\", \"seem\", \"like\", \"a\", \"moving\", \"mountain.\"], \"start_times\": [0, 0.325, 0.511, 0.836, 1.219, 1.405, 1.556, 1.904, 2.775, 3.239, 3.808, 4.063, 4.203, 5.619, 5.851, 5.991, 6.641, 6.838, 7.105, 7.674, 7.883, 7.988, 8.348, 9.067, 9.3, 9.729, 10.17, 10.368, 10.82, 11.064, 11.169, 12.457, 12.875, 13.142, 13.375, 13.502, 13.816, 14.605, 14.791, 14.988, 15.081, 15.487, 16.114, 16.335, 16.497, 16.857, 17.043, 17.194, 17.461, 17.635, 17.728, 18.1], \"end_times\": [0.279, 0.441, 0.778, 1.138, 1.382, 1.498, 1.834, 2.334, 3.193, 3.75, 4.005, 4.156, 5.016, 5.805, 5.909, 6.49, 6.769, 7.047, 7.616, 7.848, 7.953, 8.278, 8.858, 9.23, 9.671, 10.124, 10.321, 10.762, 10.995, 11.134, 11.854, 12.806, 13.073, 13.328, 13.433, 13.781, 14.361, 14.721, 14.942, 15.011, 15.429, 15.963, 16.288, 16.451, 16.823, 17.02, 17.148, 17.403, 17.612, 17.658, 18.03, 18.715]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(198, 29, 'Page 4', 'One afternoon, a sharp wind blew through the valley. The sky darkened quickly, and a heavy storm broke loose. Rain poured down in sheets, and the rivers began to rise.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_29_page_4.mp3', NULL, NULL, '{\"words\": [\"One\", \"afternoon,\", \"a\", \"sharp\", \"wind\", \"blew\", \"through\", \"the\", \"valley.\", \"The\", \"sky\", \"darkened\", \"quickly,\", \"and\", \"a\", \"heavy\", \"storm\", \"broke\", \"loose.\", \"Rain\", \"poured\", \"down\", \"in\", \"sheets,\", \"and\", \"the\", \"rivers\", \"began\", \"to\", \"rise.\"], \"start_times\": [0, 0.372, 1.045, 1.184, 1.486, 1.741, 1.974, 2.206, 2.31, 3.251, 3.425, 3.773, 4.191, 4.714, 4.934, 5.016, 5.283, 5.608, 5.863, 6.745, 7.094, 7.419, 7.639, 7.779, 8.208, 8.382, 8.487, 8.835, 9.137, 9.276], \"end_times\": [0.337, 0.998, 1.115, 1.428, 1.683, 1.939, 2.183, 2.276, 2.81, 3.379, 3.704, 4.133, 4.69, 4.876, 4.957, 5.224, 5.561, 5.828, 6.304, 7.024, 7.372, 7.593, 7.709, 8.185, 8.336, 8.452, 8.777, 9.091, 9.195, 9.985]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(199, 29, 'Page 5', 'Near the riverbank, a small group of young Triceratops had been playing. Now, the rising water was rushing around them, cutting them off from the safe high ground. They cried out in fear, but the water was moving too quickly for the older dinosaurs to cross safely.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_29_page_5.mp3', NULL, NULL, '{\"words\": [\"Near\", \"the\", \"riverbank,\", \"a\", \"small\", \"group\", \"of\", \"young\", \"Triceratops\", \"had\", \"been\", \"playing.\", \"Now,\", \"the\", \"rising\", \"water\", \"was\", \"rushing\", \"around\", \"them,\", \"cutting\", \"them\", \"off\", \"from\", \"the\", \"safe\", \"high\", \"ground.\", \"They\", \"cried\", \"out\", \"in\", \"fear,\", \"but\", \"the\", \"water\", \"was\", \"moving\", \"too\", \"quickly\", \"for\", \"the\", \"older\", \"dinosaurs\", \"to\", \"cross\", \"safely.\"], \"start_times\": [0, 0.372, 0.488, 1.451, 1.602, 1.927, 2.194, 2.334, 2.589, 3.425, 3.564, 3.738, 4.969, 5.526, 5.7, 6.118, 6.467, 6.699, 7.105, 7.407, 8.011, 8.336, 8.557, 8.8, 8.986, 9.114, 9.439, 9.659, 10.623, 10.844, 11.169, 11.355, 11.505, 12.19, 12.376, 12.492, 12.817, 13.015, 13.363, 13.572, 14.002, 14.164, 14.303, 14.617, 15.267, 15.395, 15.72], \"end_times\": [0.337, 0.441, 1.207, 1.521, 1.881, 2.136, 2.252, 2.519, 3.39, 3.529, 3.704, 4.272, 5.445, 5.631, 6.049, 6.397, 6.583, 7.059, 7.361, 7.767, 8.29, 8.475, 8.754, 8.94, 9.056, 9.392, 9.625, 10.182, 10.786, 11.134, 11.296, 11.424, 11.981, 12.341, 12.446, 12.759, 12.934, 13.305, 13.514, 13.932, 14.118, 14.234, 14.559, 15.221, 15.325, 15.673, 16.486]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(200, 29, 'Page 6', 'Aro heard their distress. Without hesitation, he waded into the rushing water. His massive legs stood firm against the strong current. He lowered his long neck, stretching it across the water like a sturdy bridge.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_29_page_6.mp3', NULL, NULL, '{\"words\": [\"Aro\", \"heard\", \"their\", \"distress.\", \"Without\", \"hesitation,\", \"he\", \"waded\", \"into\", \"the\", \"rushing\", \"water.\", \"His\", \"massive\", \"legs\", \"stood\", \"firm\", \"against\", \"the\", \"strong\", \"current.\", \"He\", \"lowered\", \"his\", \"long\", \"neck,\", \"stretching\", \"it\", \"across\", \"the\", \"water\", \"like\", \"a\", \"sturdy\", \"bridge.\"], \"start_times\": [0, 0.488, 0.72, 0.906, 1.73, 2.113, 3.251, 3.425, 3.82, 4.04, 4.156, 4.54, 5.422, 5.654, 6.06, 6.327, 6.606, 6.873, 7.198, 7.314, 7.674, 8.719, 8.916, 9.276, 9.439, 9.718, 10.31, 10.786, 10.879, 11.262, 11.378, 11.714, 11.889, 11.97, 12.365], \"end_times\": [0.406, 0.685, 0.859, 1.614, 2.067, 2.926, 3.344, 3.773, 3.982, 4.11, 4.47, 5.039, 5.584, 6.026, 6.304, 6.548, 6.827, 7.163, 7.268, 7.616, 8.208, 8.835, 9.242, 9.381, 9.648, 10.101, 10.728, 10.844, 11.204, 11.331, 11.668, 11.865, 11.912, 12.307, 13.003]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(201, 29, 'Page 7', 'With gentle encouragement, the small Triceratops climbed onto his broad back and hurried across his neck to the safety of the rocky shore. Aro stood perfectly still, ensuring not one of them slipped.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_29_page_7.mp3', NULL, NULL, '{\"words\": [\"With\", \"gentle\", \"encouragement,\", \"the\", \"small\", \"Triceratops\", \"climbed\", \"onto\", \"his\", \"broad\", \"back\", \"and\", \"hurried\", \"across\", \"his\", \"neck\", \"to\", \"the\", \"safety\", \"of\", \"the\", \"rocky\", \"shore.\", \"Aro\", \"stood\", \"perfectly\", \"still,\", \"ensuring\", \"not\", \"one\", \"of\", \"them\", \"slipped.\"], \"start_times\": [0, 0.383, 0.731, 1.486, 1.637, 1.939, 2.717, 3.088, 3.332, 3.471, 3.785, 4.122, 4.342, 4.667, 4.981, 5.132, 5.364, 5.492, 5.608, 5.991, 6.084, 6.2, 6.525, 7.755, 8.081, 8.348, 8.824, 9.404, 9.903, 10.112, 10.286, 10.379, 10.565], \"end_times\": [0.325, 0.697, 1.393, 1.591, 1.881, 2.67, 3.042, 3.262, 3.413, 3.727, 4.04, 4.272, 4.644, 4.946, 5.074, 5.306, 5.422, 5.561, 5.944, 6.037, 6.153, 6.467, 6.943, 8.022, 8.29, 8.766, 9.288, 9.857, 10.043, 10.252, 10.333, 10.507, 11.192]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(202, 29, 'Page 8', 'When the storm finally passed and the water receded, the valley was quiet again. The smaller dinosaurs no longer saw Aro as a frightening giant. They saw him as a protector. From that day on, he was never alone when he stretched his neck toward the highest leaves.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_29_page_8.mp3', NULL, NULL, '{\"words\": [\"When\", \"the\", \"storm\", \"finally\", \"passed\", \"and\", \"the\", \"water\", \"receded,\", \"the\", \"valley\", \"was\", \"quiet\", \"again.\", \"The\", \"smaller\", \"dinosaurs\", \"no\", \"longer\", \"saw\", \"Aro\", \"as\", \"a\", \"frightening\", \"giant.\", \"They\", \"saw\", \"him\", \"as\", \"a\", \"protector.\", \"From\", \"that\", \"day\", \"on,\", \"he\", \"was\", \"never\", \"alone\", \"when\", \"he\", \"stretched\", \"his\", \"neck\", \"toward\", \"the\", \"highest\", \"leaves.\"], \"start_times\": [0, 0.325, 0.43, 0.766, 1.184, 1.672, 1.8, 1.904, 2.206, 3.32, 3.483, 3.808, 3.971, 4.319, 5.492, 5.677, 6.095, 6.757, 6.931, 7.268, 7.558, 7.918, 8.057, 8.127, 8.591, 9.834, 10.043, 10.275, 10.426, 10.565, 10.646, 12.144, 12.376, 12.585, 12.817, 13.166, 13.305, 13.502, 13.804, 14.164, 14.327, 14.431, 14.861, 15.035, 15.302, 15.546, 15.662, 16.045], \"end_times\": [0.29, 0.395, 0.697, 1.115, 1.625, 1.753, 1.869, 2.148, 2.937, 3.425, 3.762, 3.913, 4.284, 4.795, 5.619, 6.037, 6.699, 6.85, 7.21, 7.465, 7.837, 7.999, 8.081, 8.522, 9.23, 9.996, 10.205, 10.379, 10.519, 10.6, 11.447, 12.33, 12.539, 12.748, 13.108, 13.247, 13.421, 13.735, 14.141, 14.292, 14.373, 14.814, 14.965, 15.244, 15.523, 15.615, 15.975, 16.718]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(203, 30, 'Page 1', 'In a dense jungle filled with towering cycads and tangled vines lived a young Velociraptor named Kira. She was quick, clever, and observant. Her kind was known for speed and sharp instincts.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"a\", \"dense\", \"jungle\", \"filled\", \"with\", \"towering\", \"cycads\", \"and\", \"tangled\", \"vines\", \"lived\", \"a\", \"young\", \"Velociraptor\", \"named\", \"Kira.\", \"She\", \"was\", \"quick,\", \"clever,\", \"and\", \"observant.\", \"Her\", \"kind\", \"was\", \"known\", \"for\", \"speed\", \"and\", \"sharp\", \"instincts.\"], \"start_times\": [0, 0.29, 0.372, 0.708, 1.126, 1.474, 1.649, 2.159, 2.821, 2.984, 3.471, 4.249, 4.493, 4.586, 4.853, 5.712, 5.979, 7.07, 7.245, 7.419, 8.022, 8.533, 8.742, 9.88, 10.077, 10.391, 10.565, 10.855, 11.029, 11.413, 11.54, 11.865], \"end_times\": [0.244, 0.313, 0.65, 1.068, 1.44, 1.602, 2.101, 2.775, 2.926, 3.413, 3.971, 4.47, 4.516, 4.783, 5.654, 5.921, 6.56, 7.198, 7.349, 7.895, 8.51, 8.696, 9.439, 10.019, 10.333, 10.507, 10.797, 10.971, 11.366, 11.494, 11.796, 12.678]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(204, 30, 'Page 2', 'But Kira had a problem. She was too curious. While her pack focused entirely on the hunt, studying tracks and sensing prey, Kira was distracted by everything else.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_2.mp3', NULL, NULL, '{\"words\": [\"But\", \"Kira\", \"had\", \"a\", \"problem.\", \"She\", \"was\", \"too\", \"curious.\", \"While\", \"her\", \"pack\", \"focused\", \"entirely\", \"on\", \"the\", \"hunt,\", \"studying\", \"tracks\", \"and\", \"sensing\", \"prey,\", \"Kira\", \"was\", \"distracted\", \"by\", \"everything\", \"else.\"], \"start_times\": [0, 0.29, 0.58, 0.708, 0.766, 1.509, 1.695, 1.858, 2.067, 3.088, 3.344, 3.483, 3.831, 4.238, 4.783, 4.888, 5.016, 5.654, 6.095, 6.525, 6.664, 7.094, 7.802, 8.173, 8.348, 8.928, 9.102, 9.543], \"end_times\": [0.244, 0.534, 0.685, 0.731, 1.358, 1.649, 1.8, 2.009, 2.763, 3.309, 3.425, 3.738, 4.203, 4.737, 4.853, 4.957, 5.41, 6.037, 6.49, 6.618, 7.024, 7.593, 8.115, 8.29, 8.882, 9.033, 9.485, 10.077]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(205, 30, 'Page 3', 'She noticed the way dew collected on spider webs. She studied the bright colors of strange new beetles. She watched the patterns of shadows cast by moving clouds. When the pack ran together, Kira often stopped to inspect a strange plant, losing her place in the formation.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_3.mp3', NULL, NULL, '{\"words\": [\"She\", \"noticed\", \"the\", \"way\", \"dew\", \"collected\", \"on\", \"spider\", \"webs.\", \"She\", \"studied\", \"the\", \"bright\", \"colors\", \"of\", \"strange\", \"new\", \"beetles.\", \"She\", \"watched\", \"the\", \"patterns\", \"of\", \"shadows\", \"cast\", \"by\", \"moving\", \"clouds.\", \"When\", \"the\", \"pack\", \"ran\", \"together,\", \"Kira\", \"often\", \"stopped\", \"to\", \"inspect\", \"a\", \"strange\", \"plant,\", \"losing\", \"her\", \"place\", \"in\", \"the\", \"formation.\"], \"start_times\": [0, 0.325, 0.673, 0.789, 0.998, 1.254, 1.707, 1.846, 2.229, 3.065, 3.274, 3.634, 3.75, 4.063, 4.516, 4.644, 5.155, 5.341, 6.385, 6.583, 6.896, 7.012, 7.442, 7.558, 8.057, 8.417, 8.603, 8.951, 10.252, 10.449, 10.553, 10.832, 11.064, 11.784, 12.19, 12.516, 12.852, 12.968, 13.363, 13.444, 13.862, 14.617, 14.977, 15.105, 15.406, 15.499, 15.615], \"end_times\": [0.255, 0.65, 0.743, 0.917, 1.184, 1.66, 1.788, 2.183, 2.74, 3.204, 3.611, 3.704, 4.005, 4.458, 4.574, 5.085, 5.283, 6.002, 6.525, 6.873, 6.966, 7.407, 7.5, 7.988, 8.359, 8.522, 8.882, 9.648, 10.414, 10.519, 10.762, 11.006, 11.633, 12.121, 12.457, 12.829, 12.899, 13.328, 13.386, 13.816, 14.443, 14.919, 15.058, 15.372, 15.464, 15.569, 16.486]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(206, 30, 'Page 4', 'The pack leader, a scarred veteran named Torak, warned her. “A distracted hunter feeds no one,” he growled.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_4.mp3', NULL, NULL, '{\"words\": [\"The\", \"pack\", \"leader,\", \"a\", \"scarred\", \"veteran\", \"named\", \"Torak,\", \"warned\", \"her.\", \"u201cA\", \"distracted\", \"hunter\", \"feeds\", \"no\", \"one,u201d\", \"he\", \"growled.\"], \"start_times\": [0, 0.267, 0.569, 0.882, 0.987, 1.405, 1.776, 2.055, 2.694, 3.053, 3.657, 3.878, 4.54, 4.934, 5.306, 5.584, 6.014, 6.153], \"end_times\": [0.221, 0.499, 0.859, 0.917, 1.358, 1.73, 1.997, 2.577, 2.995, 3.332, 3.808, 4.481, 4.853, 5.224, 5.492, 5.898, 6.084, 6.827]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(207, 30, 'Page 5', 'Kira felt ashamed, but she couldn’t stop noticing the world’s quiet details.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_5.mp3', NULL, NULL, '{\"words\": [\"Kira\", \"felt\", \"ashamed,\", \"but\", \"she\", \"couldnu2019t\", \"stop\", \"noticing\", \"the\", \"worldu2019s\", \"quiet\", \"details.\"], \"start_times\": [0, 0.499, 0.743, 1.196, 1.347, 1.486, 1.765, 2.043, 2.508, 2.624, 3.007, 3.39], \"end_times\": [0.441, 0.697, 1.173, 1.312, 1.44, 1.73, 1.974, 2.438, 2.577, 2.961, 3.332, 4.226]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(208, 30, 'Page 6', 'One dry season, food became scarce. The herds they usually followed had migrated earlier than expected. The pack grew hungry and tired. They wandered for days through scrubland, finding nothing but dry earth and quiet brush.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_6.mp3', NULL, NULL, '{\"words\": [\"One\", \"dry\", \"season,\", \"food\", \"became\", \"scarce.\", \"The\", \"herds\", \"they\", \"usually\", \"followed\", \"had\", \"migrated\", \"earlier\", \"than\", \"expected.\", \"The\", \"pack\", \"grew\", \"hungry\", \"and\", \"tired.\", \"They\", \"wandered\", \"for\", \"days\", \"through\", \"scrubland,\", \"finding\", \"nothing\", \"but\", \"dry\", \"earth\", \"and\", \"quiet\", \"brush.\"], \"start_times\": [0, 0.453, 0.778, 1.416, 1.683, 2.043, 3.228, 3.413, 3.715, 3.901, 4.272, 4.818, 5.027, 5.584, 5.944, 6.107, 7.198, 7.361, 7.674, 7.93, 8.452, 8.626, 9.543, 9.764, 10.159, 10.321, 10.635, 10.867, 11.761, 12.121, 12.457, 12.62, 12.957, 13.305, 13.479, 13.851], \"end_times\": [0.418, 0.697, 1.3, 1.637, 1.997, 2.717, 3.344, 3.669, 3.831, 4.214, 4.702, 4.969, 5.526, 5.898, 6.06, 6.815, 7.314, 7.616, 7.872, 8.382, 8.568, 9.218, 9.706, 10.124, 10.263, 10.6, 10.832, 11.61, 12.074, 12.399, 12.574, 12.887, 13.224, 13.421, 13.804, 14.582]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(209, 30, 'Page 7', 'Kira, however, noticed something no one else did.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_7.mp3', NULL, NULL, '{\"words\": [\"Kira,\", \"however,\", \"noticed\", \"something\", \"no\", \"one\", \"else\", \"did.\"], \"start_times\": [0, 0.511, 1.184, 1.533, 1.95, 2.113, 2.252, 2.496], \"end_times\": [0.488, 1.01, 1.509, 1.869, 2.043, 2.218, 2.45, 3.019]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(210, 30, 'Page 8', 'Near the base of a tall, dead tree, a specific type of blue-winged insect gathered in small clusters. Kira had studied them before in the dense jungle. She knew these insects only survived near hidden water sources, usually laying their eggs where the soil remained damp beneath the surface.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_8.mp3', NULL, NULL, '{\"words\": [\"Near\", \"the\", \"base\", \"of\", \"a\", \"tall,\", \"dead\", \"tree,\", \"a\", \"specific\", \"type\", \"of\", \"blue-winged\", \"insect\", \"gathered\", \"in\", \"small\", \"clusters.\", \"Kira\", \"had\", \"studied\", \"them\", \"before\", \"in\", \"the\", \"dense\", \"jungle.\", \"She\", \"knew\", \"these\", \"insects\", \"only\", \"survived\", \"near\", \"hidden\", \"water\", \"sources,\", \"usually\", \"laying\", \"their\", \"eggs\", \"where\", \"the\", \"soil\", \"remained\", \"damp\", \"beneath\", \"the\", \"surface.\"], \"start_times\": [0, 0.36, 0.476, 0.778, 0.882, 0.975, 1.393, 1.66, 2.38, 2.508, 3.03, 3.309, 3.448, 4.029, 4.54, 4.969, 5.108, 5.433, 7.094, 7.465, 7.605, 7.93, 8.104, 8.44, 8.533, 8.638, 8.928, 10.159, 10.379, 10.612, 10.855, 11.389, 11.691, 12.202, 12.457, 12.725, 13.015, 13.978, 14.443, 14.721, 14.93, 15.197, 15.383, 15.511, 15.906, 16.324, 16.649, 16.962, 17.078], \"end_times\": [0.325, 0.43, 0.743, 0.836, 0.906, 1.358, 1.614, 2.171, 2.438, 2.972, 3.274, 3.367, 3.982, 4.47, 4.934, 5.039, 5.375, 6.142, 7.407, 7.558, 7.906, 8.046, 8.406, 8.499, 8.603, 8.882, 9.555, 10.31, 10.553, 10.809, 11.308, 11.633, 12.132, 12.399, 12.678, 12.968, 13.653, 14.373, 14.675, 14.872, 15.174, 15.348, 15.453, 15.813, 16.254, 16.591, 16.927, 17.032, 17.833]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(211, 30, 'Page 9', 'Without waiting for a command, Kira broke away from the pack. She followed the trail of blue insects, moving swiftly until she reached a dense thicket of thorny bushes. She pushed through carefully and found a hidden rock pool, full of fresh water, surrounded by small mammals drawn to the oasis.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_9.mp3', NULL, NULL, '{\"words\": [\"Without\", \"waiting\", \"for\", \"a\", \"command,\", \"Kira\", \"broke\", \"away\", \"from\", \"the\", \"pack.\", \"She\", \"followed\", \"the\", \"trail\", \"of\", \"blue\", \"insects,\", \"moving\", \"swiftly\", \"until\", \"she\", \"reached\", \"a\", \"dense\", \"thicket\", \"of\", \"thorny\", \"bushes.\", \"She\", \"pushed\", \"through\", \"carefully\", \"and\", \"found\", \"a\", \"hidden\", \"rock\", \"pool,\", \"full\", \"of\", \"fresh\", \"water,\", \"surrounded\", \"by\", \"small\", \"mammals\", \"drawn\", \"to\", \"the\", \"oasis.\"], \"start_times\": [0, 0.441, 0.743, 0.906, 0.975, 1.765, 2.136, 2.403, 2.635, 2.81, 2.926, 3.947, 4.156, 4.493, 4.598, 4.923, 5.039, 5.306, 6.177, 6.513, 7.024, 7.303, 7.465, 7.779, 7.872, 8.22, 8.603, 8.754, 9.125, 10.6, 10.797, 11.076, 11.355, 11.889, 12.04, 12.307, 12.388, 12.701, 12.992, 13.549, 13.804, 13.909, 14.222, 14.884, 15.372, 15.546, 15.882, 16.289, 16.567, 16.684, 16.811], \"end_times\": [0.395, 0.697, 0.859, 0.929, 1.591, 2.078, 2.368, 2.589, 2.763, 2.879, 3.437, 4.087, 4.47, 4.563, 4.876, 4.981, 5.259, 6.002, 6.455, 6.966, 7.256, 7.396, 7.732, 7.802, 8.162, 8.557, 8.673, 9.056, 9.787, 10.739, 11.053, 11.308, 11.831, 11.97, 12.26, 12.33, 12.632, 12.922, 13.456, 13.758, 13.862, 14.164, 14.71, 15.337, 15.476, 15.813, 16.242, 16.533, 16.625, 16.753, 17.74]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(212, 30, 'Page 10', 'She called out. The pack followed her voice.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_10.mp3', NULL, NULL, '{\"words\": [\"She\", \"called\", \"out.\", \"The\", \"pack\", \"followed\", \"her\", \"voice.\"], \"start_times\": [0, 0.302, 0.592, 1.057, 1.219, 1.521, 1.846, 1.962], \"end_times\": [0.244, 0.557, 0.882, 1.173, 1.451, 1.811, 1.916, 2.647]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(213, 30, 'Page 11', 'They drank deeply and found enough food to sustain them through the dry stretch. Torak looked at Kira differently after that. Her curiosity wasn\'t a distraction. It was a different kind of survival instinct.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_30_page_11.mp3', NULL, NULL, '{\"words\": [\"They\", \"drank\", \"deeply\", \"and\", \"found\", \"enough\", \"food\", \"to\", \"sustain\", \"them\", \"through\", \"the\", \"dry\", \"stretch.\", \"Torak\", \"looked\", \"at\", \"Kira\", \"differently\", \"after\", \"that.\", \"Her\", \"curiosity\", \"wasn\'t\", \"a\", \"distraction.\", \"It\", \"was\", \"a\", \"different\", \"kind\", \"of\", \"survival\", \"instinct.\"], \"start_times\": [0, 0.348, 0.673, 1.126, 1.324, 1.579, 1.823, 2.09, 2.218, 2.659, 2.844, 3.077, 3.17, 3.448, 4.656, 5.097, 5.317, 5.433, 5.77, 6.235, 6.49, 7.279, 7.488, 8.208, 8.522, 8.591, 9.567, 9.718, 9.868, 9.95, 10.275, 10.519, 10.612, 11.111], \"end_times\": [0.302, 0.604, 1.068, 1.254, 1.533, 1.788, 2.043, 2.148, 2.612, 2.786, 3.053, 3.146, 3.379, 4.052, 5.039, 5.283, 5.375, 5.724, 6.177, 6.455, 6.896, 7.43, 8.15, 8.487, 8.545, 9.358, 9.683, 9.822, 9.892, 10.24, 10.472, 10.565, 11.041, 11.889]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(214, 31, 'Page 1', 'Across an open plain where ancient trees dotted the horizon lived a young Tyrannosaurus named Rexar. His footsteps shook the ground. His teeth were sharp and powerful. Even though he was not yet fully grown, other dinosaurs gave him a wide space out of respect for his strength.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_1.mp3', NULL, NULL, '{\"words\": [\"Across\", \"an\", \"open\", \"plain\", \"where\", \"ancient\", \"trees\", \"dotted\", \"the\", \"horizon\", \"lived\", \"a\", \"young\", \"Tyrannosaurus\", \"named\", \"Rexar.\", \"His\", \"footsteps\", \"shook\", \"the\", \"ground.\", \"His\", \"teeth\", \"were\", \"sharp\", \"and\", \"powerful.\", \"Even\", \"though\", \"he\", \"was\", \"not\", \"yet\", \"fully\", \"grown,\", \"other\", \"dinosaurs\", \"gave\", \"him\", \"a\", \"wide\", \"space\", \"out\", \"of\", \"respect\", \"for\", \"his\", \"strength.\"], \"start_times\": [0, 0.592, 0.72, 1.022, 1.451, 1.66, 2.043, 2.461, 2.786, 2.914, 3.843, 4.133, 4.238, 4.493, 5.329, 5.631, 6.792, 7.012, 7.744, 8.046, 8.15, 9.091, 9.323, 9.613, 9.787, 10.182, 10.379, 11.68, 11.947, 12.167, 12.26, 12.423, 12.632, 12.829, 13.142, 13.897, 14.187, 14.768, 15, 15.151, 15.255, 15.592, 16.01, 16.184, 16.289, 16.718, 16.881, 17.02], \"end_times\": [0.557, 0.662, 0.952, 1.382, 1.614, 1.997, 2.392, 2.763, 2.856, 3.518, 4.098, 4.156, 4.423, 5.259, 5.55, 6.281, 6.954, 7.628, 7.999, 8.115, 8.707, 9.265, 9.578, 9.741, 10.089, 10.321, 11.076, 11.923, 12.132, 12.214, 12.365, 12.585, 12.783, 13.084, 13.688, 14.129, 14.71, 14.965, 15.105, 15.186, 15.557, 15.975, 16.149, 16.231, 16.672, 16.823, 16.985, 17.694]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(215, 31, 'Page 2', 'Rexar loved the sunlight. He enjoyed the heat on his scales and the clear view of the plains.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_2.mp3', NULL, NULL, '{\"words\": [\"Rexar\", \"loved\", \"the\", \"sunlight.\", \"He\", \"enjoyed\", \"the\", \"heat\", \"on\", \"his\", \"scales\", \"and\", \"the\", \"clear\", \"view\", \"of\", \"the\", \"plains.\"], \"start_times\": [0, 0.557, 0.801, 0.917, 1.463, 1.625, 1.962, 2.09, 2.38, 2.531, 2.659, 3.111, 3.251, 3.355, 3.669, 3.889, 3.994, 4.098], \"end_times\": [0.499, 0.766, 0.871, 1.416, 1.567, 1.939, 2.032, 2.322, 2.473, 2.624, 3.065, 3.204, 3.32, 3.599, 3.843, 3.947, 4.063, 4.83]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(216, 31, 'Page 3', 'But there was one thing Rexar feared more than anything else: the sky roaring.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_3.mp3', NULL, NULL, '{\"words\": [\"But\", \"there\", \"was\", \"one\", \"thing\", \"Rexar\", \"feared\", \"more\", \"than\", \"anything\", \"else:\", \"the\", \"sky\", \"roaring.\"], \"start_times\": [0, 0.255, 0.418, 0.569, 0.755, 1.01, 1.382, 1.672, 1.846, 2.043, 2.45, 3.158, 3.309, 3.68], \"end_times\": [0.232, 0.383, 0.499, 0.72, 0.929, 1.324, 1.625, 1.823, 1.985, 2.392, 2.833, 3.262, 3.587, 4.365]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(217, 31, 'Page 4', 'Whenever heavy, dark clouds gathered and thunder rumbled across the plains, Rexar felt panic rise in his chest. The unpredictable flashes of lightning and the deafening cracks made the great predator cower in the thickest brush he could find.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_4.mp3', NULL, NULL, '{\"words\": [\"Whenever\", \"heavy,\", \"dark\", \"clouds\", \"gathered\", \"and\", \"thunder\", \"rumbled\", \"across\", \"the\", \"plains,\", \"Rexar\", \"felt\", \"panic\", \"rise\", \"in\", \"his\", \"chest.\", \"The\", \"unpredictable\", \"flashes\", \"of\", \"lightning\", \"and\", \"the\", \"deafening\", \"cracks\", \"made\", \"the\", \"great\", \"predator\", \"cower\", \"in\", \"the\", \"thickest\", \"brush\", \"he\", \"could\", \"find.\"], \"start_times\": [0, 0.604, 1.033, 1.37, 1.846, 2.334, 2.519, 2.961, 3.32, 3.657, 3.773, 4.621, 5.05, 5.341, 5.793, 6.107, 6.235, 6.397, 7.442, 7.663, 8.382, 8.882, 9.021, 9.578, 9.834, 9.95, 10.426, 11.32, 11.575, 11.703, 12.005, 12.527, 13.015, 13.142, 13.282, 13.723, 14.048, 14.141, 14.338], \"end_times\": [0.511, 0.975, 1.3, 1.788, 2.287, 2.426, 2.879, 3.297, 3.622, 3.727, 4.296, 4.981, 5.271, 5.712, 6.072, 6.177, 6.339, 6.931, 7.581, 8.336, 8.824, 8.94, 9.427, 9.787, 9.903, 10.356, 10.937, 11.552, 11.645, 11.935, 12.446, 12.934, 13.096, 13.212, 13.653, 14.013, 14.094, 14.292, 15]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(218, 31, 'Page 5', 'One stormy afternoon, a flash flood struck the plain. The water rose rapidly, sweeping away small trees and cutting the land into islands. Rexar scrambled to higher ground, shaking not just from the cold rain but from the constant roar of thunder.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_5.mp3', NULL, NULL, '{\"words\": [\"One\", \"stormy\", \"afternoon,\", \"a\", \"flash\", \"flood\", \"struck\", \"the\", \"plain.\", \"The\", \"water\", \"rose\", \"rapidly,\", \"sweeping\", \"away\", \"small\", \"trees\", \"and\", \"cutting\", \"the\", \"land\", \"into\", \"islands.\", \"Rexar\", \"scrambled\", \"to\", \"higher\", \"ground,\", \"shaking\", \"not\", \"just\", \"from\", \"the\", \"cold\", \"rain\", \"but\", \"from\", \"the\", \"constant\", \"roar\", \"of\", \"thunder.\"], \"start_times\": [0, 0.372, 0.778, 1.509, 1.649, 1.997, 2.31, 2.589, 2.694, 3.692, 3.866, 4.18, 4.493, 5.317, 5.735, 6.037, 6.374, 6.943, 7.152, 7.477, 7.605, 7.964, 8.231, 9.532, 9.938, 10.379, 10.495, 10.762, 11.529, 11.958, 12.156, 12.33, 12.504, 12.62, 12.957, 13.433, 13.63, 13.804, 13.92, 14.408, 14.663, 14.791], \"end_times\": [0.325, 0.708, 1.416, 1.567, 1.95, 2.252, 2.543, 2.659, 3.181, 3.808, 4.122, 4.435, 5.143, 5.689, 5.968, 6.316, 6.815, 7.094, 7.419, 7.546, 7.906, 8.139, 8.835, 9.88, 10.356, 10.426, 10.716, 11.32, 11.9, 12.109, 12.307, 12.457, 12.574, 12.887, 13.224, 13.595, 13.758, 13.874, 14.35, 14.617, 14.721, 15.418]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(219, 31, 'Page 6', 'On a small piece of high ground nearby, a group of young, frightened duck-billed dinosaurs called Parasaurolophus were huddled together. The water was rising fast, and they had nowhere to go.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_6.mp3', NULL, NULL, '{\"words\": [\"On\", \"a\", \"small\", \"piece\", \"of\", \"high\", \"ground\", \"nearby,\", \"a\", \"group\", \"of\", \"young,\", \"frightened\", \"duck-billed\", \"dinosaurs\", \"called\", \"Parasaurolophus\", \"were\", \"huddled\", \"together.\", \"The\", \"water\", \"was\", \"rising\", \"fast,\", \"and\", \"they\", \"had\", \"nowhere\", \"to\", \"go.\"], \"start_times\": [0, 0.29, 0.36, 0.673, 0.929, 1.033, 1.231, 1.509, 2.101, 2.252, 2.531, 2.682, 3.088, 3.576, 4.156, 4.911, 5.213, 6.269, 6.467, 6.769, 7.814, 7.976, 8.243, 8.406, 8.777, 9.311, 9.485, 9.625, 9.787, 10.066, 10.17], \"end_times\": [0.255, 0.313, 0.615, 0.894, 0.975, 1.196, 1.463, 2.043, 2.171, 2.473, 2.589, 2.995, 3.518, 4.122, 4.841, 5.155, 6.2, 6.432, 6.745, 7.303, 7.93, 8.197, 8.336, 8.719, 9.288, 9.451, 9.59, 9.729, 10.043, 10.112, 10.681]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(220, 31, 'Page 7', 'Rexar was terrified of the storm. Every crack of thunder made him want to hide. But the calls of the trapped youngsters pierced through the rain.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_7.mp3', NULL, NULL, '{\"words\": [\"Rexar\", \"was\", \"terrified\", \"of\", \"the\", \"storm.\", \"Every\", \"crack\", \"of\", \"thunder\", \"made\", \"him\", \"want\", \"to\", \"hide.\", \"But\", \"the\", \"calls\", \"of\", \"the\", \"trapped\", \"youngsters\", \"pierced\", \"through\", \"the\", \"rain.\"], \"start_times\": [0, 0.58, 0.743, 1.3, 1.393, 1.498, 2.229, 2.601, 2.949, 3.088, 3.495, 3.68, 3.808, 4.017, 4.156, 5.085, 5.271, 5.387, 5.7, 5.805, 5.921, 6.269, 6.815, 7.291, 7.605, 7.732], \"end_times\": [0.522, 0.673, 1.277, 1.358, 1.463, 1.95, 2.531, 2.891, 3.007, 3.437, 3.646, 3.762, 3.982, 4.075, 4.644, 5.236, 5.341, 5.666, 5.759, 5.875, 6.211, 6.734, 7.233, 7.57, 7.674, 8.313]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(221, 31, 'Page 8', 'He took a deep breath. His fear was intense, but he knew his strength was greater. Rexar stepped into the rushing water, bracing himself against the current. He positioned his massive body to block the strongest part of the flood, creating a calmer pool of water behind him.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_8.mp3', NULL, NULL, '{\"words\": [\"He\", \"took\", \"a\", \"deep\", \"breath.\", \"His\", \"fear\", \"was\", \"intense,\", \"but\", \"he\", \"knew\", \"his\", \"strength\", \"was\", \"greater.\", \"Rexar\", \"stepped\", \"into\", \"the\", \"rushing\", \"water,\", \"bracing\", \"himself\", \"against\", \"the\", \"current.\", \"He\", \"positioned\", \"his\", \"massive\", \"body\", \"to\", \"block\", \"the\", \"strongest\", \"part\", \"of\", \"the\", \"flood,\", \"creating\", \"a\", \"calmer\", \"pool\", \"of\", \"water\", \"behind\", \"him.\"], \"start_times\": [0, 0.29, 0.488, 0.569, 0.801, 1.765, 2.02, 2.322, 2.496, 3.379, 3.587, 3.727, 3.994, 4.145, 4.516, 4.69, 5.747, 6.246, 6.594, 6.792, 6.92, 7.303, 8.034, 8.522, 8.928, 9.242, 9.358, 10.217, 10.391, 10.925, 11.122, 11.564, 11.9, 12.051, 12.353, 12.481, 12.992, 13.224, 13.34, 13.468, 14.234, 14.687, 14.791, 15.244, 15.546, 15.673, 16.045, 16.475], \"end_times\": [0.244, 0.441, 0.511, 0.743, 1.324, 1.939, 2.252, 2.438, 3.228, 3.541, 3.646, 3.924, 4.098, 4.47, 4.621, 5.236, 6.177, 6.56, 6.734, 6.861, 7.245, 7.79, 8.464, 8.87, 9.207, 9.311, 9.892, 10.321, 10.879, 11.029, 11.517, 11.842, 11.981, 12.295, 12.423, 12.934, 13.189, 13.282, 13.41, 13.99, 14.64, 14.71, 15.174, 15.499, 15.604, 15.975, 16.405, 16.904]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(222, 31, 'Page 9', 'He roared—not in anger, but to guide them. The young dinosaurs recognized the path he had made and quickly paddled across the safer water to higher ground.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_9.mp3', NULL, NULL, '{\"words\": [\"He\", \"roaredu2014not\", \"in\", \"anger,\", \"but\", \"to\", \"guide\", \"them.\", \"The\", \"young\", \"dinosaurs\", \"recognized\", \"the\", \"path\", \"he\", \"had\", \"made\", \"and\", \"quickly\", \"paddled\", \"across\", \"the\", \"safer\", \"water\", \"to\", \"higher\", \"ground.\"], \"start_times\": [0, 0.348, 1.474, 1.614, 2.264, 2.461, 2.577, 2.856, 3.808, 4.005, 4.214, 4.783, 5.364, 5.468, 5.793, 5.886, 6.037, 6.304, 6.455, 6.827, 7.198, 7.558, 7.686, 8.057, 8.417, 8.568, 8.858], \"end_times\": [0.267, 1.416, 1.544, 2.09, 2.426, 2.519, 2.821, 3.204, 3.936, 4.168, 4.714, 5.329, 5.433, 5.747, 5.84, 5.991, 6.258, 6.397, 6.757, 7.175, 7.512, 7.628, 7.999, 8.348, 8.487, 8.812, 9.474]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(223, 31, 'Page 10', 'The thunder cracked again, loud and sharp. Rexar flinched, but he didn\'t run. He had stood his ground against the storm. He wasn\'t entirely fearless, but he had learned that courage wasn\'t the absence of fear; it was acting despite it.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_31_page_10.mp3', NULL, NULL, '{\"words\": [\"The\", \"thunder\", \"cracked\", \"again,\", \"loud\", \"and\", \"sharp.\", \"Rexar\", \"flinched,\", \"but\", \"he\", \"didn\'t\", \"run.\", \"He\", \"had\", \"stood\", \"his\", \"ground\", \"against\", \"the\", \"storm.\", \"He\", \"wasn\'t\", \"entirely\", \"fearless,\", \"but\", \"he\", \"had\", \"learned\", \"that\", \"courage\", \"wasn\'t\", \"the\", \"absence\", \"of\", \"fear;\", \"it\", \"was\", \"acting\", \"despite\", \"it.\"], \"start_times\": [0, 0.325, 0.662, 0.998, 1.463, 1.8, 1.939, 3.042, 3.495, 4.04, 4.249, 4.354, 4.632, 5.503, 5.654, 5.805, 6.072, 6.211, 6.571, 6.908, 7.024, 8.057, 8.22, 8.533, 9.079, 9.868, 10.077, 10.194, 10.356, 10.681, 10.855, 11.215, 11.517, 11.668, 12.121, 12.249, 12.887, 13.038, 13.235, 13.677, 14.129], \"end_times\": [0.267, 0.604, 0.964, 1.347, 1.753, 1.881, 2.438, 3.425, 3.994, 4.203, 4.296, 4.586, 5.062, 5.608, 5.759, 6.026, 6.165, 6.513, 6.861, 6.978, 7.546, 8.162, 8.487, 9.021, 9.718, 10.019, 10.136, 10.298, 10.635, 10.797, 11.18, 11.482, 11.587, 12.098, 12.179, 12.678, 13.003, 13.154, 13.618, 14.094, 15.139]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(224, 32, 'Page 1', 'In a wide valley surrounded by jagged cliffs lived a young Triceratops named Tor. His three horns were still growing, but he already carried himself with quiet determination.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"a\", \"wide\", \"valley\", \"surrounded\", \"by\", \"jagged\", \"cliffs\", \"lived\", \"a\", \"young\", \"Triceratops\", \"named\", \"Tor.\", \"His\", \"three\", \"horns\", \"were\", \"still\", \"growing,\", \"but\", \"he\", \"already\", \"carried\", \"himself\", \"with\", \"quiet\", \"determination.\"], \"start_times\": [0, 0.302, 0.383, 0.65, 0.998, 1.44, 1.614, 1.985, 2.67, 2.937, 3.03, 3.274, 4.098, 4.389, 5.213, 5.433, 5.7, 6.014, 6.177, 6.455, 7.198, 7.384, 7.512, 7.918, 8.278, 8.661, 8.835, 9.218], \"end_times\": [0.267, 0.325, 0.615, 0.94, 1.405, 1.544, 1.939, 2.392, 2.902, 2.961, 3.216, 4.04, 4.319, 4.888, 5.387, 5.654, 5.979, 6.142, 6.397, 6.989, 7.349, 7.442, 7.86, 8.243, 8.615, 8.789, 9.172, 10.217]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(225, 32, 'Page 2', 'His herd was peaceful but constantly on alert for predators. They traveled together, moving like a slow, armored wall across the landscape.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_2.mp3', NULL, NULL, '{\"words\": [\"His\", \"herd\", \"was\", \"peaceful\", \"but\", \"constantly\", \"on\", \"alert\", \"for\", \"predators.\", \"They\", \"traveled\", \"together,\", \"moving\", \"like\", \"a\", \"slow,\", \"armored\", \"wall\", \"across\", \"the\", \"landscape.\"], \"start_times\": [0, 0.372, 0.662, 0.871, 1.486, 1.707, 2.287, 2.426, 2.752, 2.926, 4.133, 4.319, 4.667, 5.387, 5.735, 5.921, 6.014, 6.478, 6.885, 7.187, 7.523, 7.639], \"end_times\": [0.313, 0.615, 0.789, 1.358, 1.66, 2.229, 2.368, 2.694, 2.868, 3.692, 4.284, 4.644, 5.178, 5.689, 5.886, 5.944, 6.455, 6.838, 7.129, 7.488, 7.593, 8.359]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11');
INSERT INTO `story_sections` (`id`, `story_id`, `title`, `content`, `page_number`, `elevenlabs_audio_url`, `elevenlabs_voice_id`, `audio_duration`, `word_timestamps`, `created_at`, `updated_at`) VALUES
(226, 32, 'Page 3', 'Tor, however, was impatient. He believed that strong armor and sharp horns meant they shouldn\'t have to yield to anything. When they approached thick brush, he preferred to push straight through it rather than walk around.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_3.mp3', NULL, NULL, '{\"words\": [\"Tor,\", \"however,\", \"was\", \"impatient.\", \"He\", \"believed\", \"that\", \"strong\", \"armor\", \"and\", \"sharp\", \"horns\", \"meant\", \"they\", \"shouldn\'t\", \"have\", \"to\", \"yield\", \"to\", \"anything.\", \"When\", \"they\", \"approached\", \"thick\", \"brush,\", \"he\", \"preferred\", \"to\", \"push\", \"straight\", \"through\", \"it\", \"rather\", \"than\", \"walk\", \"around.\"], \"start_times\": [0, 0.546, 1.207, 1.428, 2.682, 2.879, 3.262, 3.448, 3.878, 4.307, 4.481, 4.83, 5.492, 5.77, 5.921, 6.269, 6.49, 6.641, 6.931, 7.059, 8.127, 8.313, 8.452, 8.916, 9.183, 9.95, 10.101, 10.484, 10.588, 10.844, 11.157, 11.447, 11.598, 11.889, 12.051, 12.295], \"end_times\": [0.522, 1.115, 1.37, 2.241, 2.81, 3.228, 3.39, 3.796, 4.238, 4.4, 4.748, 5.317, 5.724, 5.886, 6.211, 6.455, 6.56, 6.885, 6.989, 7.616, 8.29, 8.417, 8.847, 9.125, 9.741, 10.031, 10.461, 10.53, 10.797, 11.122, 11.401, 11.529, 11.854, 12.005, 12.237, 12.957]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(227, 32, 'Page 4', 'One day, the herd reached a narrow pass between two steep rocky hills. The path was blocked by a massive, fallen tree trunk, older and thicker than any Tor had seen. The older Triceratops decided to turn back and find a longer, safer route.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_4.mp3', NULL, NULL, '{\"words\": [\"One\", \"day,\", \"the\", \"herd\", \"reached\", \"a\", \"narrow\", \"pass\", \"between\", \"two\", \"steep\", \"rocky\", \"hills.\", \"The\", \"path\", \"was\", \"blocked\", \"by\", \"a\", \"massive,\", \"fallen\", \"tree\", \"trunk,\", \"older\", \"and\", \"thicker\", \"than\", \"any\", \"Tor\", \"had\", \"seen.\", \"The\", \"older\", \"Triceratops\", \"decided\", \"to\", \"turn\", \"back\", \"and\", \"find\", \"a\", \"longer,\", \"safer\", \"route.\"], \"start_times\": [0, 0.453, 0.882, 1.045, 1.3, 1.614, 1.718, 2.067, 2.485, 2.844, 3.146, 3.564, 3.959, 4.899, 5.074, 5.329, 5.492, 5.886, 6.049, 6.153, 6.653, 7.036, 7.291, 8.081, 8.464, 8.603, 8.916, 9.102, 9.346, 9.625, 9.787, 10.913, 11.111, 11.389, 12.202, 12.62, 12.736, 13.003, 13.293, 13.421, 13.677, 13.769, 14.222, 14.663], \"end_times\": [0.418, 0.813, 0.987, 1.231, 1.579, 1.649, 1.997, 2.426, 2.798, 3.053, 3.448, 3.889, 4.516, 5.016, 5.294, 5.433, 5.828, 5.991, 6.072, 6.618, 6.989, 7.256, 7.802, 8.406, 8.545, 8.87, 9.044, 9.276, 9.567, 9.729, 10.31, 11.041, 11.343, 12.156, 12.585, 12.678, 12.945, 13.235, 13.375, 13.618, 13.7, 14.176, 14.582, 15.232]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(228, 32, 'Page 5', 'Tor snorted in frustration. He lowered his head, firmly planted his feet, and pushed his horns against the wood. He strained, his muscles tightening, but the massive trunk didn\'t budge an inch.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_5.mp3', NULL, NULL, '{\"words\": [\"Tor\", \"snorted\", \"in\", \"frustration.\", \"He\", \"lowered\", \"his\", \"head,\", \"firmly\", \"planted\", \"his\", \"feet,\", \"and\", \"pushed\", \"his\", \"horns\", \"against\", \"the\", \"wood.\", \"He\", \"strained,\", \"his\", \"muscles\", \"tightening,\", \"but\", \"the\", \"massive\", \"trunk\", \"didn\'t\", \"budge\", \"an\", \"inch.\"], \"start_times\": [0, 0.453, 0.871, 0.987, 2.345, 2.508, 2.775, 2.902, 3.355, 3.738, 4.098, 4.226, 4.807, 5.004, 5.306, 5.445, 5.759, 6.06, 6.165, 6.838, 7.012, 7.709, 7.883, 8.243, 9.021, 9.195, 9.334, 9.729, 10.043, 10.298, 10.553, 10.681], \"end_times\": [0.395, 0.824, 0.929, 1.741, 2.45, 2.752, 2.856, 3.239, 3.692, 4.063, 4.18, 4.632, 4.946, 5.271, 5.387, 5.724, 6.026, 6.13, 6.513, 6.943, 7.593, 7.837, 8.197, 8.847, 9.16, 9.265, 9.694, 9.985, 10.252, 10.53, 10.623, 11.238]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(229, 32, 'Page 6', 'He tried again, hitting it harder. Still, it remained solid.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_6.mp3', NULL, NULL, '{\"words\": [\"He\", \"tried\", \"again,\", \"hitting\", \"it\", \"harder.\", \"Still,\", \"it\", \"remained\", \"solid.\"], \"start_times\": [0, 0.29, 0.569, 0.871, 1.138, 1.254, 1.962, 2.38, 2.519, 2.856], \"end_times\": [0.232, 0.534, 0.836, 1.091, 1.207, 1.683, 2.357, 2.473, 2.81, 3.483]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(230, 32, 'Page 7', 'An old Ankylosaurus, covered in heavy armored plates, had been watching from the shadow of the rocks. “Strength is good,” the old dinosaur rumbled, “but some mountains do not move.”', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_7.mp3', NULL, NULL, '{\"words\": [\"An\", \"old\", \"Ankylosaurus,\", \"covered\", \"in\", \"heavy\", \"armored\", \"plates,\", \"had\", \"been\", \"watching\", \"from\", \"the\", \"shadow\", \"of\", \"the\", \"rocks.\", \"u201cStrength\", \"is\", \"good,u201d\", \"the\", \"old\", \"dinosaur\", \"rumbled,\", \"u201cbut\", \"some\", \"mountains\", \"do\", \"not\", \"move.u201d\"], \"start_times\": [0, 0.337, 0.58, 1.405, 1.718, 1.834, 2.078, 2.392, 2.937, 3.1, 3.262, 3.611, 3.762, 3.866, 4.18, 4.272, 4.389, 5.55, 6.165, 6.304, 6.78, 6.943, 7.105, 7.523, 8.104, 8.359, 8.58, 8.963, 9.114, 9.288], \"end_times\": [0.267, 0.511, 1.37, 1.695, 1.776, 2.032, 2.357, 2.879, 3.065, 3.228, 3.564, 3.727, 3.831, 4.133, 4.226, 4.342, 4.946, 6.118, 6.246, 6.699, 6.896, 7.07, 7.477, 8.022, 8.313, 8.545, 8.905, 9.044, 9.242, 9.845]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(231, 32, 'Page 8', 'Tor huffed, exhausted. He looked closely at the trunk. He noticed that the earth beneath one end of the log was loose and sandy, slowly washing away down a small slope.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_8.mp3', NULL, NULL, '{\"words\": [\"Tor\", \"huffed,\", \"exhausted.\", \"He\", \"looked\", \"closely\", \"at\", \"the\", \"trunk.\", \"He\", \"noticed\", \"that\", \"the\", \"earth\", \"beneath\", \"one\", \"end\", \"of\", \"the\", \"log\", \"was\", \"loose\", \"and\", \"sandy,\", \"slowly\", \"washing\", \"away\", \"down\", \"a\", \"small\", \"slope.\"], \"start_times\": [0, 0.406, 0.859, 1.916, 2.067, 2.322, 2.763, 2.879, 2.984, 4.005, 4.191, 4.528, 4.702, 4.83, 5.085, 5.41, 5.596, 5.77, 5.863, 5.979, 6.269, 6.467, 6.827, 7.059, 7.872, 8.278, 8.661, 8.963, 9.172, 9.253, 9.567], \"end_times\": [0.337, 0.801, 1.591, 2.02, 2.264, 2.717, 2.844, 2.949, 3.402, 4.11, 4.493, 4.667, 4.772, 5.027, 5.341, 5.561, 5.724, 5.817, 5.933, 6.211, 6.385, 6.78, 6.978, 7.628, 8.231, 8.615, 8.905, 9.137, 9.195, 9.509, 10.124]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(232, 32, 'Page 9', 'Instead of pushing against the center of the heavy wood, Tor moved to the edge. He used his horns not to push, but to dig. He loosened the earth beneath the weakened side.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_9.mp3', NULL, NULL, '{\"words\": [\"Instead\", \"of\", \"pushing\", \"against\", \"the\", \"center\", \"of\", \"the\", \"heavy\", \"wood,\", \"Tor\", \"moved\", \"to\", \"the\", \"edge.\", \"He\", \"used\", \"his\", \"horns\", \"not\", \"to\", \"push,\", \"but\", \"to\", \"dig.\", \"He\", \"loosened\", \"the\", \"earth\", \"beneath\", \"the\", \"weakened\", \"side.\"], \"start_times\": [0, 0.534, 0.662, 1.033, 1.37, 1.486, 1.846, 1.974, 2.09, 2.345, 2.833, 3.262, 3.646, 3.796, 3.936, 4.667, 4.865, 5.143, 5.294, 5.666, 5.875, 5.991, 6.548, 6.757, 6.885, 7.732, 7.93, 8.371, 8.51, 8.766, 9.079, 9.195, 9.601], \"end_times\": [0.499, 0.592, 0.975, 1.324, 1.44, 1.788, 1.916, 2.043, 2.299, 2.682, 3.181, 3.576, 3.727, 3.866, 4.284, 4.783, 5.108, 5.248, 5.596, 5.84, 5.933, 6.42, 6.722, 6.815, 7.291, 7.848, 8.313, 8.452, 8.696, 9.033, 9.149, 9.543, 10.217]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(233, 32, 'Page 10', 'Slowly, gravity did the rest. The massive log shifted, tilted, and finally rolled down the slope, clearing the path.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_10.mp3', NULL, NULL, '{\"words\": [\"Slowly,\", \"gravity\", \"did\", \"the\", \"rest.\", \"The\", \"massive\", \"log\", \"shifted,\", \"tilted,\", \"and\", \"finally\", \"rolled\", \"down\", \"the\", \"slope,\", \"clearing\", \"the\", \"path.\"], \"start_times\": [0, 0.639, 1.045, 1.207, 1.324, 2.055, 2.229, 2.601, 2.856, 3.286, 3.704, 3.855, 4.284, 4.586, 4.795, 4.911, 5.457, 5.828, 5.933], \"end_times\": [0.604, 0.998, 1.173, 1.277, 1.73, 2.171, 2.566, 2.786, 3.262, 3.68, 3.785, 4.214, 4.551, 4.76, 4.865, 5.306, 5.782, 5.898, 6.594]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(234, 32, 'Page 11', 'Tor realized that raw strength was rarely enough on its own. It was knowing where to apply it that truly moved mountains.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_32_page_11.mp3', NULL, NULL, '{\"words\": [\"Tor\", \"realized\", \"that\", \"raw\", \"strength\", \"was\", \"rarely\", \"enough\", \"on\", \"its\", \"own.\", \"It\", \"was\", \"knowing\", \"where\", \"to\", \"apply\", \"it\", \"that\", \"truly\", \"moved\", \"mountains.\"], \"start_times\": [0, 0.383, 0.789, 0.975, 1.219, 1.567, 1.765, 2.194, 2.485, 2.601, 2.763, 3.448, 3.611, 3.785, 4.098, 4.284, 4.4, 4.748, 4.853, 5.016, 5.433, 5.712], \"end_times\": [0.325, 0.755, 0.906, 1.149, 1.521, 1.672, 2.136, 2.438, 2.554, 2.717, 3.065, 3.564, 3.715, 4.052, 4.249, 4.331, 4.679, 4.818, 4.981, 5.375, 5.666, 6.409]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(235, 33, 'Page 1', 'In a lush forest filled with giant cycads and thick tree trunks lived a Stegosaurus named Luma. The plates along her back glowed faintly in the early morning light, shifting color with the warmth of the sun.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"a\", \"lush\", \"forest\", \"filled\", \"with\", \"giant\", \"cycads\", \"and\", \"thick\", \"tree\", \"trunks\", \"lived\", \"a\", \"Stegosaurus\", \"named\", \"Luma.\", \"The\", \"plates\", \"along\", \"her\", \"back\", \"glowed\", \"faintly\", \"in\", \"the\", \"early\", \"morning\", \"light,\", \"shifting\", \"color\", \"with\", \"the\", \"warmth\", \"of\", \"the\", \"sun.\"], \"start_times\": [0, 0.29, 0.372, 0.65, 1.068, 1.324, 1.509, 1.881, 2.473, 2.624, 2.868, 3.111, 3.518, 3.75, 3.808, 4.493, 4.76, 6.293, 6.444, 6.734, 6.989, 7.117, 7.384, 7.709, 8.081, 8.185, 8.313, 8.58, 8.893, 9.671, 10.101, 10.437, 10.6, 10.716, 11.076, 11.204, 11.331], \"end_times\": [0.244, 0.313, 0.592, 1.01, 1.3, 1.451, 1.834, 2.438, 2.566, 2.821, 3.077, 3.448, 3.727, 3.773, 4.423, 4.702, 5.341, 6.397, 6.699, 6.931, 7.059, 7.326, 7.651, 8.034, 8.139, 8.255, 8.522, 8.835, 9.346, 10.043, 10.379, 10.565, 10.67, 11.029, 11.146, 11.273, 11.935]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(236, 33, 'Page 2', 'Stegosauruses were not known for deep thinking. They focused on the present moment: eating, moving, and staying safe. But Luma was different. She noticed patterns.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_2.mp3', NULL, NULL, '{\"words\": [\"Stegosauruses\", \"were\", \"not\", \"known\", \"for\", \"deep\", \"thinking.\", \"They\", \"focused\", \"on\", \"the\", \"present\", \"moment:\", \"eating,\", \"moving,\", \"and\", \"staying\", \"safe.\", \"But\", \"Luma\", \"was\", \"different.\", \"She\", \"noticed\", \"patterns.\"], \"start_times\": [0, 0.94, 1.103, 1.3, 1.544, 1.707, 1.939, 2.949, 3.181, 3.622, 3.727, 3.831, 4.18, 4.957, 5.642, 6.118, 6.316, 6.687, 7.454, 7.663, 8.022, 8.208, 8.975, 9.195, 9.578], \"end_times\": [0.894, 1.057, 1.254, 1.498, 1.649, 1.881, 2.508, 3.111, 3.587, 3.692, 3.796, 4.133, 4.632, 5.433, 6.095, 6.258, 6.618, 7.129, 7.616, 7.976, 8.139, 8.766, 9.114, 9.52, 10.356]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(237, 33, 'Page 3', 'She remembered that when the small silver birds flew south in large numbers, a cold front always followed shortly after. She noticed that certain flowers closed tightly just hours before a heavy rain.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_3.mp3', NULL, NULL, '{\"words\": [\"She\", \"remembered\", \"that\", \"when\", \"the\", \"small\", \"silver\", \"birds\", \"flew\", \"south\", \"in\", \"large\", \"numbers,\", \"a\", \"cold\", \"front\", \"always\", \"followed\", \"shortly\", \"after.\", \"She\", \"noticed\", \"that\", \"certain\", \"flowers\", \"closed\", \"tightly\", \"just\", \"hours\", \"before\", \"a\", \"heavy\", \"rain.\"], \"start_times\": [0, 0.337, 0.778, 0.917, 1.068, 1.196, 1.602, 1.95, 2.334, 2.624, 2.995, 3.135, 3.46, 4.18, 4.342, 4.679, 5.004, 5.341, 5.724, 6.095, 7.163, 7.372, 7.721, 7.883, 8.197, 8.707, 9.091, 9.543, 9.81, 10.217, 10.542, 10.623, 10.902], \"end_times\": [0.267, 0.743, 0.894, 1.033, 1.138, 1.521, 1.904, 2.276, 2.554, 2.937, 3.065, 3.402, 4.029, 4.249, 4.609, 4.946, 5.283, 5.689, 6.037, 6.653, 7.291, 7.697, 7.837, 8.139, 8.638, 9.056, 9.451, 9.741, 10.147, 10.507, 10.565, 10.82, 11.471]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(238, 33, 'Page 4', 'The other dinosaurs in her herd ignored her observations. They continued grazing peacefully, unconcerned with what might happen tomorrow.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_4.mp3', NULL, NULL, '{\"words\": [\"The\", \"other\", \"dinosaurs\", \"in\", \"her\", \"herd\", \"ignored\", \"her\", \"observations.\", \"They\", \"continued\", \"grazing\", \"peacefully,\", \"unconcerned\", \"with\", \"what\", \"might\", \"happen\", \"tomorrow.\"], \"start_times\": [0, 0.337, 0.557, 1.091, 1.207, 1.358, 1.614, 2.043, 2.194, 3.425, 3.634, 4.18, 4.644, 5.573, 6.327, 6.49, 6.676, 6.896, 7.221], \"end_times\": [0.267, 0.511, 1.057, 1.149, 1.289, 1.556, 1.997, 2.125, 3.1, 3.599, 4.133, 4.574, 5.364, 6.293, 6.455, 6.629, 6.85, 7.175, 8.266]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(239, 33, 'Page 5', 'One particularly warm afternoon, Luma noticed the air felt unusually still. The insects had stopped buzzing. The silver birds were suddenly flying away from the mountain in the distance, not waiting for their usual migration time.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_5.mp3', NULL, NULL, '{\"words\": [\"One\", \"particularly\", \"warm\", \"afternoon,\", \"Luma\", \"noticed\", \"the\", \"air\", \"felt\", \"unusually\", \"still.\", \"The\", \"insects\", \"had\", \"stopped\", \"buzzing.\", \"The\", \"silver\", \"birds\", \"were\", \"suddenly\", \"flying\", \"away\", \"from\", \"the\", \"mountain\", \"in\", \"the\", \"distance,\", \"not\", \"waiting\", \"for\", \"their\", \"usual\", \"migration\", \"time.\"], \"start_times\": [0, 0.441, 1.126, 1.405, 2.38, 2.717, 3.111, 3.251, 3.518, 3.855, 4.586, 5.619, 5.828, 6.293, 6.467, 6.827, 7.709, 7.895, 8.243, 8.533, 8.684, 9.067, 9.52, 9.764, 9.95, 10.066, 10.379, 10.472, 10.577, 11.436, 11.691, 12.028, 12.167, 12.388, 12.794, 13.363], \"end_times\": [0.395, 1.08, 1.347, 2.101, 2.659, 3.077, 3.193, 3.448, 3.773, 4.505, 5.178, 5.747, 6.258, 6.409, 6.78, 7.384, 7.837, 8.197, 8.499, 8.661, 8.998, 9.462, 9.718, 9.903, 10.019, 10.333, 10.437, 10.542, 11.227, 11.633, 11.981, 12.132, 12.318, 12.713, 13.305, 13.886]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(240, 33, 'Page 6', 'Luma felt a deep unease. She began walking away from the mountain, toward the safety of the wide, flat plains. She nudged her friends to follow, but they grumbled and went back to eating ferns.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_6.mp3', NULL, NULL, '{\"words\": [\"Luma\", \"felt\", \"a\", \"deep\", \"unease.\", \"She\", \"began\", \"walking\", \"away\", \"from\", \"the\", \"mountain,\", \"toward\", \"the\", \"safety\", \"of\", \"the\", \"wide,\", \"flat\", \"plains.\", \"She\", \"nudged\", \"her\", \"friends\", \"to\", \"follow,\", \"but\", \"they\", \"grumbled\", \"and\", \"went\", \"back\", \"to\", \"eating\", \"ferns.\"], \"start_times\": [0, 0.499, 0.755, 0.848, 1.138, 2.02, 2.206, 2.543, 2.902, 3.135, 3.309, 3.413, 4.133, 4.447, 4.563, 5.004, 5.108, 5.248, 5.712, 6.084, 7.21, 7.419, 7.755, 7.883, 8.197, 8.336, 8.893, 9.079, 9.253, 9.706, 9.822, 10.019, 10.24, 10.356, 10.646], \"end_times\": [0.441, 0.708, 0.778, 1.057, 1.741, 2.148, 2.473, 2.844, 3.088, 3.262, 3.379, 3.959, 4.412, 4.516, 4.946, 5.062, 5.178, 5.677, 6.002, 6.769, 7.349, 7.709, 7.837, 8.15, 8.255, 8.812, 9.044, 9.195, 9.671, 9.776, 9.973, 10.194, 10.298, 10.588, 11.61]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(241, 33, 'Page 7', 'Luma didn\'t stop. She moved to the edge of the forest and bellowed a warning, loudly and persistently. The noise irritated the herd enough that a few began moving toward her just to stop the racket.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_7.mp3', NULL, NULL, '{\"words\": [\"Luma\", \"didn\'t\", \"stop.\", \"She\", \"moved\", \"to\", \"the\", \"edge\", \"of\", \"the\", \"forest\", \"and\", \"bellowed\", \"a\", \"warning,\", \"loudly\", \"and\", \"persistently.\", \"The\", \"noise\", \"irritated\", \"the\", \"herd\", \"enough\", \"that\", \"a\", \"few\", \"began\", \"moving\", \"toward\", \"her\", \"just\", \"to\", \"stop\", \"the\", \"racket.\"], \"start_times\": [0, 0.453, 0.72, 1.707, 1.916, 2.183, 2.287, 2.426, 2.612, 2.705, 2.833, 3.228, 3.39, 3.715, 3.796, 4.423, 4.865, 4.992, 6.177, 6.374, 6.803, 7.361, 7.477, 7.755, 8.092, 8.266, 8.359, 8.661, 8.975, 9.288, 9.601, 10.031, 10.333, 10.449, 10.751, 10.879], \"end_times\": [0.406, 0.685, 1.265, 1.846, 2.159, 2.229, 2.357, 2.589, 2.659, 2.775, 3.181, 3.32, 3.692, 3.75, 4.296, 4.818, 4.934, 5.793, 6.293, 6.745, 7.326, 7.43, 7.709, 8.046, 8.231, 8.301, 8.58, 8.916, 9.23, 9.555, 9.752, 10.298, 10.391, 10.693, 10.82, 11.564]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(242, 33, 'Page 8', 'Moments later, a deep rumble echoed through the ground. The mountain wasn’t just a mountain; it was a volcano. A thick plume of dark ash shot into the sky, and tremor shook the earth.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_8.mp3', NULL, NULL, '{\"words\": [\"Moments\", \"later,\", \"a\", \"deep\", \"rumble\", \"echoed\", \"through\", \"the\", \"ground.\", \"The\", \"mountain\", \"wasnu2019t\", \"just\", \"a\", \"mountain;\", \"it\", \"was\", \"a\", \"volcano.\", \"A\", \"thick\", \"plume\", \"of\", \"dark\", \"ash\", \"shot\", \"into\", \"the\", \"sky,\", \"and\", \"tremor\", \"shook\", \"the\", \"earth.\"], \"start_times\": [0, 0.569, 1.033, 1.184, 1.474, 1.881, 2.264, 2.496, 2.601, 3.425, 3.587, 3.889, 4.191, 4.423, 4.493, 4.969, 5.12, 5.271, 5.352, 6.316, 6.478, 6.757, 7.198, 7.349, 7.697, 8.057, 8.371, 8.591, 8.696, 9.137, 9.334, 9.729, 10.008, 10.147], \"end_times\": [0.522, 0.975, 1.103, 1.382, 1.823, 2.229, 2.473, 2.566, 3.1, 3.541, 3.843, 4.145, 4.377, 4.447, 4.888, 5.085, 5.224, 5.294, 6.107, 6.397, 6.687, 7.163, 7.268, 7.616, 7.999, 8.324, 8.522, 8.661, 9.102, 9.276, 9.671, 9.95, 10.089, 10.681]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(243, 33, 'Page 9', 'Panic erupted in the forest. The herd followed Luma’s lead, abandoning the lush ferns and rushing toward the open plain before the ash cloud descended.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_9.mp3', NULL, NULL, '{\"words\": [\"Panic\", \"erupted\", \"in\", \"the\", \"forest.\", \"The\", \"herd\", \"followed\", \"Lumau2019s\", \"lead,\", \"abandoning\", \"the\", \"lush\", \"ferns\", \"and\", \"rushing\", \"toward\", \"the\", \"open\", \"plain\", \"before\", \"the\", \"ash\", \"cloud\", \"descended.\"], \"start_times\": [0, 0.546, 1.033, 1.126, 1.242, 2.194, 2.368, 2.647, 2.984, 3.355, 3.936, 4.609, 4.725, 5.016, 5.619, 5.851, 6.211, 6.455, 6.594, 6.92, 7.268, 7.558, 7.697, 7.976, 8.255], \"end_times\": [0.476, 0.987, 1.091, 1.196, 1.869, 2.31, 2.589, 2.949, 3.297, 3.762, 4.551, 4.679, 4.946, 5.468, 5.77, 6.153, 6.432, 6.525, 6.85, 7.198, 7.523, 7.628, 7.93, 8.22, 8.963]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(244, 33, 'Page 10', 'They survived because Luma had understood that the present was always connected to what came next. She couldn\'t see the future, but she could read the world\'s warnings.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_33_page_10.mp3', NULL, NULL, '{\"words\": [\"They\", \"survived\", \"because\", \"Luma\", \"had\", \"understood\", \"that\", \"the\", \"present\", \"was\", \"always\", \"connected\", \"to\", \"what\", \"came\", \"next.\", \"She\", \"couldn\'t\", \"see\", \"the\", \"future,\", \"but\", \"she\", \"could\", \"read\", \"the\", \"world\'s\", \"warnings.\"], \"start_times\": [0, 0.337, 0.964, 1.324, 1.672, 1.858, 2.554, 2.752, 2.868, 3.274, 3.46, 3.878, 4.319, 4.412, 4.586, 4.83, 6.014, 6.188, 6.49, 6.664, 6.792, 7.372, 7.581, 7.732, 7.93, 8.127, 8.231, 8.545], \"end_times\": [0.29, 0.894, 1.277, 1.614, 1.788, 2.473, 2.717, 2.821, 3.228, 3.39, 3.82, 4.284, 4.365, 4.54, 4.783, 5.41, 6.142, 6.455, 6.629, 6.734, 7.303, 7.535, 7.674, 7.872, 8.092, 8.197, 8.51, 9.334]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(245, 34, 'Page 1', 'High above the ancient cliffs soared a young Pterosaur named Arin. His wings were long and powerful, built for gliding across enormous distances.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_1.mp3', NULL, NULL, '{\"words\": [\"High\", \"above\", \"the\", \"ancient\", \"cliffs\", \"soared\", \"a\", \"young\", \"Pterosaur\", \"named\", \"Arin.\", \"His\", \"wings\", \"were\", \"long\", \"and\", \"powerful,\", \"built\", \"for\", \"gliding\", \"across\", \"enormous\", \"distances.\"], \"start_times\": [0, 0.383, 0.639, 0.778, 1.126, 1.498, 1.858, 1.939, 2.194, 2.937, 3.262, 4.145, 4.365, 4.667, 4.841, 5.248, 5.468, 6.188, 6.49, 6.653, 7.059, 7.419, 7.872], \"end_times\": [0.348, 0.615, 0.708, 1.08, 1.451, 1.823, 1.881, 2.125, 2.821, 3.204, 3.704, 4.307, 4.632, 4.795, 5.166, 5.399, 6.107, 6.444, 6.606, 7.012, 7.361, 7.825, 8.824]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(246, 34, 'Page 2', 'But Arin preferred to stay close to the rocks. He didn\'t like the strong, unpredictable currents higher up. While the older Pterosaurs rode the thermal winds, spiraling up toward the clouds, Arin fluttered cautiously near the cliff edge, afraid a sudden gust would throw him off balance completely.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_2.mp3', NULL, NULL, '{\"words\": [\"But\", \"Arin\", \"preferred\", \"to\", \"stay\", \"close\", \"to\", \"the\", \"rocks.\", \"He\", \"didn\'t\", \"like\", \"the\", \"strong,\", \"unpredictable\", \"currents\", \"higher\", \"up.\", \"While\", \"the\", \"older\", \"Pterosaurs\", \"rode\", \"the\", \"thermal\", \"winds,\", \"spiraling\", \"up\", \"toward\", \"the\", \"clouds,\", \"Arin\", \"fluttered\", \"cautiously\", \"near\", \"the\", \"cliff\", \"edge,\", \"afraid\", \"a\", \"sudden\", \"gust\", \"would\", \"throw\", \"him\", \"off\", \"balance\", \"completely.\"], \"start_times\": [0, 0.313, 0.58, 0.987, 1.091, 1.324, 1.591, 1.683, 1.8, 2.995, 3.17, 3.448, 3.68, 3.796, 4.272, 4.946, 5.433, 5.793, 7.117, 7.349, 7.477, 7.779, 8.452, 8.696, 8.812, 9.207, 9.81, 10.437, 10.6, 10.855, 10.96, 11.947, 12.318, 12.725, 13.293, 13.468, 13.584, 13.886, 14.524, 14.907, 14.977, 15.302, 15.615, 15.778, 16.022, 16.173, 16.358, 16.753], \"end_times\": [0.267, 0.522, 0.952, 1.033, 1.265, 1.567, 1.637, 1.753, 2.392, 3.111, 3.413, 3.646, 3.75, 4.226, 4.911, 5.364, 5.724, 6.165, 7.326, 7.419, 7.721, 8.382, 8.673, 8.766, 9.137, 9.718, 10.379, 10.542, 10.82, 10.925, 11.703, 12.237, 12.666, 13.235, 13.433, 13.537, 13.816, 14.315, 14.872, 14.93, 15.244, 15.569, 15.755, 15.964, 16.115, 16.289, 16.718, 17.601]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(247, 34, 'Page 3', 'One late afternoon, a sudden thermal draft caught him. Before he could maneuver back to the rocks, he was pulled high into the open sky.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_3.mp3', NULL, NULL, '{\"words\": [\"One\", \"late\", \"afternoon,\", \"a\", \"sudden\", \"thermal\", \"draft\", \"caught\", \"him.\", \"Before\", \"he\", \"could\", \"maneuver\", \"back\", \"to\", \"the\", \"rocks,\", \"he\", \"was\", \"pulled\", \"high\", \"into\", \"the\", \"open\", \"sky.\"], \"start_times\": [0, 0.441, 0.673, 1.335, 1.474, 1.834, 2.206, 2.566, 2.833, 3.437, 3.82, 3.924, 4.11, 4.516, 4.748, 4.865, 4.981, 5.573, 5.7, 5.875, 6.188, 6.478, 6.676, 6.815, 7.14], \"end_times\": [0.395, 0.639, 1.289, 1.393, 1.776, 2.159, 2.508, 2.798, 3.111, 3.773, 3.878, 4.063, 4.447, 4.702, 4.807, 4.934, 5.492, 5.654, 5.805, 6.142, 6.432, 6.618, 6.745, 7.07, 7.802]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(248, 34, 'Page 4', 'Panic seized him. The wind roared clearly in his ears, pulling him higher and higher. The ground below became a distant blur of green and brown.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_4.mp3', NULL, NULL, '{\"words\": [\"Panic\", \"seized\", \"him.\", \"The\", \"wind\", \"roared\", \"clearly\", \"in\", \"his\", \"ears,\", \"pulling\", \"him\", \"higher\", \"and\", \"higher.\", \"The\", \"ground\", \"below\", \"became\", \"a\", \"distant\", \"blur\", \"of\", \"green\", \"and\", \"brown.\"], \"start_times\": [0, 0.557, 0.917, 1.486, 1.683, 2.09, 2.519, 2.937, 3.042, 3.204, 3.576, 3.924, 4.098, 4.505, 4.667, 5.445, 5.619, 5.921, 6.293, 6.618, 6.711, 7.105, 7.43, 7.558, 7.872, 7.999], \"end_times\": [0.488, 0.871, 1.207, 1.625, 1.974, 2.45, 2.891, 2.995, 3.146, 3.529, 3.878, 4.017, 4.447, 4.598, 5.166, 5.561, 5.875, 6.211, 6.583, 6.641, 7.059, 7.372, 7.488, 7.837, 7.953, 8.591]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(249, 34, 'Page 5', 'He fought against the current, flapping frantically, trying to force his way down. But the harder he fought the wind, the more exhausted he became.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_5.mp3', NULL, NULL, '{\"words\": [\"He\", \"fought\", \"against\", \"the\", \"current,\", \"flapping\", \"frantically,\", \"trying\", \"to\", \"force\", \"his\", \"way\", \"down.\", \"But\", \"the\", \"harder\", \"he\", \"fought\", \"the\", \"wind,\", \"the\", \"more\", \"exhausted\", \"he\", \"became.\"], \"start_times\": [0, 0.325, 0.58, 0.882, 0.987, 1.556, 2.02, 2.81, 3.181, 3.297, 3.564, 3.704, 3.889, 4.783, 4.969, 5.097, 5.41, 5.538, 5.793, 5.909, 6.409, 6.56, 6.745, 7.245, 7.361], \"end_times\": [0.255, 0.546, 0.848, 0.952, 1.44, 1.95, 2.694, 3.135, 3.228, 3.541, 3.657, 3.831, 4.342, 4.934, 5.039, 5.364, 5.468, 5.759, 5.863, 6.293, 6.513, 6.711, 7.21, 7.303, 8.034]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(250, 34, 'Page 6', 'He was losing strength.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_6.mp3', NULL, NULL, '{\"words\": [\"He\", \"was\", \"losing\", \"strength.\"], \"start_times\": [0, 0.29, 0.453, 0.778], \"end_times\": [0.244, 0.395, 0.72, 1.393]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(251, 34, 'Page 7', 'Then, he remembered watching a drifting feather one day. The feather never fought the wind. It simply angled itself and rode the invisible waves.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_7.mp3', NULL, NULL, '{\"words\": [\"Then,\", \"he\", \"remembered\", \"watching\", \"a\", \"drifting\", \"feather\", \"one\", \"day.\", \"The\", \"feather\", \"never\", \"fought\", \"the\", \"wind.\", \"It\", \"simply\", \"angled\", \"itself\", \"and\", \"rode\", \"the\", \"invisible\", \"waves.\"], \"start_times\": [0, 0.337, 0.464, 0.848, 1.207, 1.277, 1.707, 2.067, 2.252, 2.798, 2.972, 3.251, 3.506, 3.762, 3.878, 4.516, 4.69, 5.027, 5.375, 5.759, 5.944, 6.211, 6.327, 6.815], \"end_times\": [0.313, 0.395, 0.813, 1.161, 1.231, 1.637, 1.997, 2.218, 2.624, 2.926, 3.204, 3.448, 3.727, 3.831, 4.272, 4.656, 4.957, 5.341, 5.7, 5.875, 6.177, 6.281, 6.78, 7.523]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(252, 34, 'Page 8', 'Arin stopped flapping wildly. He took a deep breath, extended his wings fully, and locked them in place. He stopped fighting the upward draft and instead tilted his wingtips slightly, allowing the air to flow smoothly over him.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_8.mp3', NULL, NULL, '{\"words\": [\"Arin\", \"stopped\", \"flapping\", \"wildly.\", \"He\", \"took\", \"a\", \"deep\", \"breath,\", \"extended\", \"his\", \"wings\", \"fully,\", \"and\", \"locked\", \"them\", \"in\", \"place.\", \"He\", \"stopped\", \"fighting\", \"the\", \"upward\", \"draft\", \"and\", \"instead\", \"tilted\", \"his\", \"wingtips\", \"slightly,\", \"allowing\", \"the\", \"air\", \"to\", \"flow\", \"smoothly\", \"over\", \"him.\"], \"start_times\": [0, 0.476, 0.778, 1.219, 2.194, 2.357, 2.566, 2.647, 2.902, 3.518, 4.063, 4.214, 4.516, 5.074, 5.294, 5.596, 5.759, 5.875, 6.78, 6.943, 7.245, 7.546, 7.674, 7.976, 8.522, 8.777, 9.137, 9.509, 9.648, 10.112, 10.728, 11.215, 11.355, 11.587, 11.703, 11.97, 12.446, 12.701], \"end_times\": [0.418, 0.743, 1.149, 1.869, 2.299, 2.519, 2.589, 2.833, 3.344, 4.017, 4.156, 4.458, 4.957, 5.224, 5.55, 5.712, 5.817, 6.397, 6.885, 7.198, 7.512, 7.616, 7.953, 8.394, 8.719, 9.091, 9.462, 9.601, 10.089, 10.67, 11.169, 11.296, 11.529, 11.645, 11.9, 12.388, 12.632, 13.142]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(253, 34, 'Page 9', 'The chaotic tossing stopped immediately. He was gliding.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_9.mp3', NULL, NULL, '{\"words\": [\"The\", \"chaotic\", \"tossing\", \"stopped\", \"immediately.\", \"He\", \"was\", \"gliding.\"], \"start_times\": [0, 0.267, 0.673, 1.068, 1.358, 1.904, 2.032, 2.183], \"end_times\": [0.221, 0.627, 1.022, 1.335, 1.858, 1.985, 2.136, 2.879]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(254, 34, 'Page 10', 'The wind was no longer an enemy trying to bring him down; it was a force holding him up. He leaned gently, navigating the currents with subtle shifts in weight rather than brute strength.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_10.mp3', NULL, NULL, '{\"words\": [\"The\", \"wind\", \"was\", \"no\", \"longer\", \"an\", \"enemy\", \"trying\", \"to\", \"bring\", \"him\", \"down;\", \"it\", \"was\", \"a\", \"force\", \"holding\", \"him\", \"up.\", \"He\", \"leaned\", \"gently,\", \"navigating\", \"the\", \"currents\", \"with\", \"subtle\", \"shifts\", \"in\", \"weight\", \"rather\", \"than\", \"brute\", \"strength.\"], \"start_times\": [0, 0.29, 0.557, 0.731, 0.917, 1.277, 1.428, 1.788, 2.09, 2.183, 2.403, 2.554, 3.286, 3.437, 3.576, 3.669, 4.04, 4.412, 4.563, 5.259, 5.468, 5.805, 6.293, 6.885, 6.989, 7.407, 7.593, 7.918, 8.243, 8.406, 8.742, 9.044, 9.265, 9.636], \"end_times\": [0.232, 0.499, 0.673, 0.836, 1.219, 1.358, 1.73, 2.043, 2.136, 2.357, 2.496, 2.961, 3.402, 3.529, 3.599, 3.994, 4.354, 4.505, 4.818, 5.387, 5.747, 6.235, 6.838, 6.954, 7.361, 7.535, 7.883, 8.197, 8.324, 8.673, 8.998, 9.183, 9.578, 10.356]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(255, 34, 'Page 11', 'When he finally circled back down to the cliffs, he wasn\'t trembling with fear. He felt the rush of true flight.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_34_page_11.mp3', NULL, NULL, '{\"words\": [\"When\", \"he\", \"finally\", \"circled\", \"back\", \"down\", \"to\", \"the\", \"cliffs,\", \"he\", \"wasn\'t\", \"trembling\", \"with\", \"fear.\", \"He\", \"felt\", \"the\", \"rush\", \"of\", \"true\", \"flight.\"], \"start_times\": [0, 0.313, 0.43, 0.824, 1.207, 1.44, 1.66, 1.776, 1.881, 2.276, 2.403, 2.705, 3.158, 3.332, 4.238, 4.4, 4.609, 4.748, 5.004, 5.12, 5.422], \"end_times\": [0.279, 0.36, 0.766, 1.161, 1.382, 1.625, 1.718, 1.846, 2.252, 2.345, 2.67, 3.123, 3.274, 3.727, 4.342, 4.574, 4.679, 4.957, 5.062, 5.375, 6.084]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(256, 35, 'Page 1', 'In a land of wide plains and scattered forests lived a young Ankylosaurus named Brak. His body was covered in thick armor plates, and his heavy tail ended in a powerful club of bone. From the outside, he looked unbreakable.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"a\", \"land\", \"of\", \"wide\", \"plains\", \"and\", \"scattered\", \"forests\", \"lived\", \"a\", \"young\", \"Ankylosaurus\", \"named\", \"Brak.\", \"His\", \"body\", \"was\", \"covered\", \"in\", \"thick\", \"armor\", \"plates,\", \"and\", \"his\", \"heavy\", \"tail\", \"ended\", \"in\", \"a\", \"powerful\", \"club\", \"of\", \"bone.\", \"From\", \"the\", \"outside,\", \"he\", \"looked\", \"unbreakable.\"], \"start_times\": [0, 0.29, 0.372, 0.673, 0.813, 1.138, 1.509, 1.625, 2.032, 2.589, 2.81, 2.902, 3.146, 3.901, 4.191, 5.306, 5.526, 5.805, 5.956, 6.304, 6.42, 6.676, 7.001, 7.465, 7.651, 7.79, 8.057, 8.371, 8.719, 8.824, 8.905, 9.381, 9.659, 9.799, 10.925, 11.146, 11.273, 12.04, 12.167, 12.399], \"end_times\": [0.244, 0.313, 0.615, 0.731, 1.103, 1.463, 1.579, 1.985, 2.531, 2.786, 2.833, 3.088, 3.843, 4.133, 4.702, 5.468, 5.759, 5.898, 6.269, 6.362, 6.618, 6.954, 7.43, 7.605, 7.732, 7.999, 8.29, 8.673, 8.789, 8.858, 9.323, 9.613, 9.718, 10.321, 11.099, 11.215, 11.912, 12.109, 12.365, 13.235]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(257, 35, 'Page 2', 'But inside, Brak was unsure. He knew he was slow. He knew he wasn\'t agile like the raptors or towering like the long-necks. If danger came, he couldn\'t outrun it.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_2.mp3', NULL, NULL, '{\"words\": [\"But\", \"inside,\", \"Brak\", \"was\", \"unsure.\", \"He\", \"knew\", \"he\", \"was\", \"slow.\", \"He\", \"knew\", \"he\", \"wasn\'t\", \"agile\", \"like\", \"the\", \"raptors\", \"or\", \"towering\", \"like\", \"the\", \"long-necks.\", \"If\", \"danger\", \"came,\", \"he\", \"couldn\'t\", \"outrun\", \"it.\"], \"start_times\": [0, 0.302, 1.161, 1.463, 1.625, 2.601, 2.763, 2.972, 3.077, 3.251, 4.191, 4.365, 4.586, 4.714, 5.016, 5.503, 5.677, 5.805, 6.339, 6.525, 7.059, 7.233, 7.361, 8.533, 8.731, 9.102, 9.868, 9.996, 10.298, 10.658], \"end_times\": [0.267, 0.952, 1.405, 1.556, 2.276, 2.717, 2.914, 3.019, 3.193, 3.866, 4.307, 4.528, 4.644, 4.957, 5.468, 5.642, 5.747, 6.281, 6.455, 7.012, 7.198, 7.303, 8.15, 8.673, 9.044, 9.59, 9.938, 10.263, 10.6, 11.053]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(258, 35, 'Page 3', 'He often hid when he heard heavy footsteps approaching, preferring to stay out of sight rather than rely on his armor.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_3.mp3', NULL, NULL, '{\"words\": [\"He\", \"often\", \"hid\", \"when\", \"he\", \"heard\", \"heavy\", \"footsteps\", \"approaching,\", \"preferring\", \"to\", \"stay\", \"out\", \"of\", \"sight\", \"rather\", \"than\", \"rely\", \"on\", \"his\", \"armor.\"], \"start_times\": [0, 0.325, 0.65, 0.929, 1.08, 1.184, 1.428, 1.695, 2.171, 2.949, 3.413, 3.518, 3.75, 3.889, 4.017, 4.354, 4.632, 4.807, 5.155, 5.283, 5.445], \"end_times\": [0.255, 0.58, 0.882, 1.045, 1.126, 1.37, 1.637, 2.136, 2.833, 3.367, 3.46, 3.704, 3.855, 3.947, 4.307, 4.598, 4.748, 5.085, 5.236, 5.387, 6.084]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(259, 35, 'Page 4', 'One dry season, a large, aggressive predator—a wandering Allosaurus—entered their territory. It was fast and hungry, causing panic among the smaller herds.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_4.mp3', NULL, NULL, '{\"words\": [\"One\", \"dry\", \"season,\", \"a\", \"large,\", \"aggressive\", \"predatoru2014a\", \"wandering\", \"Allosaurusu2014entered\", \"their\", \"territory.\", \"It\", \"was\", \"fast\", \"and\", \"hungry,\", \"causing\", \"panic\", \"among\", \"the\", \"smaller\", \"herds.\"], \"start_times\": [0, 0.441, 0.755, 1.173, 1.289, 1.625, 2.113, 2.902, 3.413, 4.551, 4.748, 5.909, 6.06, 6.223, 6.594, 6.734, 7.198, 7.57, 7.964, 8.208, 8.313, 8.731], \"end_times\": [0.406, 0.685, 1.149, 1.219, 1.602, 2.078, 2.821, 3.344, 4.528, 4.702, 5.468, 6.026, 6.153, 6.548, 6.676, 7.163, 7.5, 7.918, 8.162, 8.278, 8.673, 9.427]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(260, 35, 'Page 5', 'Brak found himself cornered near a rocky outcrop. He had wandered too far looking for fresh roots. The Allosaurus spotted him and stepped forward, hissing, ready to test the slow creature\'s defenses.', 5, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_5.mp3', NULL, NULL, '{\"words\": [\"Brak\", \"found\", \"himself\", \"cornered\", \"near\", \"a\", \"rocky\", \"outcrop.\", \"He\", \"had\", \"wandered\", \"too\", \"far\", \"looking\", \"for\", \"fresh\", \"roots.\", \"The\", \"Allosaurus\", \"spotted\", \"him\", \"and\", \"stepped\", \"forward,\", \"hissing,\", \"ready\", \"to\", \"test\", \"the\", \"slow\", \"creature\'s\", \"defenses.\"], \"start_times\": [0, 0.453, 0.697, 1.091, 1.498, 1.718, 1.834, 2.229, 3.193, 3.332, 3.448, 3.808, 4.017, 4.319, 4.621, 4.783, 5.085, 6.014, 6.188, 6.722, 7.175, 7.338, 7.465, 7.79, 8.394, 9.102, 9.381, 9.52, 9.857, 9.973, 10.286, 10.728], \"end_times\": [0.395, 0.65, 1.022, 1.463, 1.66, 1.741, 2.159, 2.868, 3.297, 3.402, 3.785, 3.947, 4.238, 4.563, 4.725, 5.027, 5.631, 6.118, 6.676, 7.129, 7.291, 7.407, 7.744, 8.278, 8.928, 9.334, 9.451, 9.799, 9.938, 10.217, 10.681, 11.61]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(261, 35, 'Page 6', 'Brak’s first instinct was to run, but his legs were too short to escape. His heart hammered in his chest.', 6, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_6.mp3', NULL, NULL, '{\"words\": [\"Braku2019s\", \"first\", \"instinct\", \"was\", \"to\", \"run,\", \"but\", \"his\", \"legs\", \"were\", \"too\", \"short\", \"to\", \"escape.\", \"His\", \"heart\", \"hammered\", \"in\", \"his\", \"chest.\"], \"start_times\": [0, 0.441, 0.72, 1.103, 1.265, 1.405, 1.8, 1.974, 2.125, 2.357, 2.496, 2.67, 2.937, 3.077, 4.04, 4.238, 4.493, 4.865, 4.957, 5.097], \"end_times\": [0.406, 0.673, 1.068, 1.207, 1.324, 1.741, 1.939, 2.067, 2.322, 2.473, 2.624, 2.902, 2.995, 3.599, 4.191, 4.435, 4.83, 4.923, 5.05, 5.805]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(262, 35, 'Page 7', 'He remembered the shape of the stones around him—solid, unshakable, immovable.', 7, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_7.mp3', NULL, NULL, '{\"words\": [\"He\", \"remembered\", \"the\", \"shape\", \"of\", \"the\", \"stones\", \"around\", \"himu2014solid,\", \"unshakable,\", \"immovable.\"], \"start_times\": [0, 0.337, 0.778, 0.882, 1.161, 1.265, 1.37, 1.753, 2.136, 2.926, 3.692], \"end_times\": [0.267, 0.743, 0.848, 1.126, 1.219, 1.335, 1.718, 2.078, 2.891, 3.657, 4.551]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(263, 35, 'Page 8', 'He didn\'t run. He lowered his body, pressing his armored back firmly toward the predator, and planted his feet solid in the dirt. He swung his heavy tail slightly, just enough to show its weight.', 8, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_8.mp3', NULL, NULL, '{\"words\": [\"He\", \"didn\'t\", \"run.\", \"He\", \"lowered\", \"his\", \"body,\", \"pressing\", \"his\", \"armored\", \"back\", \"firmly\", \"toward\", \"the\", \"predator,\", \"and\", \"planted\", \"his\", \"feet\", \"solid\", \"in\", \"the\", \"dirt.\", \"He\", \"swung\", \"his\", \"heavy\", \"tail\", \"slightly,\", \"just\", \"enough\", \"to\", \"show\", \"its\", \"weight.\"], \"start_times\": [0, 0.302, 0.639, 1.486, 1.683, 2.043, 2.194, 2.798, 3.239, 3.402, 3.808, 4.145, 4.609, 4.888, 4.992, 5.712, 5.921, 6.327, 6.502, 6.838, 7.291, 7.396, 7.5, 8.243, 8.44, 8.812, 8.986, 9.265, 9.543, 10.298, 10.612, 10.902, 11.041, 11.285, 11.459], \"end_times\": [0.244, 0.569, 1.103, 1.602, 2.009, 2.136, 2.67, 3.181, 3.344, 3.762, 4.029, 4.551, 4.853, 4.957, 5.561, 5.863, 6.293, 6.432, 6.745, 7.245, 7.349, 7.465, 7.918, 8.359, 8.742, 8.916, 9.207, 9.485, 10.147, 10.553, 10.855, 10.971, 11.227, 11.401, 11.981]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(264, 35, 'Page 9', 'The Allosaurus lunged. Brak didn\'t flinch. The predator\'s teeth scraped harmlessly against his thick, bony plates. Frustrated, the Allosaurus circled, looking for a weak spot, but Brak simply rotated slowly, keeping his armored side exposed and his club ready.', 9, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_9.mp3', NULL, NULL, '{\"words\": [\"The\", \"Allosaurus\", \"lunged.\", \"Brak\", \"didn\'t\", \"flinch.\", \"The\", \"predator\'s\", \"teeth\", \"scraped\", \"harmlessly\", \"against\", \"his\", \"thick,\", \"bony\", \"plates.\", \"Frustrated,\", \"the\", \"Allosaurus\", \"circled,\", \"looking\", \"for\", \"a\", \"weak\", \"spot,\", \"but\", \"Brak\", \"simply\", \"rotated\", \"slowly,\", \"keeping\", \"his\", \"armored\", \"side\", \"exposed\", \"and\", \"his\", \"club\", \"ready.\"], \"start_times\": [0, 0.302, 0.987, 2.171, 2.461, 2.728, 3.599, 3.75, 4.296, 4.644, 5.074, 5.642, 5.968, 6.153, 6.478, 6.885, 8.092, 8.766, 8.893, 9.439, 10.054, 10.414, 10.577, 10.658, 10.879, 11.633, 11.854, 12.19, 12.608, 13.166, 13.955, 14.303, 14.466, 14.872, 15.209, 15.871, 16.045, 16.208, 16.544], \"end_times\": [0.232, 0.871, 1.73, 2.415, 2.682, 3.274, 3.704, 4.238, 4.574, 5.027, 5.596, 5.921, 6.072, 6.444, 6.815, 7.488, 8.742, 8.835, 9.381, 9.973, 10.344, 10.53, 10.612, 10.832, 11.355, 11.796, 12.109, 12.516, 13.108, 13.781, 14.257, 14.408, 14.826, 15.174, 15.813, 15.987, 16.149, 16.475, 17.09]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(265, 35, 'Page 10', 'After a few more failed attempts, the predator let out an annoyed snort and moved on, seeking an easier meal.', 10, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_10.mp3', NULL, NULL, '{\"words\": [\"After\", \"a\", \"few\", \"more\", \"failed\", \"attempts,\", \"the\", \"predator\", \"let\", \"out\", \"an\", \"annoyed\", \"snort\", \"and\", \"moved\", \"on,\", \"seeking\", \"an\", \"easier\", \"meal.\"], \"start_times\": [0, 0.418, 0.488, 0.685, 0.882, 1.161, 1.625, 1.765, 2.159, 2.345, 2.531, 2.647, 3.03, 3.471, 3.68, 3.982, 4.4, 4.795, 4.899, 5.259], \"end_times\": [0.372, 0.441, 0.639, 0.836, 1.138, 1.591, 1.718, 2.113, 2.299, 2.473, 2.601, 2.972, 3.413, 3.622, 3.913, 4.284, 4.748, 4.853, 5.201, 5.805]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(266, 35, 'Page 11', 'Brak stood tall. He realized he didn\'t need speed. His slowness was not a weakness; it gave him the stability to stand his ground when it mattered most. He truly was like stone, and that was exactly enough.', 11, 'https://lingola-stories-kids.b-cdn.net/audio/story_35_page_11.mp3', NULL, NULL, '{\"words\": [\"Brak\", \"stood\", \"tall.\", \"He\", \"realized\", \"he\", \"didn\'t\", \"need\", \"speed.\", \"His\", \"slowness\", \"was\", \"not\", \"a\", \"weakness;\", \"it\", \"gave\", \"him\", \"the\", \"stability\", \"to\", \"stand\", \"his\", \"ground\", \"when\", \"it\", \"mattered\", \"most.\", \"He\", \"truly\", \"was\", \"like\", \"stone,\", \"and\", \"that\", \"was\", \"exactly\", \"enough.\"], \"start_times\": [0, 0.464, 0.766, 1.753, 1.95, 2.438, 2.543, 2.833, 3.077, 3.936, 4.156, 4.702, 4.888, 5.062, 5.132, 5.968, 6.142, 6.374, 6.525, 6.653, 7.21, 7.349, 7.709, 7.848, 8.173, 8.324, 8.417, 8.742, 9.613, 9.822, 10.228, 10.53, 10.751, 11.331, 11.529, 11.726, 11.889, 12.411], \"end_times\": [0.406, 0.72, 1.37, 1.869, 2.392, 2.496, 2.786, 3.019, 3.611, 4.11, 4.656, 4.818, 5.027, 5.085, 5.793, 6.095, 6.339, 6.478, 6.594, 7.152, 7.279, 7.651, 7.802, 8.127, 8.29, 8.382, 8.707, 9.23, 9.764, 10.17, 10.449, 10.716, 11.25, 11.471, 11.68, 11.831, 12.341, 13.421]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(267, 50, 'Page 1', 'In a kingdom surrounded by silver mountains lived a princess named Elowen. The palace she grew up in was carved from pale stone that shimmered in the morning sun. From her balcony, she could see rivers winding like ribbons through the valleys below.', 1, 'https://lingola-stories-kids.b-cdn.net/audio/story_50_page_1.mp3', NULL, NULL, '{\"words\": [\"In\", \"a\", \"kingdom\", \"surrounded\", \"by\", \"silver\", \"mountains\", \"lived\", \"a\", \"princess\", \"named\", \"Elowen.\", \"The\", \"palace\", \"she\", \"grew\", \"up\", \"in\", \"was\", \"carved\", \"from\", \"pale\", \"stone\", \"that\", \"shimmered\", \"in\", \"the\", \"morning\", \"sun.\", \"From\", \"her\", \"balcony,\", \"she\", \"could\", \"see\", \"rivers\", \"winding\", \"like\", \"ribbons\", \"through\", \"the\", \"valleys\", \"below.\"], \"start_times\": [0, 0.302, 0.395, 0.801, 1.254, 1.428, 1.788, 2.241, 2.473, 2.554, 3.053, 3.332, 5.074, 5.248, 5.608, 5.759, 5.991, 6.153, 6.281, 6.444, 6.745, 6.943, 7.279, 7.651, 7.837, 8.22, 8.301, 8.406, 8.742, 10.019, 10.24, 10.379, 11.204, 11.378, 11.552, 11.738, 12.132, 12.608, 12.817, 13.201, 13.433, 13.549, 13.932], \"end_times\": [0.255, 0.325, 0.731, 1.219, 1.358, 1.73, 2.171, 2.45, 2.496, 2.995, 3.274, 3.959, 5.19, 5.584, 5.7, 5.933, 6.095, 6.235, 6.385, 6.722, 6.873, 7.233, 7.616, 7.779, 8.185, 8.266, 8.371, 8.673, 9.207, 10.194, 10.321, 11.088, 11.331, 11.517, 11.68, 12.063, 12.55, 12.771, 13.154, 13.41, 13.502, 13.874, 14.582]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(268, 50, 'Page 2', 'Elowen was next in line for the throne, but she did not want the crown. She didn\'t want to sit in council rooms or listen to endless disputes about borders and taxes. She wanted to ride horses across the open plains and map the uncharted forests beyond the mountains.', 2, 'https://lingola-stories-kids.b-cdn.net/audio/story_50_page_2.mp3', NULL, NULL, '{\"words\": [\"Elowen\", \"was\", \"next\", \"in\", \"line\", \"for\", \"the\", \"throne,\", \"but\", \"she\", \"did\", \"not\", \"want\", \"the\", \"crown.\", \"She\", \"didn\'t\", \"want\", \"to\", \"sit\", \"in\", \"council\", \"rooms\", \"or\", \"listen\", \"to\", \"endless\", \"disputes\", \"about\", \"borders\", \"and\", \"taxes.\", \"She\", \"wanted\", \"to\", \"ride\", \"horses\", \"across\", \"the\", \"open\", \"plains\", \"and\", \"map\", \"the\", \"uncharted\", \"forests\", \"beyond\", \"the\", \"mountains.\"], \"start_times\": [0, 0.534, 0.673, 0.917, 1.033, 1.289, 1.416, 1.544, 2.183, 2.368, 2.519, 2.682, 2.868, 3.077, 3.193, 4.017, 4.203, 4.447, 4.632, 4.737, 4.911, 5.039, 5.457, 5.747, 5.875, 6.153, 6.304, 6.664, 7.152, 7.407, 7.837, 7.976, 9.207, 9.392, 9.671, 9.799, 10.066, 10.484, 10.82, 10.96, 11.25, 11.68, 11.831, 12.109, 12.26, 12.794, 13.375, 13.7, 13.804], \"end_times\": [0.488, 0.615, 0.871, 0.975, 1.254, 1.382, 1.486, 2.032, 2.334, 2.461, 2.635, 2.821, 3.042, 3.146, 3.692, 4.145, 4.412, 4.598, 4.679, 4.876, 4.969, 5.399, 5.712, 5.817, 6.107, 6.211, 6.629, 7.117, 7.361, 7.802, 7.918, 8.696, 9.334, 9.636, 9.729, 10.031, 10.426, 10.786, 10.89, 11.18, 11.633, 11.773, 12.04, 12.19, 12.725, 13.317, 13.653, 13.769, 14.629]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(269, 50, 'Page 3', 'The day before her coronation, Elowen packed a modest satchel, slipped out of a servant\'s door, and fled the palace.', 3, 'https://lingola-stories-kids.b-cdn.net/audio/story_50_page_3.mp3', NULL, NULL, '{\"words\": [\"The\", \"day\", \"before\", \"her\", \"coronation,\", \"Elowen\", \"packed\", \"a\", \"modest\", \"satchel,\", \"slipped\", \"out\", \"of\", \"a\", \"servant\'s\", \"door,\", \"and\", \"fled\", \"the\", \"palace.\"], \"start_times\": [0, 0.29, 0.464, 0.801, 0.929, 1.985, 2.461, 2.798, 2.891, 3.332, 4.098, 4.447, 4.563, 4.656, 4.737, 5.155, 5.526, 5.747, 5.991, 6.095], \"end_times\": [0.232, 0.418, 0.755, 0.871, 1.707, 2.403, 2.763, 2.821, 3.262, 3.924, 4.423, 4.54, 4.609, 4.679, 5.12, 5.492, 5.677, 5.956, 6.06, 6.78]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11'),
(270, 50, 'Page 4', 'She traveled for weeks, trading her silks for rough wool, learning to build fires and navigate by the stars. She felt truly free.', 4, 'https://lingola-stories-kids.b-cdn.net/audio/story_50_page_4.mp3', NULL, NULL, '{\"words\": [\"She\", \"traveled\", \"for\", \"weeks,\", \"trading\", \"her\", \"silks\", \"for\", \"rough\", \"wool,\", \"learning\", \"to\", \"build\", \"fires\", \"and\", \"navigate\", \"by\", \"the\", \"stars.\", \"She\", \"felt\", \"truly\", \"free.\"], \"start_times\": [0, 0.313, 0.708, 0.894, 1.486, 1.846, 1.985, 2.31, 2.473, 2.728, 3.518, 3.855, 3.947, 4.203, 4.714, 4.853, 5.329, 5.48, 5.596, 6.861, 7.082, 7.349, 7.79], \"end_times\": [0.255, 0.673, 0.836, 1.416, 1.8, 1.927, 2.264, 2.426, 2.67, 3.193, 3.808, 3.901, 4.145, 4.656, 4.795, 5.294, 5.422, 5.55, 6.258, 7.001, 7.303, 7.709, 8.406]}', '2026-02-26 12:17:31', '2026-03-06 08:04:11');
